// Defaults por rol: nivel inicial al asignar un CRM nuevo a un rol.
// Para un rol "vet" en CRM "vet" → todo edit. Para "grooming" en CRM "vet" → mayoría hidden.
// Para los CRMs custom, se aplica el `defaultLevel` del schema (porque no hay info adicional sobre el rol).
const ROLE_CRM_DEFAULTS = {
  super: () => "edit",  // super edita todo
  vet: (crmId, sectionId, field) => {
    if (crmId === "vet") return field.defaultLevel;
    if (crmId === "clients") {
      // Vet en Clientes: NO ve datos del tutor pero SÍ ve mascotas
      if (sectionId === "tutor")     return "hidden";
      if (sectionId === "billing")   return "hidden";
      if (sectionId === "messaging") return "hidden";
      return field.defaultLevel;
    }
    if (crmId === "agenda") {
      // Vet en Agenda: ve y edita lo veterinario + mascotas (recordatorios suyos),
      // pero no ve grooming ni B2B (no es su área).
      if (sectionId === "categories") {
        if (field.id === "vet")      return "edit";
        if (field.id === "grooming") return "hidden";
        if (field.id === "pet")      return "edit";
        if (field.id === "b2b")      return "hidden";
        if (field.id === "other")    return "view";
      }
      if (sectionId === "actions") {
        if (field.id === "view-detail")  return "view";
        if (field.id === "create-event") return "edit";
        if (field.id === "move-event")   return "edit";
        if (field.id === "delete-event") return "hidden";
        if (field.id === "assign-staff") return "view";
        if (field.id === "reminders")    return "edit";
      }
      return field.defaultLevel;
    }
    return field.defaultLevel;
  },
  grooming: (crmId, sectionId, field) => {
    if (crmId === "grooming") return field.defaultLevel;
    if (crmId === "vet") {
      if (sectionId === "clinical") return "hidden";
      if (sectionId === "billing")  return "hidden";
      if (sectionId === "passport") return "hidden"; // historia clínica no es área de grooming
      return field.defaultLevel;
    }
    if (crmId === "clients") {
      if (sectionId === "tutor")     return field.id === "name" ? "view" : "hidden";
      if (sectionId === "billing")   return "hidden";
      if (sectionId === "messaging") return field.defaultLevel;
      if (sectionId === "pets")      return field.id === "microchip" ? "hidden" : field.defaultLevel;
      return field.defaultLevel;
    }
    if (crmId === "agenda") {
      // Groomer en Agenda: edita su grooming + ve recordatorios de mascotas.
      // No ve vet ni B2B.
      if (sectionId === "categories") {
        if (field.id === "vet")      return "hidden";
        if (field.id === "grooming") return "edit";
        if (field.id === "pet")      return "view";
        if (field.id === "b2b")      return "hidden";
        if (field.id === "other")    return "view";
      }
      if (sectionId === "actions") {
        if (field.id === "view-detail")  return "view";
        if (field.id === "create-event") return "edit";
        if (field.id === "move-event")   return "edit";
        if (field.id === "delete-event") return "hidden";
        if (field.id === "assign-staff") return "hidden";
        if (field.id === "reminders")    return "edit";
      }
      return field.defaultLevel;
    }
    return field.defaultLevel;
  },
  sales: (crmId, sectionId, field) => {
    if (sectionId === "clinical") return "hidden";
    if (sectionId === "passport") return "view"; // sales puede ver historia, no editarla
    if (crmId === "clients") {
      return field.editable ? "edit" : "view";
    }
    if (crmId === "agenda") {
      // Sales en Agenda: ve y edita B2B + ve recordatorios. No toca clínico ni grooming.
      if (sectionId === "categories") {
        if (field.id === "vet")      return "view";
        if (field.id === "grooming") return "view";
        if (field.id === "pet")      return "view";
        if (field.id === "b2b")      return "edit";
        if (field.id === "other")    return "edit";
      }
      if (sectionId === "actions") {
        if (field.id === "view-detail")  return "view";
        if (field.id === "create-event") return "edit";
        if (field.id === "move-event")   return "edit";
        if (field.id === "delete-event") return "view";
        if (field.id === "assign-staff") return "view";
        if (field.id === "reminders")    return "edit";
      }
      return field.defaultLevel;
    }
    return field.defaultLevel;
  },
};

// Genera la matriz inicial de permisos por campos, dada la lista de roles + schema.
function buildDefaultFieldPermissions() {
  const matrix = {};
  Object.keys(ROLE_CRM_DEFAULTS).forEach(roleId => {
    matrix[roleId] = {};
    Object.entries(CRM_FIELD_SCHEMA).forEach(([crmId, crm]) => {
      matrix[roleId][crmId] = {};
      Object.entries(crm.sections).forEach(([sectionId, section]) => {
        section.fields.forEach(field => {
          const resolver = ROLE_CRM_DEFAULTS[roleId];
          const level = roleId === "super" ? "edit" : resolver(crmId, sectionId, field);
          matrix[roleId][crmId][`${sectionId}.${field.id}`] = level;
        });
      });
    });
  });
  return matrix;
}

// Helper para que los componentes pregunten "¿qué nivel tiene este rol en este campo?"
// Devuelve "hidden" | "view" | "edit". Si no hay info, asume "view" (conservador).
function getFieldLevel(permissions, role, crmId, sectionId, fieldId) {
  if (role === "super") return "edit";
  const fields = permissions?.[role]?.fields?.[crmId];
  if (!fields) {
    // Buscar default del schema
    const schema = CRM_FIELD_SCHEMA[crmId]?.sections?.[sectionId]?.fields?.find(f => f.id === fieldId);
    return schema?.defaultLevel || "view";
  }
  const level = fields[`${sectionId}.${fieldId}`];
  return level || "view";
}

const DEFAULT_ROLE_PERMISSIONS = {
  super:    { views: "*", canCreateClient: true,  canCreateModule: true  },
  vet:      { views: ["dashboard", "crm", "vet", "vet-passport", "messages", "clients"], canCreateClient: false,  canCreateModule: false },
  grooming: { views: ["dashboard", "crm", "grooming-ops", "messages", "clients"], canCreateClient: false,  canCreateModule: false },
  sales:    { views: ["dashboard", "crm", "standard", "sales", "new-service", "inventory", "clients", "messages", "products"], canCreateClient: true, canCreateModule: false },
};

// Inicializa permissions completos (views + fields) para usar en App.
// Combina los defaults de vistas con la matriz de campos generada por el schema.
function buildInitialPermissions() {
  const fieldMatrix = buildDefaultFieldPermissions();
  const out = {};
  Object.entries(DEFAULT_ROLE_PERMISSIONS).forEach(([roleId, perm]) => {
    out[roleId] = { ...perm, fields: fieldMatrix[roleId] || {} };
  });
  return out;
}

