// ========== GENERADOR DE CÓDIGOS DE PASAPORTE ==========
// Hash multiplicativo de Knuth: codigo(n) = (n × 2654435761) mod 1000000
// Genera códigos NO secuenciales, sin colisiones hasta 1M de mascotas, reversible.
const KNUTH_CONSTANT = 2654435761;
const generatePetCode = (id) => String((id * KNUTH_CONSTANT) % 1000000).padStart(6, "0");

