// Helper: dado un code, devuelve el pet del catálogo o de los extras
const findPetByCode = (code, passports) => {
  const real = passports.find(p => p.code === code);
  if (real) return real;
  const extra = EXTRA_PETS[code];
  if (extra) return { ...extra, code, isExtra: true };
  return null;
};

