// === FACTURAS / VENTAS ===
// Estados: borrador → emitido → pagado → finalizado
//                              ↘ vencido (cuando emitido + fecha vencimiento pasada sin pago completo)
const INVOICE_STATES = {
  borrador:    { label: "Borrador",    color: "slate",    step: 1, badge: "bg-slate-200 text-slate-700 border border-slate-300" },
  emitido:     { label: "Emitido",     color: "blue",     step: 2, badge: "bg-blue-100 text-blue-800" },
  pagado:      { label: "Pagado",      color: "emerald",  step: 3, badge: "bg-emerald-100 text-emerald-800" },
  finalizado:  { label: "Finalizado",  color: "stone",    step: 4, badge: "bg-stone-200 text-stone-800" },
  vencido:     { label: "Vencido",     color: "red",      step: 0, badge: "bg-red-100 text-red-800" },
};

const PAY_METHODS = ["Efectivo", "Tarjeta", "Transferencia", "Pago móvil", "Mixto"];

// Generador determinista (no Math.random — para que el mock no cambie entre renders)
const buildInvoices = (clients) => {
  const invoices = [];
  const today = new Date();
  const daysAgo = (n) => new Date(today.getTime() - n*24*3600*1000);
  const fmt = (d) => d.toISOString().slice(0, 10);

  let counter = 100;
  clients.forEach((c, idx) => {
    // Cada cliente tiene 2-4 facturas según totalSpent
    const count = c.totalSpent > 5000 ? 4 : c.totalSpent > 2000 ? 3 : 2;
    for (let i = 0; i < count; i++) {
      counter++;
      const offsetDays = (i + 1) * 12 + idx * 3;
      const issueDate = daysAgo(offsetDays);
      const dueDate = daysAgo(offsetDays - 30);
      const totalAmount = Math.round((c.totalSpent / count) * (0.7 + ((i + idx) % 5) * 0.1));

      // Distribución de estados según posición
      let state, paid, payments;
      if (i === 0 && idx % 4 === 0) {
        // Algunos clientes tienen un borrador reciente
        state = "borrador"; paid = 0; payments = [];
      } else if (i === 0 && idx % 3 === 1) {
        // Emitido sin pagar (deuda activa)
        state = "emitido"; paid = 0; payments = [];
      } else if (i === 1 && idx % 5 === 2) {
        // Vencido
        state = "vencido"; paid = 0; payments = [];
      } else if (i === 1 && idx % 4 === 0) {
        // Pago parcial
        state = "emitido";
        paid = Math.round(totalAmount * 0.4);
        payments = [
          { id: `pay-${counter}-1`, date: fmt(daysAgo(offsetDays - 5)), amount: paid, method: "Transferencia", note: "Abono inicial" }
        ];
      } else {
        state = i < count - 1 ? "pagado" : "finalizado";
        paid = totalAmount;
        payments = [
          { id: `pay-${counter}-1`, date: fmt(daysAgo(offsetDays)), amount: totalAmount, method: PAY_METHODS[(idx + i) % 4], note: "Pago completo" }
        ];
      }

      invoices.push({
        id: `inv-${counter}`,
        number: `00-${String(counter).padStart(7, "0")}`,
        clientId: c.id,
        issueDate: fmt(issueDate),
        dueDate: fmt(dueDate),
        state,
        items: [
          { description: "Consulta veterinaria", qty: 1, unit: 35, total: 35 },
          { description: "Medicamentos", qty: 1, unit: Math.round(totalAmount * 0.5), total: Math.round(totalAmount * 0.5) },
          { description: "Servicios adicionales", qty: 1, unit: Math.round(totalAmount * 0.3), total: Math.round(totalAmount * 0.3) },
        ],
        subtotal: Math.round(totalAmount / 1.16),
        tax: Math.round(totalAmount - totalAmount / 1.16),
        total: totalAmount,
        paid,
        balance: totalAmount - paid,
        payments,
        createdBy: "Carlos M.",
      });
    }
  });
  return invoices.sort((a, b) => b.issueDate.localeCompare(a.issueDate));
};

// Plan de pago: deuda dividida en cuotas
const buildPaymentPlans = (invoices) => {
  const plans = [];
  const today = new Date();
  invoices
    .filter(inv => inv.balance > 200 && (inv.state === "emitido" || inv.state === "vencido"))
    .slice(0, 3)
    .forEach((inv, i) => {
      const installments = 3 + i;
      const installmentAmount = Math.round(inv.balance / installments);
      const installmentsList = [];
      for (let n = 0; n < installments; n++) {
        const dueDate = new Date(today.getTime() + (n + 1) * 30 * 24 * 3600 * 1000);
        installmentsList.push({
          id: `cuota-${inv.id}-${n + 1}`,
          number: n + 1,
          dueDate: dueDate.toISOString().slice(0, 10),
          amount: installmentAmount,
          paid: n === 0 && i === 0, // primera cuota del primer plan ya pagada
          paidDate: n === 0 && i === 0 ? new Date(today.getTime() - 5 * 24 * 3600 * 1000).toISOString().slice(0, 10) : null,
        });
      }
      plans.push({
        id: `plan-${inv.id}`,
        invoiceId: inv.id,
        clientId: inv.clientId,
        totalAmount: inv.balance,
        installments: installmentsList,
        createdAt: today.toISOString().slice(0, 10),
        status: "activo",
      });
    });
  return plans;
};



function CricketApp({ visitorMessages = [], onBackToLanding, externalAgendaEvents = null, setExternalAgendaEvents = null, appointmentSettings = { autoApprove: true }, setAppointmentSettings = null }) {
  const [user, setUser] = useState(null);
  const [loginError, setLoginError] = useState("");
  const [permissions, setPermissions] = useState(() => buildInitialPermissions());

  // === STATE GLOBAL persistente entre sesiones ===
  // Estos viven en CricketApp (no en AuthenticatedApp) para que las propuestas
  // creadas por el groomer sigan visibles cuando Sales hace login después.
  const [globalClients, setGlobalClients] = useState(CLIENTS_DATA);
  const [globalInvoices, setGlobalInvoices] = useState(() => buildInvoices(CLIENTS_DATA));
  const [globalPaymentPlans, setGlobalPaymentPlans] = useState(() => buildPaymentPlans(buildInvoices(CLIENTS_DATA)));
  const [globalPassports, setGlobalPassports] = useState(PASSPORTS_DATA);
  // Cola de propuestas de cambio a pasaportes — solo super aprueba
  const [globalPetUpdates, setGlobalPetUpdates] = useState([]);
  // Inicializamos servicios derivando moduleId de su `module`. Vet → "vet", grooming → "grooming-ops",
  // b2b → "standard". Esto permite que cuando creemos un módulo nuevo (clon de un kind), podamos
  // clonar sus servicios y reasignar moduleId a la nueva instancia, sin tocar el resto.
  const [globalServices, setGlobalServices] = useState(() =>
    INITIAL_SERVICES.map(s => ({
      ...s,
      moduleId: s.module === "vet" ? "vet"
              : s.module === "grooming" ? "grooming-ops"
              : s.module === "b2b" ? "standard"
              : "vet",
    }))
  );
  const [globalSupplies, setGlobalSupplies] = useState(GROOMING_SUPPLIES);
  const [globalVetSupplies, setGlobalVetSupplies] = useState(VET_SUPPLIES);
  const [globalProposals, setGlobalProposals] = useState([]);
  // Bookings de grooming — viven aquí para que el progreso del groomer (mover cards,
  // agregar insumos, terminar servicios) sobreviva al logout y reingreso de cualquier rol.
  const [globalGroomingBookings, setGlobalGroomingBookings] = useState(() => buildInitialGroomingBookings());
  // Conversaciones de chat — mismo motivo: si Sales le manda un mensaje a un cliente
  // y luego entra otro rol, ese mensaje no debe desaparecer.
  const [globalConversations, setGlobalConversations] = useState(() => buildInitialConversations(CLIENTS_DATA));
  // Eventos de agenda — antes era constante estática (IIFE). Ahora es state mutable
  // para que cuando se hace una venta express se cree el evento en el calendario y
  // luego al concluir el servicio se pueda marcar/eliminar.
  // Si nos llegó un state externo (desde CricketLanding), lo usamos —
  // así el AppointmentModal de la landing pública comparte la misma agenda.
  // Si no, fallback a state local (compatibilidad si CricketApp se monta standalone).
  const [localAgendaEvents, setLocalAgendaEvents] = useState(() => buildInitialAgendaEvents());
  const globalAgendaEvents = externalAgendaEvents !== null ? externalAgendaEvents : localAgendaEvents;
  const setGlobalAgendaEvents = setExternalAgendaEvents || setLocalAgendaEvents;

  // === Registro de módulos activos ===
  // Cada módulo es un registro con: id (clave en sidebar/permisos), kind (motor que usa),
  // name (editable), color, removed (soft-delete). Los módulos "core" arrancan instalados.
  // Cuando se elimina, se marca removed=true en lugar de borrarlo, así se puede reinstalar.
  // El "kind" indica cuál motor renderiza por dentro: "vet", "grooming", "standard".
  // Cuando hagamos el motor unificado, este campo dejará de importar.
  const [globalModules, setGlobalModules] = useState(() => [
    {
      id: "vet",
      kind: "vet",
      name: "Clínica Veterinaria",
      shortName: "Veterinaria",
      role: "Veterinario",
      tone: "from-orange-100 to-orange-50 text-orange-800",
      accent: "from-orange-500 to-orange-700",
      icon: "Stethoscope",
      removed: false,
      core: true, // los core no se pueden borrar definitivamente, solo marcar removed
      description: "Sugeridor inteligente de medicinas por diagnóstico, fichas clínicas con iconos por especie.",
      meta: ["Diagnóstico → tratamiento", "Historia clínica", "Recetario digital"],
      // === Features activables ===
      // Cada feature se puede activar/desactivar desde "Configurar módulo".
      // Los defaults reflejan lo que hoy se muestra en cada vista — el usuario
      // puede irlos apagando si no los necesita.
      features: {
        speciesFilters: true,    // Chips "Todos · Perros · Gatos · Aves..." arriba del kanban
        followUp: true,          // Barra "En seguimiento" inferior
        agendaSidebar: true,     // Tabs "Pacientes / Historial / Agenda" + contador
        walkIns: true,           // Permite registrar pacientes sin pasaporte previo
        medicationSuggester: true, // Sugeridor de medicinas según diagnóstico
        clinicalHistory: true,   // Acceso a historia clínica completa desde el drawer
        suppliesDuringService: false, // Insumos durante atención (típico de grooming)
        beforeAfterPhotos: false,     // Fotos antes/después
        floatingCalendar: false,      // Botón calendario flotante
        chatWithTutor: true,     // Chat integrado dentro del drawer
        invoiceLink: true,       // Mostrar número de factura asociado en cards
        dragAndDrop: true,       // Drag & drop entre columnas del kanban
      },
      // Configuración de qué campos se muestran en cada card del kanban
      cardFields: {
        petName: true,
        petCode: true,
        breed: true,
        age: true,
        tutorName: true,
        time: true,
        invoiceNumber: true,
        statusBadge: true,
      },
    },
    {
      id: "grooming-ops",
      kind: "grooming",
      name: "Atención Grooming",
      shortName: "Grooming",
      role: "Groomer",
      tone: "from-emerald-100 to-emerald-50 text-emerald-800",
      accent: "from-emerald-500 to-emerald-700",
      icon: "Bath",
      removed: false,
      core: true,
      description: "Catálogo visual de servicios, agenda de baños y cortes, registro fotográfico antes/después.",
      meta: ["Catálogo de servicios", "Agenda diaria", "Fotos antes/después"],
      features: {
        speciesFilters: false,
        followUp: false,
        agendaSidebar: false,
        walkIns: false,
        medicationSuggester: false,
        clinicalHistory: false,
        suppliesDuringService: true,
        beforeAfterPhotos: true,
        floatingCalendar: true,
        chatWithTutor: true,
        invoiceLink: true,
        dragAndDrop: true,
      },
      cardFields: {
        petName: true,
        petCode: false,
        breed: true,
        age: false,
        tutorName: true,
        time: true,
        invoiceNumber: true,
        statusBadge: false,
      },
    },
    {
      id: "standard",
      kind: "standard",
      name: "Mayoristas B2B",
      shortName: "B2B",
      role: "Vendedor B2B",
      tone: "from-blue-100 to-blue-50 text-blue-800",
      accent: "from-blue-500 to-blue-700",
      icon: "Tag",
      removed: false,
      core: true,
      description: "Pipeline genérico configurado como CRM estándar con campos personalizados y embudo de ventas.",
      meta: ["Embudo prospecto → cierre", "Campos personalizados", "Reglas de paso"],
      features: {
        speciesFilters: false,
        followUp: false,
        agendaSidebar: false,
        walkIns: false,
        medicationSuggester: false,
        clinicalHistory: false,
        suppliesDuringService: false,
        beforeAfterPhotos: false,
        floatingCalendar: false,
        chatWithTutor: true,
        invoiceLink: true,
        dragAndDrop: true,
      },
      cardFields: {
        petName: false,
        petCode: false,
        breed: false,
        age: false,
        tutorName: true,
        time: false,
        invoiceNumber: true,
        statusBadge: true,
      },
    },
  ]);

  // === Roles personalizados ===
  // Los 4 roles core (super, vet, grooming, sales) están hardcoded. Aquí el admin
  // puede crear roles adicionales — útil para multi-sede, donde cada sede puede
  // tener su propio "Veterinario Sede Norte" con permisos distintos al base.
  // Cada rol custom tiene:
  //   id: identificador único (custom-xxxx)
  //   label, desc: textos visibles
  //   color: degradado del badge (from-X-500 to-X-700)
  //   inheritFrom: rol base del que heredó permisos al crearse (vet, grooming, sales)
  //   assignedModuleIds: lista de instancias específicas a las que pertenece esta rol.
  //     Si está poblado, las vistas (SalesView, etc.) filtran automáticamente.
  //     Si está vacío, el rol ve todo lo que sus permisos le permitan.
  const [globalCustomRoles, setGlobalCustomRoles] = useState([]);

  // === Usuarios del sistema ===
  // Inicializa desde ACCOUNTS (seed). Los usuarios creados desde Ajustes → Usuarios
  // se persisten aquí y sobreviven al cambio de vista. Cuando el sistema tenga
  // backend real, ACCOUNTS se vuelve solo el seed inicial y este state pasa a sync.
  const [globalUsers, setGlobalUsers] = useState(() =>
    ACCOUNTS.map((a, idx) => ({
      id: `usr-${idx}-${a.email.split("@")[0]}`,
      email: a.email,
      password: a.password,
      name: a.name,
      initials: a.initials,
      role: a.role,
      roleLabel: a.roleLabel,
      active: true,
      createdAt: new Date(Date.now() - (ACCOUNTS.length - idx) * 86400000 * 30).toISOString(),
    }))
  );

  const handleLogin = (email, password) => {
    // Buscar primero en globalUsers (incluye los creados desde Ajustes → Usuarios).
    // Solo se permite login si el usuario está activo. ACCOUNTS legacy queda como
    // fallback para retro-compatibilidad si por algún motivo globalUsers se vacía.
    const matchedUser = globalUsers.find(
      u => u.email.toLowerCase() === email.toLowerCase().trim()
        && u.password === password
        && u.active !== false
    );
    if (matchedUser) {
      setLoginError("");
      setUser(matchedUser);
      return;
    }
    // Fallback: ACCOUNTS hardcoded (compatibilidad)
    const account = ACCOUNTS.find(
      a => a.email.toLowerCase() === email.toLowerCase().trim() && a.password === password
    );
    if (!account) {
      setLoginError("Email o contraseña incorrectos");
      return;
    }
    setLoginError("");
    setUser(account);
  };

  if (!user) {
    return <LoginScreen onLogin={handleLogin} error={loginError} onBackToLanding={onBackToLanding} />;
  }

  return (
    <AuthenticatedApp
      user={user}
      onLogout={() => setUser(null)}
      permissions={permissions}
      setPermissions={setPermissions}
      visitorMessages={visitorMessages}
      globalClients={globalClients}
      setGlobalClients={setGlobalClients}
      globalInvoices={globalInvoices}
      setGlobalInvoices={setGlobalInvoices}
      globalPaymentPlans={globalPaymentPlans}
      setGlobalPaymentPlans={setGlobalPaymentPlans}
      globalPassports={globalPassports}
      setGlobalPassports={setGlobalPassports}
      globalPetUpdates={globalPetUpdates}
      setGlobalPetUpdates={setGlobalPetUpdates}
      globalServices={globalServices}
      setGlobalServices={setGlobalServices}
      globalSupplies={globalSupplies}
      setGlobalSupplies={setGlobalSupplies}
      globalVetSupplies={globalVetSupplies}
      setGlobalVetSupplies={setGlobalVetSupplies}
      globalProposals={globalProposals}
      setGlobalProposals={setGlobalProposals}
      globalGroomingBookings={globalGroomingBookings}
      setGlobalGroomingBookings={setGlobalGroomingBookings}
      globalConversations={globalConversations}
      setGlobalConversations={setGlobalConversations}
      globalAgendaEvents={globalAgendaEvents}
      setGlobalAgendaEvents={setGlobalAgendaEvents}
      globalModules={globalModules}
      setGlobalModules={setGlobalModules}
      globalCustomRoles={globalCustomRoles}
      setGlobalCustomRoles={setGlobalCustomRoles}
      globalUsers={globalUsers}
      setGlobalUsers={setGlobalUsers}
      appointmentSettings={appointmentSettings}
      setAppointmentSettings={setAppointmentSettings}
    />
  );
}

// ========== APP AUTENTICADA ==========

function AuthenticatedApp({
  user, onLogout, permissions, setPermissions, visitorMessages = [],
  globalClients, setGlobalClients,
  globalInvoices, setGlobalInvoices,
  globalPaymentPlans, setGlobalPaymentPlans,
  globalPassports, setGlobalPassports,
  globalPetUpdates, setGlobalPetUpdates,
  globalServices, setGlobalServices,
  globalSupplies, setGlobalSupplies,
  globalVetSupplies, setGlobalVetSupplies,
  globalProposals, setGlobalProposals,
  globalGroomingBookings, setGlobalGroomingBookings,
  globalConversations, setGlobalConversations,
  globalAgendaEvents, setGlobalAgendaEvents,
  globalModules, setGlobalModules,
  globalCustomRoles, setGlobalCustomRoles,
  globalUsers, setGlobalUsers,
  appointmentSettings = { autoApprove: true },
  setAppointmentSettings = null,
}) {
 const perm = permissions[user.role];
 // Vista inicial al hacer login: dashboard si tiene permiso (es la pantalla más
 // útil al entrar — muestra panorama del día). Si su rol NO tiene "dashboard"
 // habilitado, cae a la primera vista permitida.
 const defaultView = (() => {
   if (perm.views === "*") return "dashboard";              // super: siempre dashboard
   if (perm.views.includes("dashboard")) return "dashboard"; // cualquier rol con permiso
   return perm.views[0];                                     // fallback: primera vista permitida
 })();
 const [view, setView] = useState(defaultView);
 const [showCreateModule, setShowCreateModule] = useState(false);
 const [showNewClient, setShowNewClient] = useState(false);
 const [showQuickClient, setShowQuickClient] = useState(false);
 // Sidebar plegable estilo Claude.ai/Slack: en colapsado se ven solo iconos
 // Default colapsado para maximizar espacio del contenido principal.
 const [sidebarCollapsed, setSidebarCollapsed] = useState(true);
 const [completeClient, setCompleteClient] = useState(null); // cliente al que se le completa el registro
 const [preselectedSaleClient, setPreselectedSaleClient] = useState(null); // cliente pre-cargado al abrir Nueva Venta
 const [customModules, setCustomModules] = useState([]);
 const [passportSearchInit, setPassportSearchInit] = useState("");
 const [vetPassportSearchInit, setVetPassportSearchInit] = useState("");

 // Aliases hacia el state global del padre para que el resto del componente
 // siga usando los nombres cortos (clients, invoices, etc.) sin tener que tocar nada más.
 const clients = globalClients;
 const setClients = setGlobalClients;
 const invoices = globalInvoices;
 const setInvoices = setGlobalInvoices;
 const paymentPlans = globalPaymentPlans;
 const setPaymentPlans = setGlobalPaymentPlans;
 const passports = globalPassports;
 const setPassports = setGlobalPassports;
 const petUpdates = globalPetUpdates;
 const setPetUpdates = setGlobalPetUpdates;

 // Submit de propuesta de edición de pasaporte desde drawers (vet/grooming).
 // Si el usuario es super, aplica el cambio directamente y registra el update como aprobado
 // (queda en el historial). Si no, lo crea en estado "pending" para revisión del super.
 const submitPetUpdate = ({ passportId, passportCode, passportName, proposed, changedFields, submittedBy }) => {
   if (!passportId) return;
   const isSuper = user?.role === "super";
   const now = new Date().toISOString();
   const newUpdate = {
     id: `upd-${Date.now().toString(36)}`,
     passportId,
     passportCode,
     passportName,
     proposed: { ...proposed },
     changedFields: Array.isArray(changedFields) ? changedFields : [],
     submittedBy: submittedBy || user?.name || user?.role || "—",
     submittedAt: now,
     status: isSuper ? "approved" : "pending",
     ...(isSuper ? { approvedBy: user?.name || user?.role || "—", approvedAt: now } : {}),
   };
   setPetUpdates(prev => [newUpdate, ...prev]);
   if (isSuper) {
     // Aplicar cambios al pasaporte de inmediato
     setPassports(prev => prev.map(p => p.id === passportId ? { ...p, ...proposed } : p));
   }
 };
 const services = globalServices;
 const setServices = setGlobalServices;
 const supplies = globalSupplies;
 const setSupplies = setGlobalSupplies;
 const vetSupplies = globalVetSupplies;
 const setVetSupplies = setGlobalVetSupplies;
 const proposals = globalProposals;
 const setProposals = setGlobalProposals;

 const [showProposalsModal, setShowProposalsModal] = useState(false);

 const goToPassport = (code) => {
   setPassportSearchInit(code || "");
   setView("passport");
 };
 const goToVetPassport = (code) => {
   setVetPassportSearchInit(code || "");
   setView("vet-passport");
 };

 // === Handlers de gestión de módulos ===
 // Eliminar un módulo soft-delete: marca removed=true. Antes de eso:
 //   1) Bookings activos del módulo se convierten a facturas concluidas en Ventas
 //      (con cinta "✓ Concluido" — Ventas decide cobro y cierre).
 //   2) Servicios del catálogo asociados al módulo se DESACTIVAN (no se borran).
 //      Así, las facturas históricas que referencian esos servicios siguen funcionando.
 //   3) Eventos futuros de agenda del módulo se eliminan (no tienen sentido si el
 //      módulo no opera). Eventos pasados se conservan como histórico.
 // Los datos de Ventas, Clientes, Pasaportes y facturas NO se tocan: son tronco.
 const handleRemoveModule = (moduleId) => {
   const mod = (modules || []).find(m => m.id === moduleId);
   if (!mod) return;

   // 1) Cerrar bookings activos del módulo (solo grooming usa este sistema hoy)
   //    Convertimos cada uno a una factura concluida.
   if (moduleId === "grooming-ops" && groomingBookings.length > 0) {
     const activeBookings = groomingBookings.filter(b => b.status === "pending" || b.status === "active");

     activeBookings.forEach(b => {
       // Si el booking ya tenía factura asociada (vino de venta express), solo la marcamos completed
       if (b.invoiceId) {
         setInvoices(prev => prev.map(inv => {
           if (inv.id !== b.invoiceId) return inv;
           return {
             ...inv,
             serviceCompleted: true,
             paidInAdvance: false,
             notes: [inv.notes, `Servicio cerrado automáticamente por eliminación del módulo "${mod.name}".`].filter(Boolean).join(" "),
           };
         }));
       } else {
         // Booking sin factura previa: emitir factura express con precios del catálogo
         const svcDef = (services || []).find(s => s.module === "grooming" && (s.name || "").toLowerCase().trim() === (b.service || "").toLowerCase().trim());
         const price = svcDef?.price ?? 0;
         const items = [{ id: "svc", description: b.service, qty: 1, unit: price, total: price }];
         const subtotal = price;
         const tax = Math.round(subtotal * 0.16 * 100) / 100;
         const total = Math.round((subtotal + tax) * 100) / 100;
         const matchedClient = clients.find(c => c.id === b.clientId);
         const newInvoice = {
           id: `inv-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,
           number: `00-${String(Date.now()).slice(-6)}`,
           clientId: matchedClient?.id || null,
           clientName: matchedClient?.name || b.owner || "—",
           issueDate: new Date().toISOString().slice(0, 10),
           dueDate: new Date().toISOString().slice(0, 10),
           items,
           subtotal,
           tax,
           total,
           paid: 0,
           balance: total,
           payments: [],
           state: "emitido",
           serviceCompleted: true,
           notes: `Servicio cerrado automáticamente por eliminación del módulo "${mod.name}".`,
           fromGroomingBooking: { bookingId: b.id, pet: b.pet, petCode: b.petCode },
         };
         setInvoices(prev => [newInvoice, ...prev]);
       }
     });

     // Limpiar todos los bookings del módulo (ya están cerrados)
     setGroomingBookings([]);
   }

   // 2) Desactivar servicios del catálogo asociados al módulo.
   //    Para vet → module === "vet". Para grooming-ops → module === "grooming".
   //    Para standard → module === "b2b" o cualquiera que matchee por kind.
   const catalogModule =
     mod.kind === "vet" ? "vet" :
     mod.kind === "grooming" ? "grooming" :
     mod.kind === "standard" ? "b2b" : mod.id;
   setServices(prev => prev.map(s =>
     s.module === catalogModule ? { ...s, active: false, deactivatedByModuleRemoval: true } : s
   ));

   // 3) Eliminar eventos de agenda futuros del módulo (los pasados quedan como histórico)
   const todayISO = new Date().toISOString().slice(0, 10);
   const evtType = mod.kind === "vet" ? "vet" : mod.kind === "grooming" ? "grooming" : mod.kind === "standard" ? "b2b" : null;
   if (evtType) {
     setAgendaEvents(prev => prev.filter(e => !(e.type === evtType && e.date >= todayISO)));
   }

   // 4) Marcar el módulo como eliminado (soft-delete)
   setModules(prev => prev.map(m => m.id === moduleId ? { ...m, removed: true, removedAt: new Date().toISOString(), removedBy: user.name } : m));

   // 5) Si el usuario estaba en la vista del módulo eliminado, redirigir al hub
   if (view === moduleId) setView("crm");
 };

 // Reinstalar un módulo previamente eliminado: levanta el flag, reactiva sus servicios.
 // Los bookings/eventos no se restauran — el módulo arranca limpio.
 const handleReinstallModule = (moduleId) => {
   const mod = (modules || []).find(m => m.id === moduleId);
   if (!mod || !mod.removed) return;

   // Reactivar servicios que se habían desactivado por eliminación
   const catalogModule =
     mod.kind === "vet" ? "vet" :
     mod.kind === "grooming" ? "grooming" :
     mod.kind === "standard" ? "b2b" : mod.id;
   setServices(prev => prev.map(s =>
     s.module === catalogModule && s.deactivatedByModuleRemoval
       ? { ...s, active: true, deactivatedByModuleRemoval: false }
       : s
   ));

   // Restaurar el módulo
   setModules(prev => prev.map(m =>
     m.id === moduleId ? { ...m, removed: false, removedAt: null, reinstalledAt: new Date().toISOString() } : m
   ));
 };

 // Renombrar un módulo (nombre visible — no cambia el id).
 const handleRenameModule = (moduleId, newName) => {
   const trimmed = (newName || "").trim();
   if (!trimmed) return;
   setModules(prev => prev.map(m => m.id === moduleId ? { ...m, name: trimmed } : m));
 };

 // Cliente virtual "Visitantes Web" para chats anónimos del widget de la landing.
 // Cuando un visitante se identifica, en producción se promovería a cliente real.
 const VISITOR_CLIENT = useMemo(() => ({
   id: "visitor-web",
   name: "Visitantes Web",
   cedula: "—",
   email: "anonimo@cricket.vet",
   phone: "Chat web",
   segment: "Anónimo",
   isOrg: false,
   isVisitor: true,
   petCodes: [],
   totalSpent: 0,
   since: "—",
 }), []);

 // Lista de clientes que se pasa a las vistas (incluye visitor cuando hay mensajes)
 const clientsWithVisitor = useMemo(() => {
   if (visitorMessages.length === 0) return clients;
   return [...clients, VISITOR_CLIENT];
 }, [clients, visitorMessages.length, VISITOR_CLIENT]);

 // === Sistema de chat: alias al state global del padre ===
 const conversations = globalConversations;
 const setConversations = setGlobalConversations;

 // === Eventos de agenda: alias al state global del padre ===
 // Vive en CricketApp para que las inserciones desde venta express sobrevivan al
 // re-render de AuthenticatedApp y a logout/login.
 const agendaEvents = globalAgendaEvents;
 const setAgendaEvents = setGlobalAgendaEvents;

 // === Módulos activos: alias al state global ===
 // Lista de todos los módulos registrados (instalados o eliminados). El sidebar y el
 // CRM hub iteran sobre estos para decidir qué mostrar. Soft-delete: los eliminados
 // tienen removed=true para poder reinstalarse.
 const modules = globalModules;
 const setModules = setGlobalModules;
 // Roles personalizados creados desde Roles & permisos
 const customRoles = globalCustomRoles;
 const setCustomRoles = setGlobalCustomRoles;
 // Usuarios del equipo
 const users = globalUsers;
 const setUsers = setGlobalUsers;
 // Lookup rápido: ¿el módulo "vet" está instalado y activo? (no eliminado).
 // canAccess(perm, viewId) sigue gobernando los permisos por rol — esto es independiente.
 const isModuleInstalled = (id) => {
   const m = (modules || []).find(mm => mm.id === id);
   return Boolean(m && !m.removed);
 };
 // Módulos visibles en sidebar/hub: instalados Y con permiso del rol actual
 const activeModules = useMemo(
   () => (modules || []).filter(m => !m.removed),
   [modules]
 );

 // === Bookings de grooming: alias al state global del padre ===
 // Vive en CricketApp (no aquí) para que el progreso del groomer (drag entre columnas,
 // insumos agregados, notas, servicios terminados) sobreviva al logout y reingreso de
 // cualquier rol. Si AuthenticatedApp se desmonta (logout), CricketApp conserva el state.
 const groomingBookings = globalGroomingBookings;
 const setGroomingBookings = setGlobalGroomingBookings;

 // Inyectar mensajes de visitantes en las conversaciones (con channel="web")
 const conversationsWithVisitor = useMemo(() => {
   if (visitorMessages.length === 0) return conversations;
   const visitorConvo = visitorMessages.map(m => ({
     ...m,
     clientId: VISITOR_CLIENT.id,
     channel: "web",
     status: m.direction === "out" ? "sent" : "read",
   }));
   return {
     ...conversations,
     [VISITOR_CLIENT.id]: visitorConvo,
   };
 }, [conversations, visitorMessages, VISITOR_CLIENT.id]);

 const [chatTargetClientId, setChatTargetClientId] = useState(null);

 // Helpers de chat (en producción: llamadas a Supabase / API externa)
 const sendMessage = (clientId, channel, body, extras = {}) => {
   const newMsg = {
     id: `msg-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
     clientId,
     channel,
     direction: "out",
     body,
     timestamp: new Date().toISOString(),
     status: "sent", // pending → sent → delivered → read
     author: "Operador",
     ...extras, // permite incluir { attachment: { type: 'image'|'invoice', ... } }
   };
   saveMessageToCRM(newMsg); // placeholder externo
   setConversations(prev => ({
     ...prev,
     [clientId]: [...(prev[clientId] || []), newMsg],
   }));
   // Simular delivery + read después de 1s y 3s
   setTimeout(() => updateMessageStatus(clientId, newMsg.id, "delivered"), 1000);
   setTimeout(() => updateMessageStatus(clientId, newMsg.id, "read"), 3000);
   return newMsg;
 };

 const updateMessageStatus = (clientId, msgId, status) => {
   setConversations(prev => ({
     ...prev,
     [clientId]: (prev[clientId] || []).map(m => m.id === msgId ? { ...m, status } : m),
   }));
 };

 const openChatWith = (clientId) => setChatTargetClientId(clientId);
 const closeChatWindow = () => setChatTargetClientId(null);

 // Tab inicial al entrar a Clientes. Cuando alguien navega a la ruta legacy
 // "passport-updates" o presiona "Revisar pendientes" desde el dashboard, se setea
 // a "updates" para abrir directamente esa pestaña.
 const [clientsInitialTab, setClientsInitialTab] = useState(null);

 // Si el usuario intenta navegar a una vista no permitida, redirigir
 const safeSetView = (v) => {
   // 'profile' siempre disponible para todos los roles autenticados
   if (v === "profile") { setView(v); return; }
   // 'settings-hub' es la lista visible de ajustes — accesible si el rol tiene
   // permiso a alguna vista de ajustes (productos, módulos, roles, etc.)
   if (v === "settings-hub") { setView(v); return; }
   // La ruta legacy "passport-updates" ahora vive como tab dentro de "clients".
   // Mantenemos compatibilidad redirigiéndola con el tab pre-seleccionado.
   if (v === "passport-updates") {
     setClientsInitialTab("updates");
     setView("clients");
     return;
   }
   if (v === "roles" && user.role !== "super") return;
   if (v === "roles" && user.role === "super") { setView(v); return; }
   // Bloquear acceso a un módulo si fue eliminado por el admin (soft-delete).
   // El usuario verá automáticamente el hub de CRM en su lugar.
   const targetModule = (modules || []).find(m => m.id === v);
   if (targetModule && targetModule.removed) {
     setView("crm");
     return;
   }
   // Si el destino es un módulo instalado (sea core o un clon), validar que el rol
   // tenga el permiso INDIVIDUAL para esa instancia. Cada módulo es un id propio en
   // la matriz de permisos, así que no se hereda de su kind base.
   if (targetModule && !targetModule.removed) {
     if (canAccess(perm, v)) { setView(v); return; }
     return;
   }
   if (canAccess(perm, v) || customModules.find(m => m.id === v)) {
     setView(v);
   }
 };

 // Contador de mensajes entrantes recientes (entregados, no leídos por nosotros aún en el módulo)
 const unreadMessagesCount = useMemo(() => {
   let count = 0;
   Object.values(conversationsWithVisitor).forEach(msgs => {
     const lastIn = [...msgs].reverse().find(m => m.direction === "in");
     if (lastIn) {
       const lastTime = new Date(lastIn.timestamp).getTime();
       const lastOutAfter = msgs.some(m => m.direction === "out" && new Date(m.timestamp).getTime() > lastTime);
       if (!lastOutAfter) count++;
     }
   });
   // Sumar 1 si hay mensajes de visitantes pendientes (mensajes "out" del visitante = "in" para nosotros)
   const visitorOut = visitorMessages.filter(m => m.direction === "out").length;
   const visitorIn = visitorMessages.filter(m => m.direction === "in").length;
   if (visitorOut > visitorIn) count++;
   return count;
 }, [conversationsWithVisitor, visitorMessages]);

 return (
 <div className="min-h-screen bg-stone-50 flex">
 <Sidebar
 view={view}
 setView={safeSetView}
 customModules={customModules}
 passportsCount={passports.length}
 onNewClientQuick={() => setShowQuickClient(true)}
 onNewClientFull={() => setShowNewClient(true)}
 user={user}
 onLogout={onLogout}
 permissions={permissions}
 unreadMessagesCount={unreadMessagesCount}
 petUpdates={petUpdates}
 collapsed={sidebarCollapsed}
 onToggleCollapsed={() => setSidebarCollapsed(c => !c)}
 />

 <main className="flex-1 min-w-0 flex flex-col">
 <Topbar
 view={view}
 proposalsCount={proposals.filter(p => p.status === "pending").length}
 onOpenProposals={() => setShowProposalsModal(true)}
 canSeeProposals={user.role === "super" || user.role === "sales"}
 onToggleSidebar={() => setSidebarCollapsed(c => !c)}
 sidebarCollapsed={sidebarCollapsed}
 />

 <div className="p-6 lg:p-8">
 {view === "settings-hub" && (
   <SettingsHubView
     role={user.role}
     can={(v) => canAccess(perm, v)}
     onNavigate={(id) => setView(id)}
   />
 )}
 {view === "manager" && (
 <ModulesManager
   onOpenModule={setView}
   onCreateModule={() => setShowCreateModule(true)}
   customModules={customModules}
   modules={modules}
   setModules={setModules}
   userName={user.name}
   onRemoveModule={(moduleId) => handleRemoveModule(moduleId)}
   onReinstallModule={(moduleId) => handleReinstallModule(moduleId)}
   onRenameModule={(moduleId, newName) => handleRenameModule(moduleId, newName)}
 />
 )}
 {view === "crm" && (
   <CRMHubView
     userRole={user.role}
     perm={perm}
     modules={modules}
     onSelectSection={(sectionView) => safeSetView(sectionView)}
     // Pass-through props para que cada subvista funcione exactamente igual que stand-alone
     vetProps={{ onOpenPassport: goToPassport, onOpenVetPassport: goToVetPassport, canAccessVetPassport: canAccess(perm, "vet-passport"), vetSupplies, clients, invoices, setInvoices, passports, setPassports, onGoToSales: () => safeSetView("sales"), userName: user.name, onMessageClient: openChatWith, canMessage: canAccess(perm, "messages"), conversations, onSendMessage: sendMessage, userRole: user.role, permissions, modules, agendaEvents, setAgendaEvents }}
     groomingOpsProps={{ clients, passports, invoices, setInvoices, userRole: user.role, proposals, setProposals, services, setServices, supplies, setSupplies, onMessageClient: openChatWith, canMessage: canAccess(perm, "messages"), conversations, onSendMessage: sendMessage, bookings: groomingBookings, setBookings: setGroomingBookings, petUpdates, onSubmitPetUpdate: submitPetUpdate, setPassports, userName: user.name, permissions, modules }}
     standardProps={{ title: (modules.find(m => m.id === "standard")?.name) || "Mayoristas B2B" }}
     salesProps={{ invoices, setInvoices, clients, paymentPlans, setPaymentPlans, onMessageClient: openChatWith, modules, userRole: user.role, customRoles }}
     onGoToManager={() => setView("manager")}
   />
 )}
 {view === "products" && (
   <ProductsHubView
     userRole={user.role}
     can={(v) => canAccess(perm, v)}
     onSelectSection={(sectionView) => safeSetView(sectionView)}
     vetCatalogProps={{ services, setServices, vetSupplies, setVetSupplies, userRole: user.role }}
     groomingProps={{ onOpenPassport: goToPassport, services, setServices, supplies, setSupplies, userRole: user.role }}
   />
 )}
 {view === "client-settings" && <ComingSoon view="client-settings" />}
 {view === "agenda-settings" && <AgendaSettingsView appointmentSettings={appointmentSettings} setAppointmentSettings={setAppointmentSettings} userRole={user.role} agendaEvents={agendaEvents} />}
 {view === "vet" && isModuleInstalled("vet") && <VetCRM onOpenPassport={goToPassport} onOpenVetPassport={goToVetPassport} canAccessVetPassport={canAccess(perm, "vet-passport")} vetSupplies={vetSupplies} clients={clients} invoices={invoices} setInvoices={setInvoices} passports={passports} setPassports={setPassports} onGoToSales={() => safeSetView("sales")} userName={user.name} onMessageClient={openChatWith} canMessage={canAccess(perm, "messages")} conversations={conversations} onSendMessage={sendMessage} userRole={user.role} permissions={permissions} modules={modules} agendaEvents={agendaEvents} setAgendaEvents={setAgendaEvents} />}
 {view === "vet-passport" && <VetPassportView passports={passports} setPassports={setPassports} initialSearch={vetPassportSearchInit} onClearInitialSearch={() => setVetPassportSearchInit("")} userName={user.name} userRole={user.role} permissions={permissions} />}
 {view === "grooming" && <GroomingCRM onOpenPassport={goToPassport} services={services} setServices={setServices} supplies={supplies} setSupplies={setSupplies} userRole={user.role} />}
 {view === "vet-catalog" && <VetCatalogView services={services} setServices={setServices} vetSupplies={vetSupplies} setVetSupplies={setVetSupplies} userRole={user.role} />}
 {view === "grooming-ops" && isModuleInstalled("grooming-ops") && <GroomingOpsView clients={clients} passports={passports} invoices={invoices} setInvoices={setInvoices} userRole={user.role} proposals={proposals} setProposals={setProposals} services={services} setServices={setServices} supplies={supplies} setSupplies={setSupplies} onMessageClient={openChatWith} canMessage={canAccess(perm, "messages")} conversations={conversations} onSendMessage={sendMessage} bookings={groomingBookings} setBookings={setGroomingBookings} petUpdates={petUpdates} onSubmitPetUpdate={submitPetUpdate} setPassports={setPassports} userName={user.name} permissions={permissions} modules={modules} />}
 {view === "standard" && isModuleInstalled("standard") && <StandardCRM title={(modules.find(m => m.id === "standard")?.name) || "Mayoristas B2B"} />}
 {/* Routing dinámico para módulos clonados (mismo kind, otro id).
     Cuando el usuario crea "Veterinaria 2" desde Manager, su id es por ejemplo
     "vet-lxabc123". Aquí lo capturamos para renderizar el motor según su kind,
     pasándole el módulo concreto via activeModule para que sus features y
     columnas se apliquen correctamente. */}
 {(() => {
   // No procesar si el view es un id core ya manejado arriba o una vista del tronco
   const coreViews = ["dashboard","crm","manager","modules","vet","vet-passport","grooming","vet-catalog","grooming-ops","standard","passport","roles","clients","sales","new-service","agenda","messages","profile","client-settings","agenda-settings","settings-hub","products","inventory"];
   if (coreViews.includes(view)) return null;
   const targetModule = (modules || []).find(m => m.id === view && !m.removed);
   if (!targetModule) return null;
   if (targetModule.kind === "vet") {
     return <VetCRM onOpenPassport={goToPassport} onOpenVetPassport={goToVetPassport} canAccessVetPassport={canAccess(perm, "vet-passport")} vetSupplies={vetSupplies} clients={clients} invoices={invoices} setInvoices={setInvoices} passports={passports} setPassports={setPassports} onGoToSales={() => safeSetView("sales")} userName={user.name} onMessageClient={openChatWith} canMessage={canAccess(perm, "messages")} conversations={conversations} onSendMessage={sendMessage} userRole={user.role} permissions={permissions} modules={modules} activeModule={targetModule} agendaEvents={agendaEvents} setAgendaEvents={setAgendaEvents} />;
   }
   if (targetModule.kind === "grooming") {
     return <GroomingOpsView clients={clients} passports={passports} invoices={invoices} setInvoices={setInvoices} userRole={user.role} proposals={proposals} setProposals={setProposals} services={services} setServices={setServices} supplies={supplies} setSupplies={setSupplies} onMessageClient={openChatWith} canMessage={canAccess(perm, "messages")} conversations={conversations} onSendMessage={sendMessage} bookings={groomingBookings} setBookings={setGroomingBookings} petUpdates={petUpdates} onSubmitPetUpdate={submitPetUpdate} setPassports={setPassports} userName={user.name} permissions={permissions} modules={modules} activeModule={targetModule} />;
   }
   if (targetModule.kind === "standard") {
     return <StandardCRM title={targetModule.name || "Pipeline"} />;
   }
   return null;
 })()}
 {view === "passport" && <PassportView passports={passports} setPassports={setPassports} clients={clients} setClients={setClients} canCreate={perm.canCreateClient} initialSearch={passportSearchInit} onClearInitialSearch={() => setPassportSearchInit("")} onMessageClient={openChatWith} />}
 {view === "roles" && <RolesView permissions={permissions} setPermissions={setPermissions} modules={modules} customRoles={customRoles} setCustomRoles={setCustomRoles} />}
 {view === "users" && user.role === "super" && <UsersView users={users} setUsers={setUsers} permissions={permissions} customRoles={customRoles} modules={modules} />}
 {view === "clients" && <ClientsView clients={clients} passports={passports} setPassports={setPassports} invoices={invoices} conversations={conversations} canCreate={perm.canCreateClient} onNewClient={() => setShowNewClient(true)} onOpenPassport={goToPassport} onOpenSales={() => setView("sales")} onMessageClient={openChatWith} onCompleteRegistration={(c) => setCompleteClient(c)} userRole={user.role} permissions={permissions} petUpdates={petUpdates} setPetUpdates={setPetUpdates} userName={user.name} initialTab={clientsInitialTab} onTabConsumed={() => setClientsInitialTab(null)} />}
 {view === "sales" && <SalesView invoices={invoices} setInvoices={setInvoices} clients={clients} paymentPlans={paymentPlans} setPaymentPlans={setPaymentPlans} onMessageClient={openChatWith} modules={modules} userRole={user.role} customRoles={customRoles} />}
 {view === "new-service" && <NewServiceView services={services} setServices={setServices} supplies={supplies} clients={clients} passports={passports} invoices={invoices} setInvoices={setInvoices} groomingBookings={groomingBookings} setGroomingBookings={setGroomingBookings} agendaEvents={agendaEvents} setAgendaEvents={setAgendaEvents} userName={user.name} modules={modules} onGoToSales={() => setView("sales")} preselectedClient={preselectedSaleClient} onClearPreselected={() => setPreselectedSaleClient(null)} />}
 {view === "agenda" && <AgendaView onOpenPassport={goToPassport} userRole={user.role} permissions={permissions} events={agendaEvents} setEvents={setAgendaEvents} invoices={invoices} />}
 {view === "messages" && <MessagesView clients={clientsWithVisitor} setClients={setClients} passports={passports} setPassports={setPassports} conversations={conversationsWithVisitor} onSendMessage={sendMessage} invoices={invoices} onGoToInvoice={(invoiceId) => { safeSetView("sales"); }} />}
 {view === "profile" && <UserProfileView user={user} />}
 {view === "dashboard" && <DashboardView
   user={user}
   userRole={user.role}
   userName={user.name}
   invoices={invoices}
   clients={clients}
   passports={passports}
   agendaEvents={agendaEvents}
   groomingBookings={groomingBookings}
   modules={modules}
   customRoles={customRoles}
   users={users}
   conversations={conversations}
   supplies={supplies}
   vetSupplies={vetSupplies}
   onNavigate={(v) => safeSetView(v)}
   permissions={permissions}
 />}
 {["inventory", "reports", "config"].includes(view) && <ComingSoon view={view} />}
 {customModules.find(m => m.id === view) && (
 <StandardCRM
 title={customModules.find(m => m.id === view).name}
 customFields={customModules.find(m => m.id === view).fields}
 />
 )}
 </div>
 </main>

 {showCreateModule && (
 <CreateModuleModal
   onClose={() => setShowCreateModule(false)}
   modules={modules}
   onCreate={(mod) => {
     // Los módulos creados por plantilla se agregan al registro principal globalModules.
     // No al state legacy customModules — ese se mantiene solo para compatibilidad.
     // Así, el nuevo módulo aparece en sidebar, hub y manager igual que los core.
     setModules(prev => [...prev, mod]);

     // === Permisos: el módulo nuevo arranca SIN acceso para roles no-super ===
     // Esto es por seguridad: el super crea el módulo, y luego va a Roles &
     // permisos para asignar QUÉ ROLES (qué empleados) pueden ver esta nueva
     // instancia. Así un veterinario asignado solo a "vet" no ve automáticamente
     // "vet-lxabc..." (la sede 2). Es una decisión consciente del admin.
     // El super tiene views="*" así que ya tiene acceso por defecto.

     // === Clonar servicios del catálogo del kind base ===
     // Si el módulo es del kind vet, grooming o standard, clonamos los servicios
     // del MÓDULO BASE (vet, grooming-ops, standard) y les asignamos el nuevo
     // moduleId. Así, la nueva instancia arranca con un catálogo idéntico al
     // del módulo base — el usuario puede luego eliminarlos o agregar nuevos.
     // Si es kind="custom", no se clona nada — arranca vacío.
     const baseModuleId = mod.kind === "vet" ? "vet"
                       : mod.kind === "grooming" ? "grooming-ops"
                       : mod.kind === "standard" ? "standard"
                       : null;
     // Solo clonamos si NO es la primera instancia de su kind (para no duplicar los core).
     // Si el módulo recién creado es vet/grooming/standard puro (id base), no hace falta.
     const isCloneOfBase = baseModuleId && mod.id !== baseModuleId;
     if (isCloneOfBase) {
       setServices(prev => {
         const baseServices = prev.filter(s => resolveServiceModuleId(s) === baseModuleId);
         const cloned = baseServices.map(s => ({
           ...s,
           id: `srv-${mod.id}-${s.id}`, // id único derivado del original
           moduleId: mod.id,            // ← apunta a la nueva instancia
           soldCount: 0,                // contador limpio
           clonedFrom: s.id,            // trazabilidad
         }));
         return [...prev, ...cloned];
       });
     }

     // Si el módulo es de tipo grooming/vet, también lo registramos en customModules
     // para que la cadena de routing existente (que aún consulta customModules en
     // varios lugares) lo reconozca. Cuando hagamos el motor unificado lo limpiaremos.
     if (mod.kind === "custom") {
       setCustomModules([...customModules, {
         id: mod.id,
         name: mod.name,
         role: mod.role,
         fields: mod.fields || [],
       }]);
     }
     setShowCreateModule(false);
     // Llevar al usuario al hub de CRM, donde el nuevo módulo aparece como pestaña.
     // El routing dinámico se encarga de renderizar el motor correcto según el kind.
     // Para módulos custom (kind="custom"), van a su vista propia.
     if (mod.kind === "custom") {
       setView(mod.id);
     } else {
       // Para módulos vet/grooming/standard recién clonados, ir directo a su vista
       // (gracias al routing dinámico). Si por alguna razón no se puede, caemos al hub.
       setView(mod.id);
     }
   }}
 />
 )}

 {showNewClient && <NewClientModal
   onClose={() => setShowNewClient(false)}
   clients={clients}
   setClients={setClients}
   passports={passports}
   setPassports={setPassports}
   userRole={user.role}
   perm={perm}
   customModules={customModules}
   modules={modules}
   onCreated={(code, destination, clientId, client) => {
     setShowNewClient(false);
     // El usuario eligió un destino concreto en el último paso del wizard.
     // Cada uno enruta a un punto natural del flujo de ese módulo.
     if (destination === "vet")             { setView("vet"); return; }
     if (destination === "grooming-ops")    { setView("grooming-ops"); return; }
     if (destination === "sales")           {
       // "Crear factura": preseleccionar el tutor recién registrado y abrir SaleBuilder.
       // Usamos el snapshot que NewClientModal nos pasó (no buscamos en `clients`
       // porque el setClients aún no se reflejó en este tick).
       const target = client || (clientId ? clients.find(c => c.id === clientId) : null);
       if (target) setPreselectedSaleClient(target);
       setView("new-service");
       return;
     }
     if (destination === "clients")         { setView("clients"); return; }
     if (destination === "passport") { if (code) goToPassport(code); else setView("clients"); return; }
     if (destination && customModules.find(m => m.id === destination)) { setView(destination); return; }
     // Default: ver el pasaporte recién creado
     if (code) goToPassport(code);
   }}
 />}

 {showProposalsModal && (
   <ProposalsReviewModal
     proposals={proposals}
     setProposals={setProposals}
     clients={clients}
     invoices={invoices}
     setInvoices={setInvoices}
     services={services}
     onClose={() => setShowProposalsModal(false)}
   />
 )}

 {showQuickClient && (
   <QuickClientModal
     onClose={() => setShowQuickClient(false)}
     clients={clients}
     setClients={setClients}
     onCreated={() => { setShowQuickClient(false); setView("clients"); }}
     onCreateSale={(client) => {
       setShowQuickClient(false);
       setPreselectedSaleClient(client);
       setView("new-service");
     }}
   />
 )}

 {completeClient && (
   <NewClientModal
     onClose={() => setCompleteClient(null)}
     clients={clients}
     setClients={setClients}
     passports={passports}
     setPassports={setPassports}
     existingClient={completeClient}
     userRole={user.role}
     perm={perm}
     customModules={customModules}
     modules={modules}
     onCreated={(code, destination, clientId, client) => {
       setCompleteClient(null);
       if (destination === "vet")          { setView("vet"); return; }
       if (destination === "grooming-ops") { setView("grooming-ops"); return; }
       if (destination === "sales")        {
         // "Crear factura": preseleccionar el tutor y abrir SaleBuilder.
         const target = client || (clientId ? clients.find(c => c.id === clientId) : null);
         if (target) setPreselectedSaleClient(target);
         setView("new-service");
         return;
       }
       if (destination === "clients")      { setView("clients"); return; }
       if (destination === "passport") { if (code) goToPassport(code); else setView("clients"); return; }
       if (destination && customModules.find(m => m.id === destination)) { setView(destination); return; }
       if (code) goToPassport(code); else setView("clients");
     }}
   />
 )}

 {/* Ventana de chat (overlay) */}
 {chatTargetClientId && (
   <ChatWindow
     client={clients.find(c => c.id === chatTargetClientId)}
     conversation={conversations[chatTargetClientId] || []}
     onClose={closeChatWindow}
     onSend={sendMessage}
   />
 )}
 </div>
 );
}

// ========== SIDEBAR ==========

// ========== Submenú de AJUSTES (expandible: Productos / Roles / Ajuste de clientes / Ajuste de agenda) ==========
// ========== VISTA HUB DE AJUSTES ==========
// Página dedicada que se muestra cuando el usuario hace click en el engranaje de la sidebar.
// Lista todas las secciones de ajustes en cards grandes para fácil acceso.
// Filtra por permisos del rol — el super ve todo, los demás según `can()`.
function SettingsHubView({ role, can, onNavigate }) {
  // Catálogo de secciones de ajustes con sus permisos requeridos.
  const allSections = [
    {
      id: "products",
      label: "Productos",
      icon: Package,
      desc: "Inventario, catálogos veterinaria y grooming.",
      accent: "from-orange-100 to-amber-100",
      iconColor: "text-orange-700",
      visible: () => can("inventory") || can("vet-catalog") || can("grooming") || role === "super",
    },
    {
      id: "manager",
      label: "Módulos",
      icon: LayoutGrid,
      desc: "Configura los módulos activos del sistema y sus categorías.",
      accent: "from-purple-100 to-pink-100",
      iconColor: "text-purple-700",
      visible: () => role === "super",
    },
    {
      id: "roles",
      label: "Roles & permisos",
      icon: ShieldCheck,
      desc: "Define qué puede ver y hacer cada rol del equipo.",
      accent: "from-emerald-100 to-teal-100",
      iconColor: "text-emerald-700",
      visible: () => role === "super",
    },
    {
      id: "users",
      label: "Usuarios",
      icon: UserPlus,
      desc: "Gestiona las cuentas del equipo y asígnales un rol.",
      accent: "from-amber-100 to-yellow-100",
      iconColor: "text-amber-700",
      visible: () => role === "super",
    },
    {
      id: "client-settings",
      label: "Ajuste de clientes",
      icon: Users,
      desc: "Segmentos, campos personalizados y preferencias de clientes.",
      accent: "from-blue-100 to-cyan-100",
      iconColor: "text-blue-700",
      visible: () => role === "super",
    },
    {
      id: "agenda-settings",
      label: "Ajuste de agenda",
      icon: Calendar,
      desc: "Horarios de atención, salas, recordatorios automáticos.",
      accent: "from-rose-100 to-orange-100",
      iconColor: "text-rose-700",
      visible: () => role === "super",
    },
  ];

  const sections = allSections.filter(s => s.visible());

  if (sections.length === 0) {
    return (
      <div className="max-w-2xl mx-auto pt-8">
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-10 text-center">
          <Settings size={28} className="text-stone-400 mx-auto mb-3" />
          <h2 className="font-serif text-2xl font-semibold mb-2">Sin ajustes disponibles</h2>
          <p className="text-sm text-stone-600">
            Tu rol no tiene permisos para acceder a opciones de configuración.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-5">
      {/* Hero */}
      <div className="bg-gradient-to-br from-white via-stone-50 to-orange-50 border border-stone-200 rounded-2xl p-6">
        <div className="flex items-start gap-4 flex-wrap">
          <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Settings size={26} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
              Panel de configuración
            </div>
            <h2 className="font-serif text-3xl font-semibold leading-tight">
              Ajustes <span className="italic text-orange-700">del sistema</span>
            </h2>
            <p className="text-sm text-stone-600 mt-1">
              Selecciona una sección para configurar. Tienes <strong>{sections.length}</strong> {sections.length === 1 ? "sección disponible" : "secciones disponibles"} según tu rol.
            </p>
          </div>
        </div>
      </div>

      {/* Lista de secciones (cards) */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {sections.map(s => {
          const Icon = s.icon;
          return (
            <button
              key={s.id}
              onClick={() => onNavigate(s.id)}
              className="group bg-white border border-stone-200 rounded-2xl p-5 text-left hover:border-orange-400 hover:shadow-lg hover:-translate-y-0.5 transition-all"
            >
              <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${s.accent} grid place-items-center mb-3 group-hover:scale-110 transition-transform`}>
                <Icon size={20} className={s.iconColor} strokeWidth={1.8} />
              </div>
              <h3 className="font-serif text-lg font-semibold leading-tight mb-1">{s.label}</h3>
              <p className="text-xs text-stone-500 leading-relaxed mb-3">{s.desc}</p>
              <div className="text-xs text-orange-700 font-semibold flex items-center gap-1 group-hover:gap-2 transition-all">
                Configurar <ChevronRight size={12} />
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}

function SettingsMenu({ collapsed, view, setView, can, role }) {
  const SETTINGS_VIEWS = ["settings-hub", "products", "roles", "client-settings", "agenda-settings", "inventory", "vet-catalog", "grooming", "manager"];
  const isOnSettings = SETTINGS_VIEWS.includes(view);
  const [open, setOpen] = useState(isOnSettings);

  // Si navegan a una vista de Ajustes desde otro lado, expandir automáticamente
  useEffect(() => { if (isOnSettings) setOpen(true); }, [isOnSettings]);

  const subItems = [];
  // Productos = catálogos + inventario (todos juntos, decisión de UX)
  if (can("inventory") || can("vet-catalog") || can("grooming") || role === "super") {
    subItems.push({ id: "products", icon: Package, label: "Productos", isActive: ["products","inventory","vet-catalog","grooming"].includes(view) });
  }
  if (role === "super") {
    subItems.push({ id: "manager", icon: LayoutGrid, label: "Módulos", isActive: view === "manager" });
    subItems.push({ id: "roles", icon: ShieldCheck, label: "Roles & permisos", isActive: view === "roles" });
    subItems.push({ id: "client-settings", icon: Users, label: "Ajuste de clientes", isActive: view === "client-settings" });
    subItems.push({ id: "agenda-settings", icon: Calendar, label: "Ajuste de agenda", isActive: view === "agenda-settings" });
  }
  if (subItems.length === 0) return null;

  // Cuando la sidebar está colapsada: click directo navega al hub de ajustes (vista lista).
  // Esto evita el problema de que un popover quedaba escondido o no se podía abrir.
  if (collapsed) {
    return (
      <button
        onClick={() => setView("settings-hub")}
        title="Ajustes"
        className={`relative flex items-center justify-center w-full h-10 rounded-lg transition ${
          isOnSettings
            ? "bg-orange-600 text-white shadow-md"
            : "text-stone-300 hover:bg-stone-800 hover:text-white"
        }`}
      >
        {isOnSettings && <span className="absolute -left-3 top-2 bottom-2 w-1 bg-orange-400 rounded-r"></span>}
        <Settings size={18} strokeWidth={isOnSettings ? 2 : 1.8} />
      </button>
    );
  }

  return (
    <div>
      <button
        onClick={() => {
          // Si no estás en ninguna vista de ajustes, click navega al hub.
          // Si ya estás en una vista de ajustes, solo togglea la lista expandida.
          if (!isOnSettings) {
            setView("settings-hub");
            setOpen(true);
          } else {
            setOpen(o => !o);
          }
        }}
        className={`flex items-center gap-3 w-full px-3 py-2 rounded-lg text-sm font-medium transition relative ${
          isOnSettings
            ? "bg-orange-600 text-white font-semibold shadow-md"
            : "text-stone-300 hover:bg-stone-800 hover:text-white"
        }`}
      >
        {isOnSettings && <span className="absolute -left-3 top-2 bottom-2 w-1 bg-orange-400 rounded-r"></span>}
        <Settings size={17} strokeWidth={isOnSettings ? 2 : 1.8} />
        <span className="flex-1 text-left">Ajustes</span>
        <ChevronDown size={13} className={`transition-transform ${open ? "rotate-180" : ""} ${isOnSettings ? "text-white" : "text-stone-500"}`} />
      </button>
      {open && (
        <div className="ml-3 mt-0.5 pl-3 border-l border-stone-800 space-y-0.5">
          {/* Link al hub (siempre primero) */}
          <button
            onClick={() => setView("settings-hub")}
            className={`flex items-center gap-2.5 w-full px-2.5 py-1.5 rounded-md text-xs font-medium transition ${
              view === "settings-hub"
                ? "bg-stone-800 text-orange-300"
                : "text-stone-400 hover:bg-stone-800 hover:text-stone-100"
            }`}
          >
            <LayoutGrid size={13} strokeWidth={1.8} />
            <span className="flex-1 text-left">Vista general</span>
          </button>
          {subItems.map(item => {
            const Icon = item.icon;
            return (
              <button
                key={item.id}
                onClick={() => setView(item.id)}
                className={`flex items-center gap-2.5 w-full px-2.5 py-1.5 rounded-md text-xs font-medium transition ${
                  item.isActive
                    ? "bg-stone-800 text-orange-300"
                    : "text-stone-400 hover:bg-stone-800 hover:text-stone-100"
                }`}
              >
                <Icon size={13} strokeWidth={1.8} />
                <span className="flex-1 text-left">{item.label}</span>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

function Sidebar({ view, setView, customModules, passportsCount, onNewClientQuick, onNewClientFull, user, onLogout, permissions, unreadMessagesCount, petUpdates = [], collapsed = false, onToggleCollapsed }) {
 const [showNewClientMenu, setShowNewClientMenu] = useState(false);
 const role = user?.role;
 const perm = permissions[role] || {};
 const can = (v) => canAccess(perm, v);

 // NavItem sensible al estado collapsed.
 // - Expandido: icono + label completo + badge a la derecha
 // - Colapsado: solo icono centrado (38x38), tooltip nativo, badge como dot rojo top-right
 const NavItem = ({ icon: Icon, label, badge, active, onClick }) => {
   if (collapsed) {
     return (
       <button
         onClick={onClick}
         title={label}
         className={`relative flex items-center justify-center w-full h-10 rounded-lg transition ${
           active
             ? "bg-orange-600 text-white shadow-md"
             : "text-stone-300 hover:bg-stone-800 hover:text-white"
         }`}
       >
         {active && <span className="absolute -left-3 top-2 bottom-2 w-1 bg-orange-400 rounded-r"></span>}
         <Icon size={18} strokeWidth={active ? 2 : 1.8} />
         {badge && (
           <span className={`absolute top-1 right-1 w-2 h-2 rounded-full ${
             badge.soft ? "bg-orange-400" : "bg-orange-500"
           } ring-2 ring-stone-900`}></span>
         )}
       </button>
     );
   }
   return (
     <button
       onClick={onClick}
       className={`flex items-center gap-3 w-full px-3 py-2 rounded-lg text-sm font-medium transition relative ${
         active
           ? "bg-orange-600 text-white font-semibold shadow-md"
           : "text-stone-300 hover:bg-stone-800 hover:text-white"
       }`}
     >
       {active && <span className="absolute -left-3 top-2 bottom-2 w-1 bg-orange-400 rounded-r"></span>}
       <Icon size={17} strokeWidth={active ? 2 : 1.8} />
       <span className="flex-1 text-left">{label}</span>
       {badge && (
         <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${
           active
             ? "bg-white text-orange-700"
             : badge.soft ? "bg-stone-700 text-orange-300" : "bg-orange-600 text-white"
         }`}>
           {badge.value}
         </span>
       )}
     </button>
   );
 };

 return (
 <aside className={`${collapsed ? "w-16" : "w-64"} bg-stone-900 text-stone-200 flex flex-col sticky top-0 h-screen overflow-y-auto flex-shrink-0 transition-all duration-200`}>
 {/* Brand — click toggle expandir/colapsar */}
 <button
   onClick={onToggleCollapsed}
   title={collapsed ? "Expandir menú" : "Colapsar menú"}
   className={`${collapsed ? "p-3" : "p-5"} border-b border-stone-800 flex items-center ${collapsed ? "justify-center" : "gap-3"} hover:bg-stone-800 transition group w-full text-left`}
 >
   <div className="group-hover:scale-105 transition flex-shrink-0">
     <CricketLogoIcon size={collapsed ? 44 : 40} />
   </div>
   {!collapsed && (
     <div className="flex-1 min-w-0">
       {/* Wordmark con paths reales del logo, en gris claro para contraste sobre el fondo oscuro */}
       <CricketWordmark color="#e7e5e4" height={22} />
       <div className="text-[9px] tracking-[0.2em] text-orange-400 uppercase font-semibold mt-1">
         Pet System
       </div>
     </div>
   )}
 </button>

 <nav className="p-3 flex-1 space-y-0.5">
 {/* === 1. DASHBOARD === */}
 {can("dashboard") && <NavItem icon={LayoutDashboard} label="Dashboard" active={view === "dashboard"} onClick={() => setView("dashboard")} />}

 {/* === 2. AGENDA === */}
 {can("agenda") && <NavItem icon={Calendar} label="Agenda" badge={{ value: 12 }} active={view === "agenda"} onClick={() => setView("agenda")} />}

 {/* === 3. MENSAJES === */}
 {can("messages") && <NavItem icon={MessageCircle} label="Mensajes" badge={unreadMessagesCount > 0 ? { value: unreadMessagesCount } : null} active={view === "messages"} onClick={() => setView("messages")} />}

 {/* === 4. CRM unificado (Veterinaria + Grooming + B2B según rol) === */}
 {(can("crm") || can("vet") || can("grooming-ops") || can("grooming") || can("standard") || can("vet-catalog") || can("manager")) && (
   <NavItem
     icon={LayoutGrid}
     label="CRM"
     badge={{ value: (can("vet") ? 6 : 0) + (can("grooming-ops") ? 5 : 0) || null, soft: true }}
     active={["crm","vet","grooming-ops","grooming","standard","manager"].includes(view)}
     onClick={() => setView("crm")}
   />
 )}

 {/* === 5. CLIENTES (incluye Pasaportes y Pasaporte clínico) === */}
 {(can("clients") || can("passport") || can("vet-passport") || perm.canCreateClient) && (
   <>
     <NavItem
       icon={Users}
       label="Clientes"
       badge={petUpdates.filter(u => u.status === "pending").length > 0 ? { value: petUpdates.filter(u => u.status === "pending").length, soft: true } : null}
       active={["clients","passport","vet-passport"].includes(view)}
       onClick={() => setView("clients")}
     />

     {/* CTA Nuevo cliente — sólo para roles que pueden crear clientes */}
     {perm.canCreateClient && (
       collapsed ? (
         <button
           onClick={() => onNewClientQuick && onNewClientQuick()}
           title="Nuevo cliente (registro rápido)"
           className="my-1 w-full h-10 rounded-lg bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center shadow-lg hover:-translate-y-0.5 transition"
         >
           <Plus size={18} strokeWidth={2.6} />
         </button>
       ) : (
         <div className="relative my-1">
           <button
             onClick={() => setShowNewClientMenu(v => !v)}
             className="flex items-center gap-2.5 w-full px-3 py-2.5 rounded-lg bg-gradient-to-br from-orange-500 to-orange-700 text-white text-sm font-semibold shadow-lg hover:-translate-y-0.5 transition relative overflow-hidden"
           >
             <span className="w-5 h-5 rounded-md bg-stone-700 grid place-items-center flex-shrink-0">
               <Plus size={13} strokeWidth={2.6} />
             </span>
             <span>Nuevo cliente</span>
             <ChevronDown size={13} className={`ml-auto transition-transform ${showNewClientMenu ? "rotate-180" : ""}`} />
           </button>
           {showNewClientMenu && (
             <>
               <div onClick={() => setShowNewClientMenu(false)} className="fixed inset-0 z-30"></div>
               <div className="absolute left-0 right-0 mt-1 bg-white border border-stone-200 rounded-xl shadow-2xl z-40 overflow-hidden">
                 <button
                   onClick={() => { setShowNewClientMenu(false); onNewClientQuick && onNewClientQuick(); }}
                   className="w-full flex items-start gap-3 p-3 hover:bg-orange-50 transition text-left border-b border-stone-100"
                 >
                   <div className="w-8 h-8 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                     <Zap size={14} strokeWidth={2} />
                   </div>
                   <div className="flex-1 min-w-0">
                     <div className="font-semibold text-sm text-stone-900">Registro rápido</div>
                     <div className="text-xs text-stone-500 mt-0.5 leading-snug">Solo cédula, teléfono y dirección. 30 segundos.</div>
                   </div>
                 </button>
                 <button
                   onClick={() => { setShowNewClientMenu(false); onNewClientFull && onNewClientFull(); }}
                   className="w-full flex items-start gap-3 p-3 hover:bg-orange-50 transition text-left"
                 >
                   <div className="w-8 h-8 rounded-lg bg-orange-100 text-orange-700 grid place-items-center flex-shrink-0">
                     <Stethoscope size={14} strokeWidth={2} />
                   </div>
                   <div className="flex-1 min-w-0">
                     <div className="font-semibold text-sm text-stone-900">Ficha clínica completa</div>
                     <div className="text-xs text-stone-500 mt-0.5 leading-snug">Cliente + mascota + historia clínica inicial.</div>
                   </div>
                 </button>
               </div>
             </>
           )}
         </div>
       )
     )}
   </>
 )}

 {/* === 6. AJUSTES (submenú expandible) — Productos, Roles, Ajuste de clientes, Ajuste de agenda === */}
 {(role === "super" || can("inventory") || can("vet-catalog") || can("grooming") || can("sales") || can("new-service")) && (
   <SettingsMenu
     collapsed={collapsed}
     view={view}
     setView={setView}
     can={can}
     role={role}
   />
 )}
 </nav>

 <div className={`border-t border-stone-800 ${collapsed ? "p-2 flex flex-col items-center gap-2" : ""}`}>
   <button
     onClick={() => setView("profile")}
     className={`${collapsed ? "p-0" : "p-4"} flex items-center ${collapsed ? "justify-center" : "gap-2.5"} w-full hover:bg-stone-800 transition text-left ${collapsed ? "rounded-lg" : ""}`}
     title={collapsed ? `${user?.name || "Invitado"} — Mi perfil` : "Mi perfil"}
   >
     <div className={`w-9 h-9 rounded-full grid place-items-center text-white text-xs font-bold border-2 flex-shrink-0 transition ${
       view === "profile" ? "border-orange-500 bg-gradient-to-br from-orange-400 to-orange-600" : "border-stone-800 bg-gradient-to-br from-orange-500 to-orange-700"
     }`}>
       {user?.initials || "?"}
     </div>
     {!collapsed && (
       <>
         <div className="flex-1 min-w-0">
           <div className="text-xs font-semibold text-stone-100 truncate">{user?.name || "Invitado"}</div>
           <div className="text-xs text-stone-500 tracking-wide">{user?.roleLabel || ""}</div>
         </div>
         <span
           onClick={(e) => { e.stopPropagation(); onLogout(); }}
           title="Cerrar sesión"
           className="w-8 h-8 rounded-lg bg-stone-800 hover:bg-stone-700 text-stone-400 hover:text-white grid place-items-center transition flex-shrink-0 cursor-pointer"
         >
           <LogOut size={14} />
         </span>
       </>
     )}
   </button>
   {/* Botón de logout siempre visible cuando sidebar está colapsado.
       Aparece encima del avatar (en realidad debajo, apilado) para que el usuario
       pueda cerrar sesión sin tener que expandir el sidebar primero. */}
   {collapsed && (
     <button
       onClick={onLogout}
       title="Cerrar sesión"
       className="w-9 h-9 rounded-lg bg-stone-800 hover:bg-red-900 text-stone-400 hover:text-white grid place-items-center transition border border-stone-700 hover:border-red-700"
     >
       <LogOut size={14} />
     </button>
   )}
 </div>
 </aside>
 );
}

