// ========== MODAL: CREAR MÓDULO ==========

function CreateModuleModal({ onClose, onCreate, modules = [] }) {
 // Paso 1: elegir plantilla. Paso 2: configurar nombre/columnas/campos.
 const [step, setStep] = useState(1);
 const [template, setTemplate] = useState(null); // 'vet' | 'grooming' | 'custom'
 const [name, setName] = useState("");
 const [role, setRole] = useState("");
 const [fields, setFields] = useState([
   { id: 1, label: "Nombre del cliente", type: "text" },
   { id: 2, label: "Teléfono", type: "text" },
 ]);
 // Columnas del kanban — configurables por módulo. Cada plantilla trae un default.
 const [columns, setColumns] = useState([]);

 const TEMPLATES = [
   {
     id: "vet", kind: "vet", Icon: Stethoscope, color: "orange",
     name: "Veterinaria",
     description: "Para clínicas: consultas, fichas clínicas, sugerencias de medicina por diagnóstico.",
     defaultColumns: [
       { id: "reserva-hoy",   label: "Reserva hoy" },
       { id: "en-consulta",   label: "En consulta" },
       { id: "tratamiento",   label: "Tratamiento en sede" },
       { id: "control",       label: "Control / Vacunación" },
       { id: "finalizado",    label: "Finalizado" },
     ],
     defaultRole: "Veterinario",
     accent: "from-orange-500 to-orange-700",
     tone: "from-orange-100 to-orange-50 text-orange-800",
     icon: "Stethoscope",
     example: "Útil si necesitas otra clínica con su propio equipo (ej. una sucursal o especialidad como dermatología).",
   },
   {
     id: "grooming", kind: "grooming", Icon: Bath, color: "emerald",
     name: "Grooming",
     description: "Para peluquería canina: catálogo visual, agenda diaria, control de insumos por servicio.",
     defaultColumns: [
       { id: "pending", label: "Por hacer" },
       { id: "active",  label: "En proceso" },
       { id: "done",    label: "Terminado" },
     ],
     defaultRole: "Groomer",
     accent: "from-emerald-500 to-emerald-700",
     tone: "from-emerald-100 to-emerald-50 text-emerald-800",
     icon: "Bath",
     example: "Útil si quieres llamarlo \"Peluquería canina\" o tener una segunda sala con sus propias columnas.",
   },
   {
     id: "custom", kind: "custom", Icon: LayoutGrid, color: "blue",
     name: "Personalizado",
     description: "CRM genérico: tú defines las columnas, los campos y el flujo. Útil para procesos no contemplados.",
     defaultColumns: [
       { id: "col1", label: "Por hacer" },
       { id: "col2", label: "En proceso" },
       { id: "col3", label: "Hecho" },
     ],
     defaultRole: "Operador",
     accent: "from-blue-500 to-blue-700",
     tone: "from-blue-100 to-blue-50 text-blue-800",
     icon: "LayoutGrid",
     example: "Adopciones, guardería, transporte, hospedaje... cualquier proceso con etapas que se mueven en kanban.",
   },
 ];

 // Al elegir plantilla, precargamos columnas y rol sugeridos
 const pickTemplate = (tpl) => {
   setTemplate(tpl);
   setColumns(tpl.defaultColumns.map((c, i) => ({ ...c, key: `${c.id}-${i}-${Date.now()}` })));
   if (!role) setRole(tpl.defaultRole);
   setStep(2);
 };

 const roleAuto = useMemo(() => {
   if (role) return role;
   if (!name.trim()) return template?.defaultRole || "";
   return `Encargado de ${name}`;
 }, [name, role, template]);

 const canCreate = name.trim() && template && columns.length >= 2 && columns.every(c => (c.label || "").trim());

 const handleSubmit = () => {
   if (!canCreate) return;
   // Generamos un id único basado en el kind + timestamp. Si es custom, prefijamos.
   // Esto permite tener múltiples módulos del mismo kind (ej: 2 módulos grooming con
   // nombres distintos: "Grooming" + "Peluquería canina").
   const newId = `${template.kind}-${Date.now().toString(36)}`;
   onCreate({
     id: newId,
     kind: template.kind,
     name: name.trim(),
     shortName: name.trim().slice(0, 16),
     role: (role.trim() || roleAuto),
     icon: template.icon,
     tone: template.tone,
     accent: template.accent,
     description: `${template.name} · ${columns.length} columnas configurables.`,
     meta: columns.slice(0, 3).map(c => c.label),
     columns: columns.map(c => ({ id: c.id, label: c.label.trim() })),
     fields: fields.filter(f => f.label.trim()),
     core: false,
     removed: false,
     createdAt: new Date().toISOString(),
   });
 };

 return (
 <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 sm:p-16 overflow-y-auto">
 <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-3xl shadow-2xl overflow-hidden">
 <div className="p-5 border-b border-stone-200 bg-gradient-to-r from-white to-orange-50 flex items-center gap-3">
 <div className="w-10 h-10 rounded-xl bg-orange-600 text-white grid place-items-center shadow-lg"><Sparkles size={20} /></div>
 <div className="flex-1">
 <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
   Nuevo módulo · Paso {step} de 2
 </div>
 <h3 className="font-serif text-xl font-semibold mt-0.5">
   {step === 1 ? <>Elige una <span className="text-orange-700">plantilla</span></> : <>Configura tu <span className="text-orange-700">{template?.name.toLowerCase()}</span></>}
 </h3>
 </div>
 <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
 <X size={16} />
 </button>
 </div>

 {/* === PASO 1: Selección de plantilla === */}
 {step === 1 && (
 <div className="p-5 space-y-3">
   <p className="text-sm text-stone-600 leading-relaxed">
     Cada módulo es <strong>el mismo motor con configuración distinta</strong>. Las plantillas Veterinaria y Grooming traen ejemplos pre-configurados; la Personalizada arranca desde cero.
   </p>
   <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
     {TEMPLATES.map(tpl => {
       const Ic = tpl.Icon;
       // ¿Ya hay un módulo de este kind? Solo informativo, no bloquea
       const existing = (modules || []).filter(m => m.kind === tpl.kind && !m.removed).length;
       return (
         <button
           key={tpl.id}
           onClick={() => pickTemplate(tpl)}
           className={`text-left p-4 rounded-2xl border-2 bg-white hover:-translate-y-0.5 hover:shadow-md transition ${
             tpl.color === "orange" ? "border-orange-200 hover:border-orange-400" :
             tpl.color === "emerald" ? "border-emerald-200 hover:border-emerald-400" :
             "border-blue-200 hover:border-blue-400"
           }`}
         >
           <div className={`w-11 h-11 rounded-xl bg-gradient-to-br ${tpl.accent} text-white grid place-items-center shadow mb-3`}>
             <Ic size={20} strokeWidth={1.8} />
           </div>
           <div className="font-serif text-base font-semibold mb-1">{tpl.name}</div>
           <p className="text-xs text-stone-600 leading-relaxed mb-2">{tpl.description}</p>
           <div className="text-xs text-stone-500 italic mb-2">{tpl.example}</div>
           <div className="flex items-center justify-between pt-2 border-t border-dashed border-stone-200">
             <span className="text-xs text-stone-500">{tpl.defaultColumns.length} columnas</span>
             {existing > 0 && (
               <span className="text-xs font-semibold text-orange-700">+{existing} ya activos</span>
             )}
           </div>
         </button>
       );
     })}
   </div>
 </div>
 )}

 {/* === PASO 2: Configuración del módulo === */}
 {step === 2 && template && (
 <div className="p-5 space-y-4">
   <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
     <Field label="Nombre del módulo">
       <input
         className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
         placeholder={`Ej: ${template.kind === "grooming" ? "Peluquería canina" : template.kind === "vet" ? "Clínica San Bernardo" : "Adopciones"}`}
         value={name}
         onChange={(e) => setName(e.target.value)}
         autoFocus
       />
     </Field>
     <Field label="Rol asociado (auto-creado)">
       <input
         className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
         placeholder={roleAuto || "Se autocompleta"}
         value={role}
         onChange={(e) => setRole(e.target.value)}
       />
     </Field>
   </div>

   {/* Editor de columnas del kanban */}
   <div>
     <div className="flex items-center justify-between mb-2">
       <label className="text-xs font-semibold text-stone-600 tracking-wide">
         Columnas del kanban · {columns.length}
       </label>
       <span className="text-xs text-stone-400">Mínimo 2, máximo 8</span>
     </div>
     <div className="space-y-2">
       {columns.map((c, idx) => (
         <div key={c.key} className="flex items-center gap-2 p-2.5 bg-white rounded-xl border border-stone-200">
           <span className={`w-6 h-6 rounded-md grid place-items-center text-xs font-mono font-bold flex-shrink-0 ${
             template.color === "orange" ? "bg-orange-100 text-orange-700" :
             template.color === "emerald" ? "bg-emerald-100 text-emerald-700" :
             "bg-blue-100 text-blue-700"
           }`}>
             {idx + 1}
           </span>
           <input
             placeholder="Nombre de la columna (ej: Por hacer)"
             value={c.label}
             onChange={(e) => setColumns(columns.map(x => x.key === c.key ? { ...x, label: e.target.value } : x))}
             className="flex-1 border-none outline-none text-sm bg-transparent"
           />
           {columns.length > 2 && (
             <button
               onClick={() => setColumns(columns.filter(x => x.key !== c.key))}
               className="w-7 h-7 rounded-md text-stone-400 hover:text-red-500 grid place-items-center"
               title="Eliminar columna"
             >
               <Trash2 size={13} />
             </button>
           )}
         </div>
       ))}
       {columns.length < 8 && (
         <button
           onClick={() => setColumns([...columns, { id: `col-${Date.now()}`, label: "", key: `new-${Date.now()}` }])}
           className="w-full flex items-center justify-center gap-2 px-3 py-2 rounded-xl bg-white border border-dashed border-stone-300 hover:border-orange-400 text-stone-600 hover:text-orange-700 text-sm font-semibold transition"
         >
           <Plus size={14} /> Añadir columna
         </button>
       )}
     </div>
   </div>

   <div className="p-3 rounded-xl bg-orange-50 border border-orange-200 flex gap-2.5 text-xs text-orange-900 leading-relaxed">
     <ShieldCheck size={14} className="text-orange-700 flex-shrink-0 mt-0.5" />
     <div>
       Al crear este módulo se generará automáticamente el rol <strong>"{roleAuto || "..."}"</strong> con permisos de lectura/escritura. Podrás asignar usuarios desde <em>Roles &amp; permisos</em>. Las columnas y el nombre se pueden seguir editando luego desde <em>Ajustes → Módulos</em>.
     </div>
   </div>
 </div>
 )}

 <div className="p-3.5 px-5 border-t border-stone-200 bg-white flex justify-end gap-2">
   <button onClick={step === 1 ? onClose : () => setStep(1)} className="px-4 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200 hover:border-orange-400">
     {step === 1 ? "Cancelar" : "← Cambiar plantilla"}
   </button>
   {step === 2 && (
     <button
       onClick={handleSubmit}
       disabled={!canCreate}
       className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white transition ${
         canCreate ? "" : "opacity-40 cursor-not-allowed"
       }`}
     >
       <Check size={14} /> Crear módulo
     </button>
   )}
 </div>
 </div>
 </div>
 );
}

// ========== VISTA: ROLES & PERMISOS ==========

// ========== Panel de permisos por CAMPO en cada CRM (Roles & Permisos) ==========
// Por cada CRM (vet, grooming, B2B, custom) renderiza una tarjeta con sus secciones
// y campos. Cada campo tiene un selector triple: oculto / ver / editar.
// Cada sección tiene un botón "aplicar a todos" para acelerar la configuración masiva.
function CRMFieldsPermissionsPanel({ role, permissions, setPermissions, isSuper, onChange }) {
  // Track: qué CRM y secciones están expandidos. Default: todos los CRM colapsados,
  // se expanden al hacer click. Adentro: secciones expandidas por default.
  const [expandedCRMs, setExpandedCRMs] = useState(() => new Set());

  if (isSuper) {
    return (
      <div className="bg-stone-50 border border-stone-200 rounded-2xl p-5 text-center">
        <ShieldCheck size={28} className="text-orange-600 mx-auto mb-2" />
        <div className="font-semibold text-stone-900">Super usuario</div>
        <p className="text-xs text-stone-500 mt-1 max-w-md mx-auto">
          El super usuario tiene acceso a todos los campos de todos los CRMs sin restricción.
        </p>
      </div>
    );
  }

  const currentFields = permissions[role]?.fields || {};

  const setLevel = (crmId, sectionId, fieldId, level) => {
    const key = `${sectionId}.${fieldId}`;
    setPermissions(prev => ({
      ...prev,
      [role]: {
        ...prev[role],
        fields: {
          ...(prev[role].fields || {}),
          [crmId]: {
            ...((prev[role].fields || {})[crmId] || {}),
            [key]: level,
          },
        },
      },
    }));
    onChange && onChange();
  };

  // Aplicar un nivel a TODOS los campos de una sección (atajo masivo).
  const applyToSection = (crmId, sectionId, level) => {
    const sectionFields = CRM_FIELD_SCHEMA[crmId]?.sections?.[sectionId]?.fields || [];
    setPermissions(prev => {
      const prevFields = (prev[role].fields || {})[crmId] || {};
      const nextFields = { ...prevFields };
      sectionFields.forEach(f => {
        // Si el campo no es editable, máximo es "view"
        const finalLevel = (level === "edit" && !f.editable) ? "view" : level;
        nextFields[`${sectionId}.${f.id}`] = finalLevel;
      });
      return {
        ...prev,
        [role]: {
          ...prev[role],
          fields: { ...(prev[role].fields || {}), [crmId]: nextFields },
        },
      };
    });
    onChange && onChange();
  };

  const toggleCRM = (crmId) => {
    setExpandedCRMs(prev => {
      const next = new Set(prev);
      if (next.has(crmId)) next.delete(crmId); else next.add(crmId);
      return next;
    });
  };

  // Helper: obtener el nivel actual del campo (con fallback al schema default)
  const levelOf = (crmId, sectionId, field) => {
    const stored = currentFields[crmId]?.[`${sectionId}.${field.id}`];
    return stored || field.defaultLevel;
  };

  return (
    <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
      <div className="p-5 border-b border-stone-200 bg-stone-50">
        <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
          Acceso a campos por CRM
        </div>
        <h3 className="font-serif text-xl font-semibold leading-tight">
          Permisos granulares por campo
        </h3>
        <p className="text-xs text-stone-500 mt-1">
          Define qué información de cada CRM se muestra a este rol y cuál puede editar.
          Los cambios sensibles (microchip, tutores) requieren aprobación del super.
        </p>
      </div>

      <div className="p-4 space-y-3">
        {Object.entries(CRM_FIELD_SCHEMA).map(([crmId, crm]) => {
          const isOpen = expandedCRMs.has(crmId);
          // Resumen del CRM: contar cuántos campos visibles vs total
          const allFields = Object.entries(crm.sections).flatMap(([secId, sec]) =>
            sec.fields.map(f => ({ secId, field: f, level: levelOf(crmId, secId, f) }))
          );
          const visibleCount = allFields.filter(f => f.level !== "hidden").length;
          const editableCount = allFields.filter(f => f.level === "edit").length;

          return (
            <div key={crmId} className="border border-stone-200 rounded-xl overflow-hidden">
              {/* Header CRM clickeable */}
              <button
                onClick={() => toggleCRM(crmId)}
                className="w-full flex items-center gap-3 p-3 hover:bg-stone-50 transition text-left"
              >
                <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-orange-100 to-orange-200 grid place-items-center text-orange-700 flex-shrink-0">
                  {crmId === "vet" ? <Stethoscope size={15} /> :
                   crmId === "grooming" ? <Scissors size={15} /> :
                   crmId === "standard" ? <Tag size={15} /> :
                   <Sparkles size={15} />}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-sm">{crm.label}</div>
                  <div className="text-xs text-stone-500">
                    {visibleCount} / {allFields.length} campos visibles
                    {" · "}
                    {editableCount} editables
                  </div>
                </div>
                <ChevronDown size={14} className={`text-stone-400 transition-transform ${isOpen ? "rotate-180" : ""}`} />
              </button>

              {/* Contenido del CRM */}
              {isOpen && (
                <div className="border-t border-stone-200 bg-stone-50">
                  {Object.entries(crm.sections).map(([sectionId, section]) => (
                    <div key={sectionId} className="border-b border-stone-200 last:border-b-0 p-3">
                      {/* Header sección con atajos masivos */}
                      <div className="flex items-start justify-between gap-3 mb-2">
                        <div className="flex-1 min-w-0">
                          <div className="text-xs font-bold uppercase tracking-wide text-stone-700">
                            {section.label}
                          </div>
                          {section.description && (
                            <div className="text-xs text-stone-500 mt-0.5 leading-snug">
                              {section.description}
                            </div>
                          )}
                        </div>
                        <div className="flex gap-1 flex-shrink-0">
                          <button
                            onClick={() => applyToSection(crmId, sectionId, "hidden")}
                            title="Ocultar todos los campos de esta sección"
                            className="text-xs px-2 py-1 rounded-md bg-white border border-stone-200 hover:border-stone-400 text-stone-600 font-semibold transition"
                          >
                            Ocultar todo
                          </button>
                          <button
                            onClick={() => applyToSection(crmId, sectionId, "view")}
                            title="Solo lectura para todos los campos de esta sección"
                            className="text-xs px-2 py-1 rounded-md bg-white border border-stone-200 hover:border-blue-400 text-blue-700 font-semibold transition"
                          >
                            Solo ver
                          </button>
                          <button
                            onClick={() => applyToSection(crmId, sectionId, "edit")}
                            title="Permitir editar todos los campos de esta sección"
                            className="text-xs px-2 py-1 rounded-md bg-white border border-stone-200 hover:border-emerald-400 text-emerald-700 font-semibold transition"
                          >
                            Editar todo
                          </button>
                        </div>
                      </div>

                      {/* Campos individuales */}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-1.5 mt-2">
                        {section.fields.map(field => {
                          const level = levelOf(crmId, sectionId, field);
                          return (
                            <div
                              key={field.id}
                              className="bg-white border border-stone-200 rounded-lg p-2 flex items-center gap-2"
                            >
                              <div className="flex-1 min-w-0">
                                <div className="text-xs font-semibold text-stone-800 truncate">
                                  {field.label}
                                </div>
                                {!field.editable && (
                                  <div className="text-xs text-stone-400 italic">Solo lectura</div>
                                )}
                              </div>
                              <FieldLevelSelector
                                value={level}
                                disabled={!field.editable && level === "edit"}
                                allowEdit={field.editable}
                                onChange={(newLevel) => setLevel(crmId, sectionId, field.id, newLevel)}
                              />
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// Selector triple: oculto / ver / editar.
// Si el campo no es editable, "edit" se deshabilita.
function FieldLevelSelector({ value, onChange, allowEdit = true }) {
  const options = [
    { id: "hidden", label: "Oculto",   icon: EyeOff,    activeBg: "bg-stone-200 text-stone-700" },
    { id: "view",   label: "Ver",      icon: Eye,       activeBg: "bg-blue-100 text-blue-800" },
    ...(allowEdit ? [{ id: "edit", label: "Editar", icon: Edit3, activeBg: "bg-emerald-100 text-emerald-800" }] : []),
  ];
  return (
    <div className="flex gap-px bg-stone-100 rounded-md p-px flex-shrink-0">
      {options.map(opt => {
        const Icon = opt.icon;
        const active = value === opt.id;
        return (
          <button
            key={opt.id}
            onClick={() => onChange(opt.id)}
            title={opt.label}
            className={`px-2 py-1 rounded text-xs font-semibold transition flex items-center gap-1 ${
              active ? opt.activeBg : "text-stone-500 hover:bg-white"
            }`}
          >
            <Icon size={11} strokeWidth={active ? 2.4 : 1.8} />
            <span className="hidden sm:inline">{opt.label}</span>
          </button>
        );
      })}
    </div>
  );
}

function RolesView({ permissions, setPermissions, modules = [], customRoles = [], setCustomRoles }) {
  const [selectedRole, setSelectedRole] = useState("vet");
  const [savedFlash, setSavedFlash] = useState(false);
  const [showCreateRole, setShowCreateRole] = useState(false);
  // Modal de confirmación de eliminación (no usamos window.confirm porque no funciona
  // bien en algunos sandboxes/embeds de Claude)
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  // Modal de edición de etiquetas — para cualquier rol (core o custom).
  // Solo se editan etiquetas y filtro técnico, no el resto de la identidad.
  const [editingTagsRoleId, setEditingTagsRoleId] = useState(null);

  // Roles core hardcoded
  const baseRoleOptions = [
    { id: "super",    label: "Super usuario", desc: "Acceso total", Icon: ShieldCheck, color: "from-orange-500 to-orange-700", count: ACCOUNTS.filter(a => a.role === "super").length, core: true },
    { id: "vet",      label: "Veterinario",   desc: "Clínica veterinaria", Icon: Stethoscope, color: "from-blue-500 to-blue-700", count: ACCOUNTS.filter(a => a.role === "vet").length, core: true },
    { id: "grooming", label: "Groomer",       desc: "Peluquería canina",  Icon: Scissors,    color: "from-emerald-500 to-emerald-700", count: ACCOUNTS.filter(a => a.role === "grooming").length, core: true },
    { id: "sales",    label: "Ventas",        desc: "Ventas y clientes",  Icon: ShoppingBag, color: "from-amber-500 to-amber-700", count: ACCOUNTS.filter(a => a.role === "sales").length, core: true },
  ];
  // Combinar roles core + custom
  const roleOptions = useMemo(() => {
    // Separar entradas shadow (overrides de etiquetas para roles core) del resto
    const shadows = (customRoles || []).filter(r => r.isCoreOverride);
    const realCustoms = (customRoles || []).filter(r => !r.isCoreOverride);

    // Helper: encontrar la shadow entry de un rol core
    const findShadow = (coreId) => shadows.find(s => s.shadowOf === coreId);

    // Roles core enriquecidos con sus etiquetas shadow (si las tienen)
    const coresWithTags = baseRoleOptions.map(r => {
      const shadow = findShadow(r.id);
      return {
        ...r,
        assignedTags: shadow?.assignedTags || [],
        assignedModuleIds: shadow?.assignedModuleIds || [],
      };
    });

    const customs = realCustoms.map(r => ({
      id: r.id,
      label: r.label,
      desc: r.desc || "Rol personalizado",
      Icon: LayoutGrid,
      color: r.color || "from-stone-500 to-stone-700",
      count: 0, // por ahora 0 (no hay creación de usuarios todavía)
      core: false,
      assignedTags: r.assignedTags || [],
      assignedModuleIds: r.assignedModuleIds || [],
    }));
    return [...coresWithTags, ...customs];
  }, [customRoles]);

  // === Vistas dinámicas: combinar fijas + módulos clonados ===
  // ALL_VIEWS solo incluye los módulos core (vet, grooming-ops, standard).
  // Los módulos clonados desde Manager (ej. "vet-lxabc..." llamado "Veterinaria 2")
  // se agregan aquí como toggles del grupo "CRM" para poder asignar/revocar permisos.
  // Esto permite tener un veterinario con acceso solo a "vet" y otro solo a "vet-lxabc...".
  const allViews = useMemo(() => {
    const dynamicModuleViews = (modules || [])
      .filter(m => !m.removed && !m.core) // solo no-core (los core ya están en ALL_VIEWS)
      .map(m => ({
        id: m.id,
        label: m.name || m.id,
        group: "CRM",
        // Marcamos como módulo dinámico para mostrar un badge informativo en la UI
        isDynamicModule: true,
        kind: m.kind,
      }));
    return [...ALL_VIEWS, ...dynamicModuleViews];
  }, [modules]);

  const currentPerm = permissions[selectedRole];
  const isSuper = currentPerm?.views === "*";
  const enabledViews = isSuper ? allViews.map(v => v.id) : (currentPerm?.views || []);
  // Encontrar info del rol seleccionado (para badge de sede)
  const selectedRoleInfo = roleOptions.find(r => r.id === selectedRole);

  const toggleView = (viewId) => {
    if (isSuper) return; // super tiene todo, no se edita
    const newViews = enabledViews.includes(viewId)
      ? enabledViews.filter(v => v !== viewId)
      : [...enabledViews, viewId];
    setPermissions({
      ...permissions,
      [selectedRole]: { ...currentPerm, views: newViews }
    });
    setSavedFlash(true);
    setTimeout(() => setSavedFlash(false), 1500);
  };

  const toggleFlag = (flag) => {
    setPermissions({
      ...permissions,
      [selectedRole]: { ...currentPerm, [flag]: !currentPerm[flag] }
    });
    setSavedFlash(true);
    setTimeout(() => setSavedFlash(false), 1500);
  };

  const resetRole = () => {
    // Reset a los defaults — para roles core usa DEFAULT_ROLE_PERMISSIONS,
    // para custom usa el rol base del que heredaron.
    const customRole = customRoles.find(r => r.id === selectedRole);
    if (customRole) {
      const baseDefaults = DEFAULT_ROLE_PERMISSIONS[customRole.inheritFrom] || DEFAULT_ROLE_PERMISSIONS.sales;
      setPermissions({
        ...permissions,
        [selectedRole]: { ...baseDefaults, fields: permissions[selectedRole]?.fields || {} }
      });
    } else {
      setPermissions({
        ...permissions,
        [selectedRole]: DEFAULT_ROLE_PERMISSIONS[selectedRole]
      });
    }
    setSavedFlash(true);
    setTimeout(() => setSavedFlash(false), 1500);
  };

  // Eliminar rol custom (los core no se pueden eliminar)
  // Abre el modal de confirmación. La eliminación real ocurre en confirmDeleteRole.
  const handleDeleteRole = (roleId) => {
    setConfirmDeleteId(roleId);
  };

  const confirmDeleteRole = () => {
    const roleId = confirmDeleteId;
    if (!roleId) return;
    setCustomRoles?.(prev => prev.filter(r => r.id !== roleId));
    setPermissions(prev => {
      const next = { ...prev };
      delete next[roleId];
      return next;
    });
    if (selectedRole === roleId) setSelectedRole("vet");
    setConfirmDeleteId(null);
  };

  // Actualizar etiquetas de un rol existente. Funciona tanto para roles core como custom.
  // Para los core, las etiquetas se guardan en customRoles igual (con flag isCoreOverride
  // para distinguir), permitiendo que se vean en la UI sin alterar los defaults.
  const handleUpdateRoleTags = (roleId, newTags, newModuleIds) => {
    const isCustom = (customRoles || []).some(r => r.id === roleId);
    if (isCustom) {
      setCustomRoles?.(prev => prev.map(r =>
        r.id === roleId
          ? { ...r, assignedTags: newTags, assignedModuleIds: newModuleIds }
          : r
      ));
    } else {
      // Rol core (super, vet, grooming, sales): persistir etiquetas en una entrada
      // shadow dentro de customRoles que el render combina al mostrar.
      const existing = (customRoles || []).find(r => r.id === `tags-${roleId}`);
      if (existing) {
        setCustomRoles?.(prev => prev.map(r =>
          r.id === `tags-${roleId}`
            ? { ...r, assignedTags: newTags, assignedModuleIds: newModuleIds }
            : r
        ));
      } else {
        setCustomRoles?.(prev => [...prev, {
          id: `tags-${roleId}`,
          shadowOf: roleId,
          assignedTags: newTags,
          assignedModuleIds: newModuleIds,
          isCoreOverride: true,
        }]);
      }
    }
    // Si tiene moduleIds, también extender los permisos de views para que
    // efectivamente pueda acceder a esas instancias.
    if (newModuleIds.length > 0) {
      setPermissions(prev => {
        const cur = prev[roleId];
        if (!cur) return prev;
        if (cur.views === "*") return prev; // super ya tiene todo
        const next = [...cur.views];
        newModuleIds.forEach(mid => {
          if (!next.includes(mid)) next.push(mid);
        });
        return { ...prev, [roleId]: { ...cur, views: next } };
      });
    }
    setEditingTagsRoleId(null);
  };

  // Crear nuevo rol
  const handleCreateRole = (newRole) => {
    // Generar permisos heredados del rol base
    const inheritedPerm = { ...DEFAULT_ROLE_PERMISSIONS[newRole.inheritFrom] };
    // Si el rol tiene assignedModuleIds, agregar esos a las views automáticamente
    if (newRole.assignedModuleIds && newRole.assignedModuleIds.length > 0) {
      const baseViews = inheritedPerm.views === "*" ? [] : [...inheritedPerm.views];
      newRole.assignedModuleIds.forEach(mid => {
        if (!baseViews.includes(mid)) baseViews.push(mid);
      });
      inheritedPerm.views = baseViews;
    }
    // Agregar al state de roles custom
    setCustomRoles?.(prev => [...prev, newRole]);
    // Agregar permisos al state de permissions
    setPermissions(prev => ({
      ...prev,
      [newRole.id]: { ...inheritedPerm, fields: prev[newRole.inheritFrom]?.fields || {} },
    }));
    // Seleccionar el rol recién creado
    setSelectedRole(newRole.id);
    setShowCreateRole(false);
  };

  // Agrupar vistas (incluyendo las dinámicas de módulos clonados)
  const viewsByGroup = useMemo(() => {
    const groups = {};
    allViews.forEach(v => {
      if (!groups[v.group]) groups[v.group] = [];
      groups[v.group].push(v);
    });
    return groups;
  }, [allViews]);

  return (
    <div className="space-y-5">
      {/* Hero */}
      <div className="relative p-6 rounded-2xl bg-gradient-to-br from-white via-orange-50 to-orange-100 border border-stone-200 overflow-hidden">
        <div className="flex items-center gap-4 flex-wrap">
          <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-orange-500 to-orange-700 grid place-items-center text-white shadow-lg flex-shrink-0">
            <ShieldCheck size={24} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
              Administración · Control de acceso
            </div>
            <h2 className="font-serif text-3xl font-semibold leading-tight">
              Roles <span className="italic text-orange-600">y permisos</span>
            </h2>
            <p className="text-sm text-stone-600 mt-1 max-w-2xl">
              Define qué módulos puede ver cada rol. Los cambios aplican inmediatamente al próximo inicio de sesión.
            </p>
          </div>
          {savedFlash && (
            <span className="inline-flex items-center gap-1.5 px-3 py-2 rounded-full bg-emerald-100 text-emerald-800 text-xs font-semibold">
              <Check size={13} strokeWidth={2.5} /> Cambios guardados
            </span>
          )}
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-5">
        {/* Lista de roles */}
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden w-full lg:w-80 flex-shrink-0">
          <div className="p-5 border-b border-stone-200 flex items-center justify-between gap-2">
            <div>
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Roles disponibles</div>
              <div className="font-serif text-lg font-semibold mt-0.5">{roleOptions.length} configurados</div>
            </div>
            <button
              onClick={() => setShowCreateRole(true)}
              title="Crear rol personalizado"
              className="w-9 h-9 rounded-xl bg-orange-600 hover:bg-orange-700 text-white grid place-items-center shadow-sm flex-shrink-0 transition"
            >
              <Plus size={16} strokeWidth={2.2} />
            </button>
          </div>
          <div>
            {roleOptions.map(r => {
              const Icon = r.Icon;
              const active = selectedRole === r.id;
              const rPerm = permissions[r.id];
              const accessCount = !rPerm ? 0 : (rPerm.views === "*" ? allViews.length : rPerm.views.length);
              // Resolver etiquetas libres (assignedTags) y módulos técnicos asignados.
              // Las etiquetas libres son lo que el admin escribe manualmente para
              // identificar el rol visualmente. Los módulos son el filtro técnico real.
              const assignedTags = r.assignedTags || [];
              const assignedMods = (r.assignedModuleIds || [])
                .map(mid => (modules || []).find(m => m.id === mid))
                .filter(Boolean);
              return (
                <div
                  key={r.id}
                  className={`relative border-b border-stone-200 border-l-4 transition ${
                    active ? "bg-orange-50 border-l-orange-600" : "border-l-transparent hover:bg-orange-50"
                  }`}
                >
                  <button
                    onClick={() => setSelectedRole(r.id)}
                    className="flex items-center gap-3 p-4 w-full text-left pr-16"
                  >
                    <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${r.color} grid place-items-center text-white flex-shrink-0`}>
                      <Icon size={18} strokeWidth={1.8} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <span className="font-semibold text-sm truncate">{r.label}</span>
                      </div>
                      <div className="text-xs text-stone-500 mt-0.5 truncate">{r.desc}</div>
                      {/* Etiquetas asignadas — sustituyen al badge "Custom" como identificador */}
                      {assignedTags.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-1.5">
                          {assignedTags.slice(0, 3).map(tag => (
                            <span
                              key={tag}
                              className="text-[10px] font-semibold px-1.5 py-0.5 rounded-md truncate max-w-32 bg-orange-100 text-orange-700"
                            >
                              📍 {tag}
                            </span>
                          ))}
                          {assignedTags.length > 3 && (
                            <span className="text-[10px] font-semibold px-1.5 py-0.5 rounded-md bg-stone-100 text-stone-600">
                              +{assignedTags.length - 3}
                            </span>
                          )}
                        </div>
                      )}
                      {/* Indicador si tiene filtro técnico activo (módulos asignados) */}
                      {assignedMods.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-1">
                          <span className="text-[10px] font-semibold px-1.5 py-0.5 rounded-md bg-amber-100 text-amber-800 inline-flex items-center gap-1">
                            <Filter size={9} strokeWidth={2.4} />
                            Filtro: {assignedMods.length} {assignedMods.length === 1 ? "sede" : "sedes"}
                          </span>
                        </div>
                      )}
                      <div className="flex items-center gap-2 mt-1.5">
                        <span className="text-xs font-semibold px-1.5 py-px rounded bg-stone-100 text-stone-600">
                          {accessCount} módulos
                        </span>
                        <span className="text-xs text-stone-400">·</span>
                        <span className="text-xs text-stone-500">
                          <Users size={10} className="inline mr-1" />{r.count} usuario{r.count !== 1 ? "s" : ""}
                        </span>
                      </div>
                    </div>
                  </button>
                  {/* Acciones: lápiz para editar etiquetas (todos) + eliminar (solo custom) */}
                  <div className="absolute top-3 right-3 flex gap-1">
                    <button
                      onClick={(e) => { e.stopPropagation(); setEditingTagsRoleId(r.id); }}
                      title="Editar etiquetas"
                      className="w-7 h-7 rounded-md text-stone-400 hover:text-orange-600 hover:bg-orange-50 grid place-items-center transition"
                    >
                      <Edit3 size={12} />
                    </button>
                    {!r.core && (
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDeleteRole(r.id); }}
                        title="Eliminar rol"
                        className="w-7 h-7 rounded-md text-stone-400 hover:text-red-600 hover:bg-red-50 grid place-items-center transition"
                      >
                        <Trash2 size={12} />
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Editor de permisos */}
        <div className="flex-1 min-w-0 space-y-4">
          {/* Header del rol seleccionado */}
          <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-6 flex items-center justify-between gap-4 flex-wrap">
            <div className="flex items-center gap-4">
              {(() => {
                const r = roleOptions.find(x => x.id === selectedRole);
                const Icon = r.Icon;
                return (
                  <>
                    <div className={`w-14 h-14 rounded-2xl bg-gradient-to-br ${r.color} grid place-items-center text-white shadow-lg flex-shrink-0`}>
                      <Icon size={26} strokeWidth={1.8} />
                    </div>
                    <div>
                      <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
                        Configurando rol
                      </div>
                      <h3 className="font-serif text-2xl font-semibold leading-none mt-0.5">{r.label}</h3>
                      <div className="text-sm text-stone-500 mt-1">{r.desc}</div>
                    </div>
                  </>
                );
              })()}
            </div>
            {!isSuper && (
              <button
                onClick={resetRole}
                className="flex items-center gap-2 px-3 py-2 rounded-xl bg-white border border-stone-200 hover:border-orange-400 text-stone-700 text-sm font-semibold transition"
              >
                <History size={14} /> Restaurar defecto
              </button>
            )}
          </div>

          {isSuper && (
            <div className="bg-orange-50 border border-orange-200 rounded-2xl p-4 flex gap-3">
              <ShieldCheck size={18} className="text-orange-700 flex-shrink-0 mt-0.5" />
              <div className="text-sm text-orange-900 leading-relaxed">
                <strong>Super usuario tiene acceso total a todos los módulos.</strong>
                {" "}Esta configuración no es editable por seguridad — siempre debe existir al menos un rol con acceso completo al sistema.
              </div>
            </div>
          )}

          {/* Permisos especiales */}
          <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-6">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-3">
              Permisos especiales
            </div>
            <div className="space-y-2">
              <PermToggle
                label="Crear nuevos clientes"
                description="Permite usar el botón ⌘N de la barra lateral"
                checked={!!currentPerm.canCreateClient}
                disabled={isSuper}
                onChange={() => toggleFlag("canCreateClient")}
              />
              <PermToggle
                label="Crear módulos personalizados"
                description="Permite generar nuevos CRMs estándar desde el catálogo"
                checked={!!currentPerm.canCreateModule}
                disabled={isSuper}
                onChange={() => toggleFlag("canCreateModule")}
              />
            </div>
          </div>

          {/* Matriz de vistas */}
          <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-6">
            <div className="flex items-center justify-between mb-4 flex-wrap gap-2">
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
                  Acceso a módulos
                </div>
                <h4 className="font-serif text-xl font-semibold mt-0.5">
                  Matriz de permisos por sección
                </h4>
              </div>
              <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-orange-100 text-orange-800 text-xs font-semibold">
                {enabledViews.length} de {allViews.length} habilitadas
              </span>
            </div>

            <div className="space-y-5">
              {Object.entries(viewsByGroup).map(([group, views]) => (
                <div key={group}>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2 pb-2 border-b border-stone-200">
                    {group}
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                    {views.map(v => {
                      const enabled = enabledViews.includes(v.id);
                      return (
                        <button
                          key={v.id}
                          onClick={() => toggleView(v.id)}
                          disabled={isSuper}
                          className={`flex items-center gap-3 p-3 rounded-xl border transition text-left ${
                            isSuper ? "cursor-not-allowed opacity-60" : ""
                          } ${
                            enabled
                              ? "bg-orange-50 border-orange-300"
                              : "bg-white border-stone-200 hover:border-stone-300"
                          }`}
                        >
                          <div className={`w-10 h-6 rounded-full relative transition flex-shrink-0 ${
                            enabled ? "bg-orange-600" : "bg-stone-300"
                          }`}>
                            <span className={`absolute top-1 w-4 h-4 rounded-full bg-white shadow transition ${
                              enabled ? "left-5" : "left-1"
                            }`}></span>
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className={`text-sm font-semibold flex items-center gap-1.5 ${enabled ? "text-stone-900" : "text-stone-500"}`}>
                              <span className="truncate">{v.label}</span>
                              {v.isDynamicModule && (
                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full uppercase tracking-wider flex-shrink-0 ${
                                  v.kind === "vet" ? "bg-orange-100 text-orange-700" :
                                  v.kind === "grooming" ? "bg-emerald-100 text-emerald-700" :
                                  v.kind === "standard" ? "bg-blue-100 text-blue-700" :
                                  "bg-stone-100 text-stone-700"
                                }`}>
                                  Sede
                                </span>
                              )}
                            </div>
                            <div className="text-xs text-stone-400 mt-0.5">
                              {enabled ? "Visible en la sidebar" : "Oculto"}
                            </div>
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* === SECCIÓN: Campos visibles y editables por CRM === */}
          {/* Para cada CRM en CRM_FIELD_SCHEMA mostramos sus secciones, y dentro
              cada campo con un selector "oculto / ver / editar". Cada sección tiene
              un botón para aplicar un nivel global a todos sus campos. */}
          <CRMFieldsPermissionsPanel
            role={selectedRole}
            permissions={permissions}
            setPermissions={setPermissions}
            isSuper={isSuper}
            onChange={() => {
              setSavedFlash(true);
              setTimeout(() => setSavedFlash(false), 1500);
            }}
          />
        </div>
      </div>

      {/* Modal de creación de rol custom */}
      {showCreateRole && (
        <CreateRoleModal
          modules={modules}
          customRoles={customRoles}
          onCancel={() => setShowCreateRole(false)}
          onConfirm={handleCreateRole}
        />
      )}

      {/* Modal de confirmación de eliminación */}
      {confirmDeleteId && (
        <ConfirmDeleteRoleModal
          roleLabel={roleOptions.find(r => r.id === confirmDeleteId)?.label || ""}
          onCancel={() => setConfirmDeleteId(null)}
          onConfirm={confirmDeleteRole}
        />
      )}

      {/* Modal de edición de etiquetas (para cualquier rol) */}
      {editingTagsRoleId && (
        <EditRoleTagsModal
          role={roleOptions.find(r => r.id === editingTagsRoleId)}
          modules={modules}
          customRoles={customRoles}
          onCancel={() => setEditingTagsRoleId(null)}
          onConfirm={(newTags, newModuleIds) => handleUpdateRoleTags(editingTagsRoleId, newTags, newModuleIds)}
        />
      )}
    </div>
  );
}

// ========== MODAL: Confirmar eliminación de rol ==========
function ConfirmDeleteRoleModal({ roleLabel, onCancel, onConfirm }) {
  return (
    <div onClick={onCancel} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="p-5 bg-gradient-to-br from-red-500 to-red-700 text-white flex items-center gap-3">
          <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
            <Trash2 size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">
              Eliminar rol
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5 truncate">
              {roleLabel}
            </h3>
          </div>
          <button onClick={onCancel} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
            <X size={14} />
          </button>
        </div>
        <div className="p-5 space-y-3">
          <p className="text-sm text-stone-700 leading-relaxed">
            ¿Estás seguro de eliminar este rol? Esta acción <strong>no se puede deshacer</strong>.
          </p>
          <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 text-xs text-amber-900 leading-relaxed flex items-start gap-2">
            <Info size={13} className="text-amber-700 flex-shrink-0 mt-0.5" />
            <span>
              Los usuarios que tuvieran asignado este rol quedarán sin permisos hasta que les asignes otro.
            </span>
          </div>
        </div>
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
          <button
            onClick={onCancel}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            Cancelar
          </button>
          <button
            onClick={onConfirm}
            className="flex-[2] px-3 py-2.5 rounded-xl text-sm font-semibold bg-red-600 hover:bg-red-700 text-white shadow flex items-center justify-center gap-2"
          >
            <Trash2 size={13} strokeWidth={2.4} />
            Sí, eliminar
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== MODAL: Editar etiquetas de un rol ==========
// Funciona tanto para roles core como custom. Solo edita assignedTags y assignedModuleIds.
// Para los demás campos (nombre, color, hereda de, descripción), eso queda fuera —
// los core no se pueden cambiar, y los custom se editan al recrearlos si hace falta.
function EditRoleTagsModal({ role, modules = [], customRoles = [], onCancel, onConfirm }) {
  const [assignedTags, setAssignedTags] = useState(role?.assignedTags || []);
  const [assignedModuleIds, setAssignedModuleIds] = useState(role?.assignedModuleIds || []);
  const [tagInput, setTagInput] = useState("");
  const [showTechnicalFilter, setShowTechnicalFilter] = useState(false);

  const availableModules = (modules || []).filter(m => !m.removed);

  // Mismo mapeo de etiqueta → módulos asociados que en CreateRoleModal
  const tagToModulesMap = useMemo(() => {
    const map = {};
    (customRoles || []).forEach(r => {
      if (r.id === role?.id) return; // ignorar el propio rol
      const tags = r.assignedTags || [];
      const mods = r.assignedModuleIds || [];
      tags.forEach(t => {
        if (!map[t]) map[t] = new Set();
        mods.forEach(mid => map[t].add(mid));
      });
    });
    const result = {};
    Object.entries(map).forEach(([tag, set]) => { result[tag] = [...set]; });
    return result;
  }, [customRoles, role]);

  const existingTags = useMemo(() => {
    const all = new Set();
    (customRoles || []).forEach(r => {
      if (r.id === role?.id) return;
      (r.assignedTags || []).forEach(t => all.add(t));
    });
    return [...all];
  }, [customRoles, role]);

  const tagSuggestions = useMemo(() => {
    const q = tagInput.trim().toLowerCase();
    return existingTags
      .filter(t => !assignedTags.includes(t))
      .filter(t => !q || t.toLowerCase().includes(q));
  }, [existingTags, assignedTags, tagInput]);

  const addTag = (forceTag = null) => {
    const safeForce = (typeof forceTag === "string") ? forceTag : null;
    const raw = safeForce ? safeForce.trim() : tagInput.trim().replace(/,$/, "").trim();
    if (!raw) return;
    if (raw.length > 30) return;
    if (assignedTags.includes(raw)) {
      setTagInput("");
      return;
    }
    setAssignedTags(prev => [...prev, raw]);
    setTagInput("");
    const inheritedModuleIds = tagToModulesMap[raw];
    if (inheritedModuleIds && inheritedModuleIds.length > 0) {
      setAssignedModuleIds(prev => {
        const merged = new Set([...prev, ...inheritedModuleIds]);
        return [...merged];
      });
    }
  };

  const removeTag = (tag) => {
    setAssignedTags(prev => prev.filter(t => t !== tag));
  };

  const handleTagKeyDown = (e) => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      addTag();
    } else if (e.key === "Backspace" && !tagInput && assignedTags.length > 0) {
      removeTag(assignedTags[assignedTags.length - 1]);
    }
  };

  const toggleModule = (moduleId) => {
    setAssignedModuleIds(prev =>
      prev.includes(moduleId) ? prev.filter(id => id !== moduleId) : [...prev, moduleId]
    );
  };

  if (!role) return null;
  const Ic = role.Icon || LayoutGrid;

  return (
    <div onClick={onCancel} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl overflow-hidden flex flex-col" style={{ maxHeight: "calc(100vh - 6rem)" }}>
        {/* Header */}
        <div className={`p-5 bg-gradient-to-br ${role.color} text-white flex items-center gap-3 flex-shrink-0`}>
          <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
            <Ic size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">
              Editar etiquetas del rol
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5 truncate">{role.label}</h3>
          </div>
          <button onClick={onCancel} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
            <X size={14} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-5 space-y-5">
          {/* Etiquetas */}
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-2">
              Etiquetas del rol
            </label>
            <div className="bg-stone-50 border border-stone-200 rounded-xl p-3 mb-2 text-xs text-stone-700 leading-relaxed">
              <Info size={12} className="inline mr-1 -mt-0.5 text-stone-500" />
              Identifica este rol con etiquetas (ej. <em>"Sede Norte"</em>). <kbd className="px-1 py-0.5 bg-white border border-stone-300 rounded text-[10px] font-mono">Enter</kbd> o <kbd className="px-1 py-0.5 bg-white border border-stone-300 rounded text-[10px] font-mono">,</kbd> para agregar.
            </div>
            <div className={`flex flex-wrap items-center gap-1.5 px-3 py-2.5 bg-white border-2 rounded-xl transition focus-within:border-orange-400 ${
              assignedTags.length > 0 ? "border-stone-300" : "border-stone-200"
            }`}>
              {assignedTags.map(tag => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-orange-100 text-orange-800 text-xs font-semibold"
                >
                  📍 {tag}
                  <button
                    onClick={() => removeTag(tag)}
                    type="button"
                    className="w-4 h-4 rounded-full hover:bg-orange-200 grid place-items-center text-orange-700"
                    title="Quitar etiqueta"
                  >
                    <X size={10} strokeWidth={2.5} />
                  </button>
                </span>
              ))}
              <input
                type="text"
                value={tagInput}
                onChange={(e) => setTagInput(e.target.value)}
                onKeyDown={handleTagKeyDown}
                onBlur={() => addTag()}
                placeholder={assignedTags.length === 0 ? "Escribe una etiqueta..." : ""}
                maxLength={30}
                className="flex-1 min-w-32 px-1 py-0.5 outline-none text-sm bg-transparent"
              />
            </div>

            {tagSuggestions.length > 0 && (
              <div className="mt-2.5 pt-2.5 border-t border-dashed border-stone-200">
                <div className="text-[11px] text-stone-500 mb-1.5 flex items-center gap-1.5">
                  <Sparkles size={10} className="text-orange-500" />
                  <span>Etiquetas ya creadas — click para reusar:</span>
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {tagSuggestions.map(t => {
                    const linkedMods = tagToModulesMap[t] || [];
                    return (
                      <button
                        key={t}
                        type="button"
                        onClick={() => addTag(t)}
                        className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-white border-2 border-dashed border-stone-300 hover:border-orange-400 hover:bg-orange-50 text-xs font-semibold text-stone-700 hover:text-orange-700 transition"
                      >
                        <Plus size={11} strokeWidth={2.4} />
                        📍 {t}
                        {linkedMods.length > 0 && (
                          <span className="text-[9px] font-bold uppercase tracking-wider px-1 py-px rounded bg-amber-100 text-amber-800 ml-1">
                            +filtro
                          </span>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          {/* Filtro técnico */}
          {availableModules.length > 0 && (
            <div className="border-t border-stone-200 pt-4">
              <button
                type="button"
                onClick={() => setShowTechnicalFilter(s => !s)}
                className="w-full flex items-center justify-between text-left mb-2 hover:text-orange-700 transition"
              >
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold flex items-center gap-2">
                    Filtro técnico de sedes
                    <span className="text-[10px] font-normal lowercase tracking-normal text-stone-400 italic">avanzado, opcional</span>
                  </div>
                  <div className="text-xs text-stone-500 mt-0.5">
                    {assignedModuleIds.length === 0
                      ? "Sin restricciones"
                      : `Restringido a ${assignedModuleIds.length} ${assignedModuleIds.length === 1 ? "sede" : "sedes"}`}
                  </div>
                </div>
                <ChevronRight
                  size={16}
                  strokeWidth={2}
                  className={`text-stone-400 transition-transform ${showTechnicalFilter ? "rotate-90" : ""}`}
                />
              </button>

              {showTechnicalFilter && (
                <div className="space-y-1.5">
                  {availableModules.map(m => {
                    const checked = assignedModuleIds.includes(m.id);
                    return (
                      <button
                        key={m.id}
                        type="button"
                        onClick={() => toggleModule(m.id)}
                        className={`w-full flex items-center gap-3 p-2.5 rounded-xl border-2 text-left transition ${
                          checked
                            ? "border-orange-300 bg-orange-50"
                            : "border-stone-200 bg-white hover:border-stone-300"
                        }`}
                      >
                        <div className={`w-5 h-5 rounded-md flex-shrink-0 grid place-items-center ${
                          checked ? "bg-orange-600" : "border-2 border-stone-300"
                        }`}>
                          {checked && <Check size={11} className="text-white" strokeWidth={3} />}
                        </div>
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wider flex-shrink-0 ${
                          m.kind === "vet" ? "bg-orange-100 text-orange-700" :
                          m.kind === "grooming" ? "bg-emerald-100 text-emerald-700" :
                          m.kind === "standard" ? "bg-blue-100 text-blue-700" :
                          "bg-stone-100 text-stone-700"
                        }`}>
                          {m.kind}
                        </span>
                        <span className={`text-sm font-semibold flex-1 truncate ${checked ? "text-orange-900" : "text-stone-700"}`}>
                          {m.name}
                        </span>
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2 flex-shrink-0">
          <button
            onClick={onCancel}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            Cancelar
          </button>
          <button
            onClick={() => onConfirm(assignedTags, assignedModuleIds)}
            className="flex-[2] px-3 py-2.5 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white shadow flex items-center justify-center gap-2"
          >
            <Check size={13} strokeWidth={2.4} />
            Guardar etiquetas
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== UsersView: Gestión de cuentas del equipo ==========
// Vista para crear, editar y desactivar usuarios. Cada usuario tiene email, nombre,
// iniciales y un rol asignado (puede ser core o custom). Los usuarios se persisten
// en state local — en una versión real esto sería contra un backend de auth.
//
// Por ahora, el state es local a la vista (no global), porque el sistema sigue
// usando ACCOUNTS para el login. Cuando se agregue persistencia real, este state
// pasa a ser global y ACCOUNTS se vuelve solo el seed.
function UsersView({ users = [], setUsers, permissions = {}, customRoles = [], modules = [] }) {
  // Los usuarios vienen del state global (CricketApp) — sobreviven al cambio de vista
  // y al logout. ACCOUNTS solo se usa como seed inicial allá arriba.

  const [showCreate, setShowCreate] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [filterRole, setFilterRole] = useState("all"); // "all" | <roleId>

  // Lista combinada de roles (core + custom) para el selector
  const allRoles = useMemo(() => {
    const core = [
      { id: "super",    label: "Super usuario", color: "from-orange-500 to-orange-700" },
      { id: "vet",      label: "Veterinario",   color: "from-blue-500 to-blue-700" },
      { id: "grooming", label: "Groomer",       color: "from-emerald-500 to-emerald-700" },
      { id: "sales",    label: "Ventas",        color: "from-amber-500 to-amber-700" },
    ];
    const customs = (customRoles || [])
      .filter(r => !r.isCoreOverride)
      .map(r => ({ id: r.id, label: r.label, color: r.color, assignedTags: r.assignedTags || [] }));
    return [...core, ...customs];
  }, [customRoles]);

  // Resolver datos del rol asignado (label, color, etiquetas)
  const resolveRole = (roleId) => allRoles.find(r => r.id === roleId);

  // Filtrar usuarios según búsqueda y filtro de rol
  const filteredUsers = useMemo(() => {
    let list = users;
    if (filterRole !== "all") list = list.filter(u => u.role === filterRole);
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      list = list.filter(u =>
        u.name.toLowerCase().includes(q) ||
        u.email.toLowerCase().includes(q)
      );
    }
    return list;
  }, [users, searchQuery, filterRole]);

  // Crear o actualizar usuario
  const handleSaveUser = (userData) => {
    if (editingUser) {
      setUsers(prev => prev.map(u => u.id === editingUser.id ? { ...u, ...userData } : u));
    } else {
      const role = resolveRole(userData.role);
      const newUser = {
        id: `usr-${Date.now().toString(36)}`,
        ...userData,
        roleLabel: role?.label || "Sin rol",
        initials: userData.name.split(" ").map(p => p[0]).join("").slice(0, 2).toUpperCase(),
        active: true,
        createdAt: new Date().toISOString(),
      };
      setUsers(prev => [...prev, newUser]);
    }
    setShowCreate(false);
    setEditingUser(null);
  };

  // Toggle activo/inactivo
  const toggleActive = (userId) => {
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, active: !u.active } : u));
  };

  const handleDelete = () => {
    if (!confirmDeleteId) return;
    setUsers(prev => prev.filter(u => u.id !== confirmDeleteId));
    setConfirmDeleteId(null);
  };

  // Stats
  const stats = useMemo(() => ({
    total: users.length,
    active: users.filter(u => u.active).length,
    inactive: users.filter(u => !u.active).length,
  }), [users]);

  return (
    <div className="space-y-5">
      {/* Hero */}
      <div className="relative p-6 rounded-2xl bg-gradient-to-br from-white via-amber-50 to-orange-100 border border-stone-200 overflow-hidden">
        <div className="flex items-center gap-4 flex-wrap">
          <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-amber-500 to-orange-600 grid place-items-center text-white shadow-lg flex-shrink-0">
            <UserPlus size={24} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-amber-700 font-semibold mb-1">
              Equipo · Cuentas
            </div>
            <h2 className="font-serif text-2xl font-semibold leading-tight">
              <span className="text-amber-700">{stats.total}</span> usuarios registrados
            </h2>
            <p className="text-xs text-stone-500 mt-1">
              {stats.active} activos · {stats.inactive} inactivos
            </p>
          </div>
          <button
            onClick={() => { setEditingUser(null); setShowCreate(true); }}
            className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-amber-600 hover:bg-amber-700 text-white font-semibold text-sm shadow"
          >
            <Plus size={16} strokeWidth={2.4} />
            Crear usuario
          </button>
        </div>
      </div>

      {/* Filtros */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-3 flex items-center gap-3 flex-wrap">
        <div className="flex-1 min-w-48 relative">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Buscar por nombre o email..."
            className="w-full pl-9 pr-3 py-2 rounded-xl border border-stone-200 outline-none focus:border-orange-400 text-sm"
          />
        </div>
        <div className="flex items-center gap-1.5 flex-wrap">
          <button
            onClick={() => setFilterRole("all")}
            className={`text-xs font-semibold px-3 py-1.5 rounded-lg transition ${
              filterRole === "all"
                ? "bg-stone-900 text-white"
                : "bg-stone-100 text-stone-700 hover:bg-stone-200"
            }`}
          >
            Todos ({users.length})
          </button>
          {allRoles.map(r => {
            const count = users.filter(u => u.role === r.id).length;
            if (count === 0) return null;
            return (
              <button
                key={r.id}
                onClick={() => setFilterRole(r.id)}
                className={`text-xs font-semibold px-3 py-1.5 rounded-lg transition ${
                  filterRole === r.id
                    ? `bg-gradient-to-br ${r.color} text-white shadow`
                    : "bg-white border border-stone-200 text-stone-700 hover:border-stone-400"
                }`}
              >
                {r.label} ({count})
              </button>
            );
          })}
        </div>
      </div>

      {/* Tabla de usuarios */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        {filteredUsers.length === 0 ? (
          <div className="p-10 text-center">
            <UserPlus size={28} className="text-stone-400 mx-auto mb-3" />
            <h3 className="font-serif text-lg font-semibold mb-1">Sin usuarios encontrados</h3>
            <p className="text-sm text-stone-500">
              {searchQuery || filterRole !== "all"
                ? "Ajusta los filtros o borra la búsqueda."
                : "Crea el primer usuario del equipo."}
            </p>
          </div>
        ) : (
          <div>
            {/* Header */}
            <div className="hidden md:grid grid-cols-[auto_1fr_auto_auto_auto] gap-4 px-5 py-3 border-b border-stone-200 bg-stone-50 text-xs tracking-wider uppercase text-stone-500 font-semibold">
              <div className="w-10"></div>
              <div>Usuario</div>
              <div>Rol</div>
              <div>Estado</div>
              <div className="w-20 text-right">Acciones</div>
            </div>
            {filteredUsers.map(u => {
              const role = resolveRole(u.role);
              return (
                <div
                  key={u.id}
                  className="grid grid-cols-[auto_1fr_auto] md:grid-cols-[auto_1fr_auto_auto_auto] gap-4 px-5 py-3 border-b border-stone-200 last:border-b-0 items-center hover:bg-stone-50 transition"
                >
                  {/* Avatar */}
                  <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${role?.color || "from-stone-400 to-stone-600"} grid place-items-center text-white text-sm font-bold flex-shrink-0 ${u.active ? "" : "opacity-40 grayscale"}`}>
                    {u.initials}
                  </div>
                  {/* Datos */}
                  <div className="min-w-0">
                    <div className={`font-semibold text-sm truncate ${u.active ? "text-stone-900" : "text-stone-500"}`}>
                      {u.name}
                    </div>
                    <div className="text-xs text-stone-500 truncate">{u.email}</div>
                  </div>
                  {/* Rol con etiquetas */}
                  <div className="min-w-0 hidden md:block">
                    <div className={`text-xs font-semibold px-2 py-1 rounded-md inline-block ${
                      role
                        ? `bg-gradient-to-br ${role.color} text-white`
                        : "bg-stone-100 text-stone-500"
                    }`}>
                      {role?.label || "Sin rol"}
                    </div>
                    {role?.assignedTags?.length > 0 && (
                      <div className="flex flex-wrap gap-1 mt-1">
                        {role.assignedTags.slice(0, 2).map(t => (
                          <span key={t} className="text-[10px] font-semibold px-1.5 py-0.5 rounded-md bg-orange-100 text-orange-700">
                            📍 {t}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                  {/* Toggle activo */}
                  <div className="hidden md:block">
                    <button
                      onClick={() => toggleActive(u.id)}
                      title={u.active ? "Desactivar usuario" : "Activar usuario"}
                      className={`w-10 h-6 rounded-full relative transition ${
                        u.active ? "bg-emerald-500" : "bg-stone-300"
                      }`}
                    >
                      <span className={`absolute top-1 w-4 h-4 rounded-full bg-white shadow transition ${
                        u.active ? "left-5" : "left-1"
                      }`}></span>
                    </button>
                  </div>
                  {/* Acciones */}
                  <div className="flex items-center gap-1 justify-end">
                    <button
                      onClick={() => { setEditingUser(u); setShowCreate(true); }}
                      title="Editar usuario"
                      className="w-8 h-8 rounded-md text-stone-400 hover:text-orange-600 hover:bg-orange-50 grid place-items-center transition"
                    >
                      <Edit3 size={13} />
                    </button>
                    <button
                      onClick={() => setConfirmDeleteId(u.id)}
                      title="Eliminar usuario"
                      className="w-8 h-8 rounded-md text-stone-400 hover:text-red-600 hover:bg-red-50 grid place-items-center transition"
                    >
                      <Trash2 size={13} />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Modal crear / editar usuario */}
      {showCreate && (
        <UserFormModal
          user={editingUser}
          allRoles={allRoles}
          onCancel={() => { setShowCreate(false); setEditingUser(null); }}
          onConfirm={handleSaveUser}
        />
      )}

      {/* Modal confirmación eliminar */}
      {confirmDeleteId && (
        <div onClick={() => setConfirmDeleteId(null)} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-center p-4">
          <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
            <div className="p-5 bg-gradient-to-br from-red-500 to-red-700 text-white flex items-center gap-3">
              <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
                <Trash2 size={20} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">
                  Eliminar usuario
                </div>
                <h3 className="font-serif text-xl font-semibold mt-0.5 truncate">
                  {users.find(u => u.id === confirmDeleteId)?.name}
                </h3>
              </div>
              <button onClick={() => setConfirmDeleteId(null)} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
                <X size={14} />
              </button>
            </div>
            <div className="p-5 space-y-3">
              <p className="text-sm text-stone-700 leading-relaxed">
                ¿Estás seguro de eliminar este usuario? Esta acción <strong>no se puede deshacer</strong>.
              </p>
              <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 text-xs text-amber-900 leading-relaxed flex items-start gap-2">
                <Info size={13} className="text-amber-700 flex-shrink-0 mt-0.5" />
                <span>
                  El usuario perderá acceso inmediatamente. Si solo quieres pausarlo temporalmente, mejor usa el toggle de activo.
                </span>
              </div>
            </div>
            <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
              <button
                onClick={() => setConfirmDeleteId(null)}
                className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
              >
                Cancelar
              </button>
              <button
                onClick={handleDelete}
                className="flex-[2] px-3 py-2.5 rounded-xl text-sm font-semibold bg-red-600 hover:bg-red-700 text-white shadow flex items-center justify-center gap-2"
              >
                <Trash2 size={13} strokeWidth={2.4} />
                Sí, eliminar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ========== MODAL: Crear / Editar usuario ==========
function UserFormModal({ user = null, allRoles = [], onCancel, onConfirm }) {
  const isEdit = !!user;
  const [name, setName] = useState(user?.name || "");
  const [email, setEmail] = useState(user?.email || "");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState(user?.role || allRoles[0]?.id || "vet");

  const valid = name.trim().length >= 2 && email.includes("@") && (isEdit || password.length >= 4);

  const selectedRole = allRoles.find(r => r.id === role);

  const handleConfirm = () => {
    if (!valid) return;
    onConfirm({
      name: name.trim(),
      email: email.trim().toLowerCase(),
      ...(password ? { password } : {}),
      role,
      roleLabel: selectedRole?.label || "Sin rol",
    });
  };

  return (
    <div onClick={onCancel} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col" style={{ maxHeight: "calc(100vh - 6rem)" }}>
        {/* Header */}
        <div className="p-5 bg-gradient-to-br from-amber-500 to-orange-600 text-white flex items-center gap-3 flex-shrink-0">
          <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
            <UserPlus size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">
              {isEdit ? "Editar usuario" : "Nuevo usuario"}
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5 truncate">
              {name || "Sin nombre"}
            </h3>
          </div>
          <button onClick={onCancel} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
            <X size={14} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Nombre completo <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              autoFocus
              placeholder="Ej: Dr. Pedro García"
              className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition"
            />
          </div>

          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="usuario@cricket.vet"
              className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition"
            />
          </div>

          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Contraseña {isEdit ? "" : <span className="text-red-500">*</span>}
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder={isEdit ? "Dejar en blanco para no cambiar" : "Mínimo 4 caracteres"}
              className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition"
            />
            {isEdit && (
              <div className="text-xs text-stone-500 mt-1.5">
                Solo escribe aquí si quieres cambiar la contraseña actual
              </div>
            )}
          </div>

          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-2">
              Rol asignado
            </label>
            <div className="space-y-1.5">
              {allRoles.map(r => (
                <button
                  key={r.id}
                  type="button"
                  onClick={() => setRole(r.id)}
                  className={`w-full flex items-center gap-3 p-3 rounded-xl border-2 text-left transition ${
                    role === r.id
                      ? "border-orange-300 bg-orange-50"
                      : "border-stone-200 bg-white hover:border-stone-300"
                  }`}
                >
                  <div className={`w-5 h-5 rounded-full mt-0.5 flex-shrink-0 grid place-items-center ${
                    role === r.id ? "bg-orange-600" : "bg-stone-200"
                  }`}>
                    {role === r.id && <Check size={11} className="text-white" strokeWidth={3} />}
                  </div>
                  <div className={`text-xs font-bold px-2 py-1 rounded-md bg-gradient-to-br ${r.color} text-white flex-shrink-0`}>
                    {r.label}
                  </div>
                  {r.assignedTags?.length > 0 && (
                    <div className="flex flex-wrap gap-1 flex-1 min-w-0">
                      {r.assignedTags.slice(0, 2).map(t => (
                        <span key={t} className="text-[10px] font-semibold px-1.5 py-0.5 rounded-md bg-orange-100 text-orange-700 truncate">
                          📍 {t}
                        </span>
                      ))}
                    </div>
                  )}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2 flex-shrink-0">
          <button
            onClick={onCancel}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            Cancelar
          </button>
          <button
            onClick={handleConfirm}
            disabled={!valid}
            className={`flex-[2] px-3 py-2.5 rounded-xl text-sm font-semibold transition shadow flex items-center justify-center gap-2 ${
              valid
                ? "bg-amber-600 hover:bg-amber-700 text-white"
                : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Check size={13} strokeWidth={2.4} />
            {isEdit ? "Guardar cambios" : "Crear usuario"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== MODAL: Crear rol personalizado ==========
// Permite al admin crear roles adicionales a los 4 core. Útil sobre todo para multi-sede:
// "Veterinario Sede Norte", "Vendedor Sede Sur", etc. Cada rol custom se basa en uno
// existente (vet/grooming/sales) y opcionalmente queda asignado a sedes específicas.
function CreateRoleModal({ modules = [], customRoles = [], onCancel, onConfirm }) {
  const [name, setName] = useState("");
  const [desc, setDesc] = useState("");
  const [inheritFrom, setInheritFrom] = useState("vet");
  const [color, setColor] = useState("from-rose-500 to-rose-700");
  const [assignedModuleIds, setAssignedModuleIds] = useState([]);
  // Etiquetas libres — útiles para identificar visualmente el rol (ej. "Sede Norte",
  // "Turno Mañana"). NO afectan permisos ni filtros — son puramente descriptivas.
  // Para que el filtro de facturas opere automáticamente, los assignedModuleIds
  // (sección "Filtro técnico" abajo) son los que importan.
  const [assignedTags, setAssignedTags] = useState([]);
  const [tagInput, setTagInput] = useState("");
  // Toggle para expandir la sección técnica (oculta por defecto, lo común es solo tags)
  const [showTechnicalFilter, setShowTechnicalFilter] = useState(false);

  const COLORS = [
    { id: "from-rose-500 to-rose-700",       label: "Rosa",     swatch: "bg-rose-500" },
    { id: "from-violet-500 to-violet-700",   label: "Violeta",  swatch: "bg-violet-500" },
    { id: "from-cyan-500 to-cyan-700",       label: "Cian",     swatch: "bg-cyan-500" },
    { id: "from-teal-500 to-teal-700",       label: "Teal",     swatch: "bg-teal-500" },
    { id: "from-fuchsia-500 to-fuchsia-700", label: "Fucsia",   swatch: "bg-fuchsia-500" },
    { id: "from-stone-600 to-stone-800",     label: "Piedra",   swatch: "bg-stone-700" },
  ];

  const INHERIT_OPTIONS = [
    { id: "vet",      label: "Veterinario",   desc: "Acceso a clínica, pasaportes, mensajes y clientes" },
    { id: "grooming", label: "Groomer",       desc: "Acceso a atención grooming, mensajes y clientes" },
    { id: "sales",    label: "Vendedor",      desc: "Acceso a ventas, catálogo, inventario y clientes" },
  ];

  // Módulos disponibles para asignar (solo no-core, por convención)
  const availableModules = (modules || []).filter(m => !m.removed);

  const valid = name.trim().length >= 2;

  const handleConfirm = () => {
    if (!valid) return;
    const newRole = {
      id: `custom-${Date.now().toString(36)}`,
      label: name.trim(),
      desc: desc.trim() || `Rol personalizado heredado de ${INHERIT_OPTIONS.find(o => o.id === inheritFrom)?.label}`,
      color,
      inheritFrom,
      assignedModuleIds,
      assignedTags,
      createdAt: new Date().toISOString(),
    };
    onConfirm(newRole);
  };

  const toggleModule = (moduleId) => {
    setAssignedModuleIds(prev =>
      prev.includes(moduleId)
        ? prev.filter(id => id !== moduleId)
        : [...prev, moduleId]
    );
  };

  // === Mapeo de etiquetas existentes → moduleIds asociados ===
  // Cuando varios roles comparten etiqueta (ej. 3 roles con "Sede Norte"), todos
  // suelen apuntar al mismo módulo técnico. Aprovechamos eso: si el admin escribe
  // una etiqueta que YA existe en otro rol con moduleIds, automáticamente esos
  // moduleIds se heredan al rol nuevo. Así la etiqueta se convierte en un filtro
  // real sin tener que volver a configurar la sección técnica.
  const tagToModulesMap = useMemo(() => {
    const map = {};
    (customRoles || []).forEach(role => {
      const tags = role.assignedTags || [];
      const mods = role.assignedModuleIds || [];
      tags.forEach(t => {
        if (!map[t]) map[t] = new Set();
        mods.forEach(mid => map[t].add(mid));
      });
    });
    // Convertir Sets a arrays
    const result = {};
    Object.entries(map).forEach(([tag, set]) => { result[tag] = [...set]; });
    return result;
  }, [customRoles]);

  // Lista de etiquetas únicas existentes en otros roles (para sugerencias).
  // Se filtran las que ya tiene este rol en construcción y las que no matchean
  // con lo que el usuario está escribiendo (autocompletar).
  const existingTags = useMemo(() => {
    const all = new Set();
    (customRoles || []).forEach(role => {
      (role.assignedTags || []).forEach(t => all.add(t));
    });
    return [...all];
  }, [customRoles]);

  // Sugerencias filtradas: quitar las ya seleccionadas y filtrar por lo escrito
  const tagSuggestions = useMemo(() => {
    const q = tagInput.trim().toLowerCase();
    return existingTags
      .filter(t => !assignedTags.includes(t))
      .filter(t => !q || t.toLowerCase().includes(q));
  }, [existingTags, assignedTags, tagInput]);

  // Agregar una etiqueta nueva (Enter o coma). Limpia espacios y evita duplicados.
  // Si la etiqueta existe en otros roles con moduleIds, esos se heredan también.
  // forceTag debe ser un string. Si llega un evento (caso de onBlur sin wrapper),
  // lo ignoramos defensivamente y caemos al input.
  const addTag = (forceTag = null) => {
    const safeForce = (typeof forceTag === "string") ? forceTag : null;
    const raw = safeForce ? safeForce.trim() : tagInput.trim().replace(/,$/, "").trim();
    if (!raw) return;
    if (raw.length > 30) return;
    if (assignedTags.includes(raw)) {
      setTagInput("");
      return;
    }
    setAssignedTags(prev => [...prev, raw]);
    setTagInput("");

    // Si esta etiqueta ya estaba asociada a moduleIds en otros roles, heredarlos.
    // Esto convierte la etiqueta en un filtro real automáticamente.
    const inheritedModuleIds = tagToModulesMap[raw];
    if (inheritedModuleIds && inheritedModuleIds.length > 0) {
      setAssignedModuleIds(prev => {
        const merged = new Set([...prev, ...inheritedModuleIds]);
        return [...merged];
      });
    }
  };

  const removeTag = (tag) => {
    setAssignedTags(prev => prev.filter(t => t !== tag));
    // No quitamos los moduleIds asociados — el admin puede gestionarlos manualmente
    // en la sección técnica si quiere desligarlos.
  };

  const handleTagKeyDown = (e) => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      addTag();
    } else if (e.key === "Backspace" && !tagInput && assignedTags.length > 0) {
      // Backspace en input vacío borra la última etiqueta
      removeTag(assignedTags[assignedTags.length - 1]);
    }
  };

  return (
    <div onClick={onCancel} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl overflow-hidden flex flex-col" style={{ maxHeight: "calc(100vh - 6rem)" }}>
        {/* Header */}
        <div className={`p-5 bg-gradient-to-br ${color} text-white flex items-center gap-3 flex-shrink-0 transition-colors`}>
          <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
            <ShieldCheck size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">
              Nuevo rol personalizado
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5 truncate">
              {name || "Sin nombre"}
            </h3>
          </div>
          <button onClick={onCancel} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
            <X size={14} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-5 space-y-5">
          {/* Identidad */}
          <div className="space-y-3">
            <div>
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
                Nombre del rol <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                autoFocus
                placeholder="Ej: Veterinario Sede Norte"
                className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition"
              />
            </div>
            <div>
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
                Descripción
              </label>
              <input
                type="text"
                value={desc}
                onChange={(e) => setDesc(e.target.value)}
                placeholder="Ej: Solo atiende pacientes de la sede Norte"
                className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition"
              />
            </div>
          </div>

          {/* Color */}
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-2">
              Color del badge
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => (
                <button
                  key={c.id}
                  onClick={() => setColor(c.id)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-xl border-2 transition ${
                    color === c.id ? "border-stone-900 bg-stone-50" : "border-stone-200 hover:border-stone-300"
                  }`}
                  title={c.label}
                >
                  <div className={`w-5 h-5 rounded-md ${c.swatch}`}></div>
                  <span className="text-xs font-semibold">{c.label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Heredar permisos */}
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-2">
              Heredar permisos base de
            </label>
            <div className="space-y-1.5">
              {INHERIT_OPTIONS.map(opt => (
                <button
                  key={opt.id}
                  onClick={() => setInheritFrom(opt.id)}
                  className={`w-full flex items-start gap-3 p-3 rounded-xl border-2 text-left transition ${
                    inheritFrom === opt.id
                      ? "border-orange-300 bg-orange-50"
                      : "border-stone-200 bg-white hover:border-stone-300"
                  }`}
                >
                  <div className={`w-5 h-5 rounded-full mt-0.5 flex-shrink-0 grid place-items-center ${
                    inheritFrom === opt.id ? "bg-orange-600" : "bg-stone-200"
                  }`}>
                    {inheritFrom === opt.id && <Check size={11} className="text-white" strokeWidth={3} />}
                  </div>
                  <div>
                    <div className={`text-sm font-semibold ${inheritFrom === opt.id ? "text-orange-900" : "text-stone-700"}`}>
                      {opt.label}
                    </div>
                    <div className="text-xs text-stone-500 mt-0.5">{opt.desc}</div>
                  </div>
                </button>
              ))}
            </div>
            <div className="text-xs text-stone-500 mt-1.5 italic">
              Los permisos del rol base se copian al crear. Después puedes ajustarlos en la matriz.
            </div>
          </div>

          {/* === Etiquetas (tags libres) === */}
          {/* Etiquetas descriptivas que el admin escribe libremente. Útiles para
              identificar visualmente el rol en la lista (ej. "Sede Norte"). */}
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-2">
              Etiquetas del rol (opcional)
            </label>
            <div className="bg-stone-50 border border-stone-200 rounded-xl p-3 mb-2 text-xs text-stone-700 leading-relaxed">
              <Info size={12} className="inline mr-1 -mt-0.5 text-stone-500" />
              Escribe libremente etiquetas para identificar el rol (ej. <em>"Sede Norte"</em>, <em>"Turno Mañana"</em>). Presiona <kbd className="px-1 py-0.5 bg-white border border-stone-300 rounded text-[10px] font-mono">Enter</kbd> o <kbd className="px-1 py-0.5 bg-white border border-stone-300 rounded text-[10px] font-mono">,</kbd> para agregar.
            </div>
            <div className={`flex flex-wrap items-center gap-1.5 px-3 py-2.5 bg-white border-2 rounded-xl transition focus-within:border-orange-400 ${
              assignedTags.length > 0 ? "border-stone-300" : "border-stone-200"
            }`}>
              {assignedTags.map(tag => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-orange-100 text-orange-800 text-xs font-semibold"
                >
                  📍 {tag}
                  <button
                    onClick={() => removeTag(tag)}
                    type="button"
                    className="w-4 h-4 rounded-full hover:bg-orange-200 grid place-items-center text-orange-700"
                    title="Quitar etiqueta"
                  >
                    <X size={10} strokeWidth={2.5} />
                  </button>
                </span>
              ))}
              <input
                type="text"
                value={tagInput}
                onChange={(e) => setTagInput(e.target.value)}
                onKeyDown={handleTagKeyDown}
                onBlur={() => addTag()}
                placeholder={assignedTags.length === 0 ? "Escribe una etiqueta..." : ""}
                maxLength={30}
                className="flex-1 min-w-32 px-1 py-0.5 outline-none text-sm bg-transparent"
              />
            </div>
            {assignedTags.length > 0 && (
              <div className="text-xs text-stone-500 mt-1.5">
                {assignedTags.length} {assignedTags.length === 1 ? "etiqueta agregada" : "etiquetas agregadas"}
              </div>
            )}

            {/* === Sugerencias de etiquetas ya creadas === */}
            {/* Cuando el admin ha creado roles antes con etiquetas, las mostramos
                aquí como pills clickables. Evita reescribir nombres y mantiene
                consistencia. Click en una pill la agrega — y si esa etiqueta
                tiene moduleIds asociados en otros roles, se heredan también. */}
            {tagSuggestions.length > 0 && (
              <div className="mt-2.5 pt-2.5 border-t border-dashed border-stone-200">
                <div className="text-[11px] text-stone-500 mb-1.5 flex items-center gap-1.5">
                  <Sparkles size={10} className="text-orange-500" />
                  <span>Etiquetas ya creadas — click para reusar:</span>
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {tagSuggestions.map(t => {
                    const linkedMods = tagToModulesMap[t] || [];
                    return (
                      <button
                        key={t}
                        type="button"
                        onClick={() => addTag(t)}
                        title={
                          linkedMods.length > 0
                            ? `Al agregar también heredas ${linkedMods.length} ${linkedMods.length === 1 ? "sede técnica" : "sedes técnicas"} asociadas`
                            : "Agregar etiqueta"
                        }
                        className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-white border-2 border-dashed border-stone-300 hover:border-orange-400 hover:bg-orange-50 text-xs font-semibold text-stone-700 hover:text-orange-700 transition"
                      >
                        <Plus size={11} strokeWidth={2.4} />
                        📍 {t}
                        {linkedMods.length > 0 && (
                          <span className="text-[9px] font-bold uppercase tracking-wider px-1 py-px rounded bg-amber-100 text-amber-800 ml-1">
                            +filtro
                          </span>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          {/* === Filtro técnico (módulos) === */}
          {/* Sección secundaria, colapsada por defecto. Para que el filtro de facturas
              en SalesView se aplique automáticamente, hay que asignar los módulos
              técnicos. Las etiquetas de arriba son solo visuales. */}
          {availableModules.length > 0 && (
            <div className="border-t border-stone-200 pt-4">
              <button
                type="button"
                onClick={() => setShowTechnicalFilter(s => !s)}
                className="w-full flex items-center justify-between text-left mb-2 hover:text-orange-700 transition"
              >
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold flex items-center gap-2">
                    Filtro técnico de sedes
                    <span className="text-[10px] font-normal lowercase tracking-normal text-stone-400 italic">avanzado, opcional</span>
                  </div>
                  <div className="text-xs text-stone-500 mt-0.5">
                    {assignedModuleIds.length === 0
                      ? "Sin restricciones — el rol verá todas las facturas según sus permisos"
                      : `Restringido a ${assignedModuleIds.length} ${assignedModuleIds.length === 1 ? "sede" : "sedes"}`}
                  </div>
                </div>
                <ChevronRight
                  size={16}
                  strokeWidth={2}
                  className={`text-stone-400 transition-transform ${showTechnicalFilter ? "rotate-90" : ""}`}
                />
              </button>

              {showTechnicalFilter && (
                <>
                  <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 mb-2 text-xs text-amber-900 leading-relaxed">
                    <Info size={12} className="inline mr-1 -mt-0.5 text-amber-700" />
                    <strong>Solo si necesitas restringir facturas.</strong> Si seleccionas sedes aquí, el rol solo verá <em>facturas y pestañas</em> de esas instancias en SalesView. Si lo dejas vacío, las etiquetas de arriba siguen sirviendo como descripción visual.
                  </div>
                  <div className="space-y-1.5">
                    {availableModules.map(m => {
                      const checked = assignedModuleIds.includes(m.id);
                      return (
                        <button
                          key={m.id}
                          type="button"
                          onClick={() => toggleModule(m.id)}
                          className={`w-full flex items-center gap-3 p-2.5 rounded-xl border-2 text-left transition ${
                            checked
                              ? "border-orange-300 bg-orange-50"
                              : "border-stone-200 bg-white hover:border-stone-300"
                          }`}
                        >
                          <div className={`w-5 h-5 rounded-md flex-shrink-0 grid place-items-center ${
                            checked ? "bg-orange-600" : "border-2 border-stone-300"
                          }`}>
                            {checked && <Check size={11} className="text-white" strokeWidth={3} />}
                          </div>
                          <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wider flex-shrink-0 ${
                            m.kind === "vet" ? "bg-orange-100 text-orange-700" :
                            m.kind === "grooming" ? "bg-emerald-100 text-emerald-700" :
                            m.kind === "standard" ? "bg-blue-100 text-blue-700" :
                            "bg-stone-100 text-stone-700"
                          }`}>
                            {m.kind}
                          </span>
                          <span className={`text-sm font-semibold flex-1 truncate ${checked ? "text-orange-900" : "text-stone-700"}`}>
                            {m.name}
                          </span>
                        </button>
                      );
                    })}
                  </div>
                </>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2 flex-shrink-0">
          <button
            onClick={onCancel}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            Cancelar
          </button>
          <button
            onClick={handleConfirm}
            disabled={!valid}
            className={`flex-[2] px-3 py-2.5 rounded-xl text-sm font-semibold transition shadow ${
              valid
                ? "bg-orange-600 hover:bg-orange-700 text-white"
                : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Check size={13} className="inline mr-1" strokeWidth={2.5} />
            Crear rol
          </button>
        </div>
      </div>
    </div>
  );
}

function PermToggle({ label, description, checked, disabled, onChange }) {
  return (
    <button
      onClick={onChange}
      disabled={disabled}
      className={`flex items-center gap-3 p-3 rounded-xl border w-full text-left transition ${
        disabled ? "cursor-not-allowed opacity-60" : ""
      } ${
        checked ? "bg-orange-50 border-orange-300" : "bg-white border-stone-200 hover:border-stone-300"
      }`}
    >
      <div className={`w-10 h-6 rounded-full relative transition flex-shrink-0 ${
        checked ? "bg-orange-600" : "bg-stone-300"
      }`}>
        <span className={`absolute top-1 w-4 h-4 rounded-full bg-white shadow transition ${
          checked ? "left-5" : "left-1"
        }`}></span>
      </div>
      <div className="flex-1 min-w-0">
        <div className="text-sm font-semibold text-stone-900">{label}</div>
        <div className="text-xs text-stone-500 mt-0.5">{description}</div>
      </div>
    </button>
  );
}

// ========== VISTA: CLIENTES ==========

// ========== VISTA: CLIENTES (con drawer de detalle) ==========

function ClientsView({
  clients, passports, setPassports, invoices, conversations,
  canCreate, onNewClient, onOpenPassport, onOpenSales, onMessageClient,
  onCompleteRegistration, userRole = "super", permissions = {},
  petUpdates = [], setPetUpdates, userName,
  initialTab = null, onTabConsumed,
}) {
  // Tab principal de la vista: "directory" (la grilla de clientes) | "updates" (cola de propuestas)
  const [mainTab, setMainTab] = useState(initialTab || "directory");
  // Si se navegó con un initialTab pendiente (ej. desde "passport-updates" legacy),
  // lo aplicamos una vez y notificamos al padre para que limpie el state.
  useEffect(() => {
    if (initialTab && initialTab !== mainTab) {
      setMainTab(initialTab);
      onTabConsumed && onTabConsumed();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialTab]);
  const pendingUpdatesCount = (petUpdates || []).filter(u => u.status === "pending").length;

  // Helpers de permisos por campo del CRM "clients".
  // showField devuelve si el campo es visible (level !== "hidden").
  // Si no hay permisos configurados, usa los defaults del schema.
  const showField = (sectionId, fieldId) =>
    getFieldLevel(permissions, userRole, "clients", sectionId, fieldId) !== "hidden";
  const canEditField = (sectionId, fieldId) =>
    getFieldLevel(permissions, userRole, "clients", sectionId, fieldId) === "edit";
  // Atajos para evitar repetir literales en el render
  const showTutorInfo = ["name","cedula","phone","email","address","segment","spending"].some(f => showField("tutor", f));
  const showAnyTutorContact = ["cedula","phone","email","address"].some(f => showField("tutor", f));
  const showBilling = ["invoices","balance","plans","create"].some(f => showField("billing", f));
  const showMessaging = showField("messaging", "chat-read");

  const [searchQuery, setSearchQuery] = useState("");
  const [segmentFilter, setSegmentFilter] = useState("all");
  const [drawerClientId, setDrawerClientId] = useState(null);
  const [activeSubTab, setActiveSubTab] = useState("all"); // all | debtors
  // Categorías visibles del historial — administrable
  const [visibleCategories, setVisibleCategories] = useState(
    Object.keys(HISTORY_CATEGORIES)
  );

  const drawerClient = clients.find(c => c.id === drawerClientId);

  const segments = useMemo(() => {
    const map = {};
    clients.forEach(c => { map[c.segment] = (map[c.segment] || 0) + 1; });
    return Object.entries(map).map(([id, count]) => ({ id, count }));
  }, [clients]);

  // Mapa cliente → deuda total (de invoices)
  const debtMap = useMemo(() => {
    const m = {};
    (invoices || []).forEach(inv => {
      if (inv.balance > 0 && (inv.state === "emitido" || inv.state === "vencido")) {
        m[inv.clientId] = (m[inv.clientId] || 0) + inv.balance;
      }
    });
    return m;
  }, [invoices]);

  const filtered = useMemo(() => {
    let r = clients;
    if (activeSubTab === "debtors") {
      r = r.filter(c => (debtMap[c.id] || 0) > 0);
    }
    if (segmentFilter !== "all") r = r.filter(c => c.segment === segmentFilter);
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      // Buscar solo en los campos que el rol puede ver.
      // El petCode siempre es buscable (está en la sección "pets" y no es sensible).
      r = r.filter(c => {
        const matches = [];
        if (showField("tutor", "name"))    matches.push(c.name.toLowerCase().includes(q));
        if (showField("tutor", "cedula"))  matches.push(c.cedula.toLowerCase().includes(q));
        if (showField("tutor", "phone"))   matches.push(c.phone.includes(q));
        if (showField("tutor", "email"))   matches.push(c.email.toLowerCase().includes(q));
        // Búsqueda por nombre de mascota (resolviendo desde passports si está disponible)
        if (showField("pets", "list")) {
          matches.push(c.petCodes.some(code => code.includes(q)));
          // Buscar por nombre de mascota dentro de los pasaportes asociados
          c.petCodes.forEach(code => {
            const pet = passports.find(p => p.code === code);
            if (pet?.name && showField("pets", "name")) {
              matches.push(pet.name.toLowerCase().includes(q));
            }
            if (pet?.breed && showField("pets", "breed")) {
              matches.push(pet.breed.toLowerCase().includes(q));
            }
          });
        }
        return matches.some(Boolean);
      });
    }
    // Si tab deudores, ordenar por monto de deuda descendente
    if (activeSubTab === "debtors") {
      r = [...r].sort((a, b) => (debtMap[b.id] || 0) - (debtMap[a.id] || 0));
    }
    return r;
  }, [clients, segmentFilter, searchQuery, activeSubTab, debtMap]);

  const stats = useMemo(() => {
    const totalPets = clients.reduce((sum, c) => sum + c.petCodes.length, 0);
    const totalSpent = clients.reduce((sum, c) => sum + c.totalSpent, 0);
    const totalDebt = Object.values(debtMap).reduce((s, v) => s + v, 0);
    const debtorCount = Object.keys(debtMap).length;
    return { totalClients: clients.length, totalPets, totalSpent, totalDebt, debtorCount };
  }, [clients, debtMap]);

  const toggleCategory = (catId) => {
    setVisibleCategories(prev =>
      prev.includes(catId) ? prev.filter(c => c !== catId) : [...prev, catId]
    );
  };

  return (
    <div className="relative">
      {/* Tabs principales: Directorio de clientes vs Cola de actualizaciones de pasaportes.
          La pestaña "Actualizaciones" reemplaza el item de sidebar "passport-updates" antiguo:
          ahora vive aquí dentro porque conceptualmente pertenece al módulo de Clientes. */}
      <div className="mb-4 flex gap-1 bg-white border border-stone-200 rounded-2xl p-1 shadow-sm">
        <button
          onClick={() => setMainTab("directory")}
          className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold transition ${
            mainTab === "directory"
              ? "bg-orange-600 text-white shadow"
              : "text-stone-600 hover:bg-stone-50"
          }`}
        >
          <Users size={14} />
          <span>Directorio de clientes</span>
          <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
            mainTab === "directory" ? "bg-orange-700 text-white" : "bg-stone-100 text-stone-600"
          }`}>{clients.length}</span>
        </button>
        <button
          onClick={() => setMainTab("updates")}
          className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold transition ${
            mainTab === "updates"
              ? "bg-orange-600 text-white shadow"
              : "text-stone-600 hover:bg-stone-50"
          }`}
        >
          <BadgeCheck size={14} />
          <span>Actualizaciones</span>
          {pendingUpdatesCount > 0 && (
            <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
              mainTab === "updates" ? "bg-white text-orange-700" : "bg-amber-100 text-amber-800"
            }`}>{pendingUpdatesCount}</span>
          )}
        </button>
      </div>

      {/* Tab "Actualizaciones": cola de propuestas de cambio enviadas desde cualquier CRM */}
      {mainTab === "updates" && (
        <PassportUpdatesView
          passports={passports}
          setPassports={setPassports}
          petUpdates={petUpdates}
          setPetUpdates={setPetUpdates}
          userRole={userRole}
          userName={userName}
          embedded
        />
      )}

      {/* Tab "Directorio": el contenido original de Clientes (cards + filtros + drawer) */}
      {mainTab === "directory" && (<>
      <div className={`space-y-5 transition-all duration-300 ${drawerClient ? "sm:pr-80" : ""}`}>
        {/* Hero */}
        <div className="relative p-6 rounded-2xl bg-gradient-to-br from-white via-orange-50 to-orange-100 border border-stone-200 overflow-hidden">
          <div className="flex items-center gap-4 flex-wrap">
            <div className="flex-1 min-w-0">
              <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
                Operación · Base de tutores
              </div>
              <h2 className="font-serif text-3xl font-semibold leading-tight">
                <span className="text-orange-700">{stats.totalClients}</span> clientes registrados
              </h2>
              <p className="text-sm text-stone-600 mt-1 max-w-2xl">
                Click en cualquier cliente para ver su ficha completa con historial multi-categoría.
              </p>
            </div>
            <div className="flex gap-2.5 flex-wrap">
              <Kpi label="Mascotas totales" value={stats.totalPets} />
              {stats.totalDebt > 0 && (
                <button
                  onClick={() => setActiveSubTab("debtors")}
                  className={`px-5 py-3 rounded-xl text-center min-w-20 transition border ${
                    activeSubTab === "debtors"
                      ? "bg-red-600 border-red-600 text-white"
                      : "bg-white border-red-200 hover:border-red-400"
                  }`}
                >
                  <div className={`text-xs tracking-widest uppercase font-semibold flex items-center gap-1 justify-center ${
                    activeSubTab === "debtors" ? "text-white" : "text-red-700"
                  }`}>
                    <AlertTriangle size={11} /> Deuda
                  </div>
                  <div className={`font-serif text-2xl font-semibold leading-none mt-1 ${
                    activeSubTab === "debtors" ? "text-white" : "text-red-700"
                  }`}>
                    ${(stats.totalDebt / 1000).toFixed(1)}k
                  </div>
                </button>
              )}
              <Kpi label="Facturación" value={`$${(stats.totalSpent / 1000).toFixed(1)}k`} accent />
            </div>
          </div>
        </div>

        {/* Sub-tabs: Todos | Deudores */}
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-1.5 inline-flex gap-1">
          <button
            onClick={() => setActiveSubTab("all")}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition ${
              activeSubTab === "all" ? "bg-stone-900 text-white" : "text-stone-600 hover:bg-stone-50"
            }`}
          >
            <Users size={14} />
            Todos los clientes
            <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
              activeSubTab === "all" ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-600"
            }`}>{clients.length}</span>
          </button>
          {showField("billing", "balance") && (
            <button
              onClick={() => setActiveSubTab("debtors")}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition ${
                activeSubTab === "debtors" ? "bg-red-600 text-white" : "text-stone-600 hover:bg-stone-50"
              }`}
            >
              <AlertTriangle size={14} />
              Deudores
              <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                activeSubTab === "debtors" ? "bg-red-700 text-white" : "bg-red-100 text-red-700"
              }`}>{stats.debtorCount}</span>
            </button>
          )}
          {activeSubTab === "debtors" && (
            <button
              onClick={onOpenSales}
              className="ml-auto flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold text-stone-600 hover:text-orange-700 hover:bg-orange-50 transition"
            >
              <ExternalLink size={12} />
              Ir a Ventas
            </button>
          )}
        </div>

        {/* Toolbar */}
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-4 flex flex-col lg:flex-row gap-3 items-stretch lg:items-center">
          <div className="relative flex-1">
            <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
            <input
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder={(() => {
                // Construir placeholder reflejando solo los campos buscables
                const parts = [];
                if (showField("tutor", "name"))    parts.push("nombre");
                if (showField("pets", "name"))     parts.push("mascota");
                if (showField("tutor", "cedula"))  parts.push("cédula");
                if (showField("tutor", "phone"))   parts.push("teléfono");
                if (showField("tutor", "email"))   parts.push("email");
                if (showField("pets", "list"))     parts.push("código de mascota");
                if (parts.length === 0) return "Buscar...";
                if (parts.length === 1) return `Buscar por ${parts[0]}...`;
                const last = parts.pop();
                return `Buscar por ${parts.join(", ")} o ${last}...`;
              })()}
              className="w-full pl-11 pr-10 py-2.5 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white"
            />
            {searchQuery && (
              <button
                onClick={() => setSearchQuery("")}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-400 hover:text-stone-600"
              >
                <X size={14} />
              </button>
            )}
          </div>

          <div className="flex gap-1.5 flex-wrap">
            <button
              onClick={() => setSegmentFilter("all")}
              className={`flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold transition ${
                segmentFilter === "all" ? "bg-stone-900 text-white" : "bg-white text-stone-600 border border-stone-200"
              }`}
            >
              Todos
              <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                segmentFilter === "all" ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-500"
              }`}>{clients.length}</span>
            </button>
            {segments.map(s => (
              <button
                key={s.id}
                onClick={() => setSegmentFilter(s.id)}
                className={`flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold transition ${
                  segmentFilter === s.id ? "bg-stone-900 text-white" : "bg-white text-stone-600 border border-stone-200"
                }`}
              >
                {s.id}
                <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                  segmentFilter === s.id ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-500"
                }`}>{s.count}</span>
              </button>
            ))}
          </div>

          {canCreate && (
            <button
              onClick={onNewClient}
              className="flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-orange-600 hover:bg-orange-700 text-white text-sm font-semibold transition"
            >
              <UserPlus size={14} /> Nuevo cliente
            </button>
          )}
        </div>

        {/* Grid de clientes */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
          {filtered.length === 0 && (
            <div className="col-span-full bg-white border border-stone-200 rounded-2xl p-12 text-center">
              <Search size={32} className="text-stone-300 mx-auto mb-3" />
              <div className="text-base font-semibold text-stone-700">Sin resultados</div>
              <div className="text-sm text-stone-500 mt-1">
                Intenta otros términos de búsqueda.
              </div>
            </div>
          )}
          {filtered.map(c => (
            <ClientCard
              key={c.id}
              client={c}
              active={drawerClientId === c.id}
              onOpen={() => setDrawerClientId(c.id)}
              debt={debtMap[c.id] || 0}
              viewPerms={{
                showName: showField("tutor", "name"),
                showCedula: showField("tutor", "cedula"),
                showSegment: showField("tutor", "segment"),
                showBalance: showField("billing", "balance"),
                showPets: showField("pets", "list"),
              }}
            />
          ))}
        </div>
      </div>

      {/* DRAWER lateral derecho — solo visible en el tab directorio */}
      {drawerClient && (
        <ClientDrawer
          client={drawerClient}
          passports={passports}
          visibleCategories={visibleCategories}
          onToggleCategory={toggleCategory}
          onClose={() => setDrawerClientId(null)}
          onOpenPassport={onOpenPassport}
          conversation={conversations?.[drawerClient.id] || []}
          onMessageClient={onMessageClient}
          onCompleteRegistration={onCompleteRegistration}
          userRole={userRole}
          permissions={permissions}
        />
      )}
      </>)}
    </div>
  );
}

function ClientCard({ client, active, onOpen, debt, viewPerms = {} }) {
  const initials = client.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase();
  // Defaults: si no se pasan permisos, mostrar todo (compatibilidad hacia atrás)
  const {
    showName = true, showCedula = true, showSegment = true,
    showBalance = true, showPets = true,
  } = viewPerms;
  return (
    <button
      onClick={onOpen}
      className={`text-left bg-white border rounded-2xl p-4 transition cursor-pointer ${
        active
          ? "border-orange-400 shadow-md ring-2 ring-orange-200"
          : debt > 0 && showBalance
            ? "border-red-200 hover:border-red-400 hover:shadow-md"
            : "border-stone-200 hover:border-orange-300 hover:shadow-md"
      }`}
    >
      <div className="flex items-start gap-3 mb-3">
        <div className={`w-12 h-12 rounded-xl grid place-items-center text-white text-sm font-bold flex-shrink-0 ${
          client.isOrg
            ? "bg-gradient-to-br from-stone-700 to-stone-900"
            : "bg-gradient-to-br from-orange-500 to-orange-700"
        }`}>
          {initials}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5 flex-wrap">
            {/* Nombre del tutor: si está oculto mostramos un placeholder neutro para que se pueda ubicar la card por petCodes */}
            <span className="font-semibold text-sm leading-tight truncate">
              {showName ? client.name : `Tutor de ${client.petCodes.length} ${client.petCodes.length === 1 ? "mascota" : "mascotas"}`}
            </span>
            {client.quickRegistration && showName && (
              <span className="text-xs font-bold px-1.5 py-px rounded-full bg-amber-100 text-amber-800 inline-flex items-center gap-0.5">
                <Zap size={9} strokeWidth={2.5} /> Express
              </span>
            )}
          </div>
          {showCedula && (
            <div className="text-xs text-stone-500 mt-0.5 font-mono truncate">{client.cedula}</div>
          )}
        </div>
      </div>
      {showBalance && debt > 0 && (
        <div className="mb-2 px-2 py-1.5 rounded-lg bg-red-50 border border-red-200 flex items-center gap-1.5">
          <AlertTriangle size={11} className="text-red-600 flex-shrink-0" />
          <span className="text-xs font-semibold text-red-700">Debe</span>
          <span className="text-xs font-bold text-red-800 font-mono ml-auto">${debt.toLocaleString()}</span>
        </div>
      )}
      <div className="flex items-center justify-between gap-2 pt-3 border-t border-dashed border-stone-200">
        {showPets ? (
          <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-orange-100 text-orange-800 inline-flex items-center gap-1">
            <PawPrint size={11} />
            {client.petCodes.length}
          </span>
        ) : <span />}
        {showSegment && (
          <span className="text-xs text-stone-500 truncate">{client.segment}</span>
        )}
      </div>
    </button>
  );
}

// ========== DRAWER LATERAL DERECHO ==========

function ClientDrawer({ client, passports, visibleCategories, onToggleCategory, onClose, onOpenPassport, conversation, onMessageClient, onCompleteRegistration, userRole = "super", permissions = {} }) {
  // Helpers de permisos para el CRM "clients"
  const showField = (sectionId, fieldId) =>
    getFieldLevel(permissions, userRole, "clients", sectionId, fieldId) !== "hidden";
  const showAnyTutorContact = ["cedula","phone","email","address"].some(f => showField("tutor", f));
  const showBilling = ["invoices","balance","plans"].some(f => showField("billing", f));
  const showMessaging = showField("messaging", "chat-read");

  const [activeTab, setActiveTab] = useState("overview"); // overview | history | pets
  const [expandedPet, setExpandedPet] = useState(null);
  const [showCustomize, setShowCustomize] = useState(false);

  const initials = client.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase();
  const events = useMemo(() => buildClientHistory(client), [client]);
  const visibleEvents = events.filter(e => visibleCategories.includes(e.category));
  const allPets = useMemo(
    () => client.petCodes.map(code => findPetByCode(code, passports)).filter(Boolean),
    [client.petCodes, passports]
  );

  const segmentColors = {
    Premium: "bg-amber-100 text-amber-800",
    Frecuente: "bg-blue-100 text-blue-800",
    Nuevo: "bg-emerald-100 text-emerald-800",
    Institucional: "bg-stone-200 text-stone-800",
  };

  return (
    <>
      {/* Backdrop solo en mobile */}
      <div
        onClick={onClose}
        className="fixed inset-0 bg-stone-900 z-30 sm:hidden"
      />

      {/* Drawer: en desktop pegado a la derecha del módulo (absolute), en mobile ocupa pantalla */}
      <aside className="fixed top-0 right-0 bottom-0 w-full sm:absolute sm:top-0 sm:right-0 sm:bottom-auto sm:w-80 sm:min-h-screen bg-stone-50 z-40 shadow-2xl flex flex-col border-l border-stone-200">
        {/* Header del drawer */}
        <div className="bg-white border-b border-stone-200 flex-shrink-0">
          <div className="p-4 flex items-center gap-3">
            <button
              onClick={onClose}
              className="w-9 h-9 rounded-lg bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600 transition"
            >
              <X size={16} />
            </button>
            <div className="flex-1 min-w-0">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
                Ficha del cliente
              </div>
              <div className="font-serif text-lg font-semibold leading-tight truncate">
                {client.name}
              </div>
            </div>
            <button
              onClick={() => setShowCustomize(!showCustomize)}
              className={`w-9 h-9 rounded-lg grid place-items-center transition ${
                showCustomize
                  ? "bg-orange-600 text-white"
                  : "bg-stone-100 hover:bg-stone-200 text-stone-600"
              }`}
              title="Administrar visibilidad"
            >
              <Settings size={15} />
            </button>
          </div>

          {/* Tabs (filtradas por permisos del rol) */}
          <div className="flex border-t border-stone-200">
            {[
              { id: "overview", label: "Resumen", Icon: User, visible: true },
              { id: "history",  label: "Historial", Icon: History, visible: showBilling },
              { id: "messages", label: "Mensajes", Icon: MessageCircle, badge: (conversation || []).length, visible: showMessaging },
              { id: "pets",     label: `Mascotas`, Icon: PawPrint, badge: allPets.length, visible: showField("pets", "list") },
            ].filter(t => t.visible).map(t => {
              const Icon = t.Icon;
              const active = activeTab === t.id;
              return (
                <button
                  key={t.id}
                  onClick={() => setActiveTab(t.id)}
                  className={`flex-1 flex items-center justify-center gap-1.5 px-2 py-3 text-xs font-semibold transition relative ${
                    active ? "text-orange-700 bg-orange-50" : "text-stone-600 hover:bg-stone-50"
                  }`}
                >
                  {active && <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-orange-600" />}
                  <Icon size={13} strokeWidth={1.8} />
                  <span className="hidden sm:inline">{t.label}</span>
                  {t.badge !== undefined && t.badge > 0 && (
                    <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                      active ? "bg-orange-600 text-white" : "bg-stone-200 text-stone-600"
                    }`}>{t.badge}</span>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* Panel de personalización (cuando se abre) */}
        {showCustomize && (
          <div className="bg-orange-50 border-b border-orange-200 p-4 flex-shrink-0">
            <div className="flex items-center gap-2 mb-2.5">
              <Eye size={13} className="text-orange-700" />
              <span className="text-xs tracking-widest uppercase text-orange-800 font-semibold">
                Categorías visibles del historial
              </span>
            </div>
            <div className="grid grid-cols-2 gap-1.5">
              {Object.entries(HISTORY_CATEGORIES).map(([catId, cat]) => {
                const Icon = cat.Icon;
                const enabled = visibleCategories.includes(catId);
                const colors = COLOR_CLASSES[cat.color];
                return (
                  <button
                    key={catId}
                    onClick={() => onToggleCategory(catId)}
                    className={`flex items-center gap-2 p-2 rounded-lg border text-left transition ${
                      enabled
                        ? `${colors.bg} ${colors.border} ${colors.text}`
                        : "bg-white border-stone-200 text-stone-400"
                    }`}
                  >
                    <span className={`w-2 h-2 rounded-full ${enabled ? colors.dot : "bg-stone-300"}`}></span>
                    <Icon size={13} strokeWidth={1.8} />
                    <span className="text-xs font-semibold flex-1">{cat.label}</span>
                    {enabled
                      ? <Eye size={11} />
                      : <EyeOff size={11} />
                    }
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* Banner: cliente con registro rápido sin completar */}
        {client.quickRegistration && (
          <div className="bg-amber-50 border-b border-amber-200 p-3 flex items-start gap-2.5 flex-shrink-0">
            <Zap size={14} className="text-amber-700 flex-shrink-0 mt-0.5" />
            <div className="flex-1 min-w-0">
              <div className="text-xs font-bold text-amber-900 leading-tight">Registro Express</div>
              <div className="text-xs text-amber-800 leading-relaxed mt-0.5">
                Para servicios clínicos, completa el registro y agrega al menos una mascota.
              </div>
              {onCompleteRegistration && (
                <button
                  onClick={() => onCompleteRegistration(client)}
                  className="mt-2 flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-amber-600 hover:bg-amber-700 text-white text-xs font-semibold transition"
                >
                  <UserPlus size={11} /> Completar registro
                </button>
              )}
            </div>
          </div>
        )}

        {/* Body scrollable */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {activeTab === "overview" && (
            <DrawerOverview
              client={client}
              initials={initials}
              segmentColors={segmentColors}
              allPets={allPets}
              viewPerms={{
                showCedula: showField("tutor", "cedula"),
                showPhone: showField("tutor", "phone"),
                showEmail: showField("tutor", "email"),
                showAddress: showField("tutor", "address"),
                showSegment: showField("tutor", "segment"),
                showSpending: showField("tutor", "spending"),
                showAnyContact: showAnyTutorContact,
                showBalance: showField("billing", "balance"),
                showPets: showField("pets", "list"),
              }}
            />
          )}

          {activeTab === "history" && (
            <DrawerHistory
              events={visibleEvents}
              totalEvents={events.length}
              hiddenCount={events.length - visibleEvents.length}
            />
          )}

          {activeTab === "messages" && (
            <ChatHistoryPreview
              conversation={conversation}
              onOpenChat={() => onMessageClient?.(client.id)}
              max={6}
            />
          )}

          {activeTab === "pets" && (
            <DrawerPets
              pets={allPets}
              expandedPet={expandedPet}
              setExpandedPet={setExpandedPet}
              onOpenPassport={onOpenPassport}
            />
          )}
        </div>

        {/* Footer (botones según permisos) */}
        {(showMessaging || showField("tutor", "phone") || showField("tutor", "email")) && (
          <div className="bg-white border-t border-stone-200 p-3 flex gap-2 flex-shrink-0">
            {showMessaging && (
              <button
                onClick={() => onMessageClient?.(client.id)}
                className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold transition"
              >
                <MessageCircle size={13} /> Mensaje
              </button>
            )}
            {showField("tutor", "phone") && (
              <button className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl bg-white border border-stone-200 hover:border-orange-300 text-stone-700 hover:text-orange-700 text-xs font-semibold transition">
                <Phone size={13} /> Llamar
              </button>
            )}
            {showField("tutor", "email") && (
              <button className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl bg-white border border-stone-200 hover:border-orange-300 text-stone-700 hover:text-orange-700 text-xs font-semibold transition">
                <Mail size={13} /> Email
              </button>
            )}
          </div>
        )}
      </aside>
    </>
  );
}

function DrawerOverview({ client, initials, segmentColors, allPets, viewPerms = {} }) {
  const {
    showCedula = true, showPhone = true, showEmail = true, showAddress = true,
    showSegment = true, showSpending = true, showAnyContact = true,
    showBalance = true, showPets = true,
  } = viewPerms;
  return (
    <>
      {/* Hero del cliente */}
      <div className="bg-white border border-stone-200 rounded-xl p-4 text-center">
        <div className={`w-16 h-16 rounded-2xl grid place-items-center text-white text-xl font-bold mx-auto mb-3 ${
          client.isOrg
            ? "bg-gradient-to-br from-stone-700 to-stone-900"
            : "bg-gradient-to-br from-orange-500 to-orange-700"
        }`}>
          {initials}
        </div>
        <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
          Cliente desde {client.since}
        </div>
        <h3 className="font-serif text-2xl font-semibold leading-tight mb-2">{client.name}</h3>
        <div className="flex flex-wrap gap-1.5 justify-center">
          {showSegment && (
            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-bold ${segmentColors[client.segment] || "bg-stone-100 text-stone-700"}`}>
              {client.segment === "Premium" && <Star size={10} strokeWidth={2.5} />}
              {client.segment}
            </span>
          )}
          {showCedula && (
            <span className="text-xs text-stone-500 font-mono">{client.cedula}</span>
          )}
        </div>
      </div>

      {/* Datos de contacto — solo si hay al menos un campo visible */}
      {showAnyContact && (
        <div className="bg-white border border-stone-200 rounded-xl p-4 space-y-3">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
            Datos de contacto
          </div>
          {showPhone && <ContactRow icon={Phone} label="Teléfono" value={client.phone} mono />}
          {showEmail && <ContactRow icon={Mail} label="Email" value={client.email} />}
          {showAddress && <ContactRow icon={MapPin} label="Dirección" value={client.address} />}
          <ContactRow icon={Clock} label="Última visita" value={client.lastVisit} />
        </div>
      )}

      {/* Aviso si TODO el bloque tutor está oculto y no hay nada que mostrar */}
      {!showAnyContact && !showSegment && !showSpending && (
        <div className="bg-stone-50 border border-stone-200 rounded-xl p-4 text-center">
          <Lock size={16} className="text-stone-400 mx-auto mb-1.5" />
          <div className="text-xs text-stone-500 italic">
            Datos administrativos del tutor restringidos para tu rol.
          </div>
        </div>
      )}

      {/* Métricas */}
      <div className="grid grid-cols-2 gap-2">
        {showPets && <MetricCard icon={PawPrint} label="Mascotas" value={client.petCodes.length} />}
        {showSpending && <MetricCard icon={TrendingUp} label="Facturado" value={`$${client.totalSpent.toLocaleString()}`} accent />}
      </div>

      {/* Quick pets list */}
      {showPets && (
        <div className="bg-white border border-stone-200 rounded-xl p-4">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
            Mascotas vinculadas
          </div>
          <div className="space-y-1.5">
            {allPets.slice(0, 4).map(pet => {
              const Icon = ANIMAL_ICONS[pet.species] || PawPrint;
              return (
                <div key={pet.code} className="flex items-center gap-2 p-2 rounded-lg bg-stone-50">
                  <div className="w-7 h-7 rounded-lg bg-orange-100 grid place-items-center text-orange-700 flex-shrink-0">
                    <Icon size={13} strokeWidth={1.8} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="text-xs font-semibold truncate">{pet.name}</div>
                    <div className="text-xs text-orange-600 font-mono">{pet.code}</div>
                  </div>
                </div>
              );
            })}
            {allPets.length > 4 && (
              <div className="text-xs text-stone-500 text-center py-1">
                + {allPets.length - 4} más en la pestaña <strong>Mascotas</strong>
              </div>
            )}
          </div>
        </div>
      )}
    </>
  );
}

function DrawerHistory({ events, totalEvents, hiddenCount }) {
  const [expandedId, setExpandedId] = useState(null);

  const byCategory = useMemo(() => {
    const groups = {};
    events.forEach(e => {
      if (!groups[e.category]) groups[e.category] = [];
      groups[e.category].push(e);
    });
    return groups;
  }, [events]);

  return (
    <>
      <div className="bg-white border border-stone-200 rounded-xl p-3 flex items-center justify-between">
        <div>
          <div className="text-xs font-semibold text-stone-700">
            {events.length} {events.length === 1 ? "evento" : "eventos"} visibles
          </div>
          {hiddenCount > 0 && (
            <div className="text-xs text-stone-500 mt-0.5">
              {hiddenCount} ocultos por filtros
            </div>
          )}
        </div>
        <div className="text-xs text-stone-400">de {totalEvents} totales</div>
      </div>

      {Object.entries(HISTORY_CATEGORIES).map(([catId, cat]) => {
        const catEvents = byCategory[catId] || [];
        if (catEvents.length === 0) return null;
        const Icon = cat.Icon;
        const colors = COLOR_CLASSES[cat.color];
        return (
          <div key={catId} className={`rounded-xl border ${colors.border} ${colors.bg} overflow-hidden`}>
            <div className={`px-4 py-2.5 border-b ${colors.border} flex items-center justify-between gap-2`}>
              <div className="flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${colors.dot}`}></span>
                <Icon size={14} className={colors.text} strokeWidth={1.8} />
                <span className={`text-xs font-bold uppercase tracking-wider ${colors.text}`}>
                  {cat.label}
                </span>
              </div>
              <span className={`text-xs font-bold px-2 py-0.5 rounded-full bg-white ${colors.text}`}>
                {catEvents.length}
              </span>
            </div>
            <div className="bg-white divide-y divide-stone-100">
              {catEvents.map(e => (
                <HistoryEvent
                  key={e.id}
                  event={e}
                  colors={colors}
                  expanded={expandedId === e.id}
                  onToggle={() => setExpandedId(expandedId === e.id ? null : e.id)}
                />
              ))}
            </div>
          </div>
        );
      })}

      {events.length === 0 && (
        <div className="bg-white border border-stone-200 rounded-xl p-8 text-center">
          <EyeOff size={28} className="text-stone-300 mx-auto mb-2" />
          <div className="text-sm font-semibold text-stone-700">Todas las categorías ocultas</div>
          <div className="text-xs text-stone-500 mt-1">
            Activa al menos una desde el icono ⚙ arriba.
          </div>
        </div>
      )}
    </>
  );
}

// Despachador: cada subtipo se renderiza con su propio look
function HistoryEvent({ event, colors, expanded, onToggle }) {
  if (event.subtype === "factura")        return <EventInvoice event={event} colors={colors} expanded={expanded} onToggle={onToggle} />;
  if (event.subtype === "examen")         return <EventExam event={event} colors={colors} expanded={expanded} onToggle={onToggle} />;
  if (event.subtype === "cita-proxima")   return <EventUpcomingAppt event={event} colors={colors} expanded={expanded} onToggle={onToggle} />;
  if (event.subtype === "cita-realizada") return <EventPastAppt event={event} colors={colors} expanded={expanded} onToggle={onToggle} />;
  if (event.subtype === "recipe")         return <EventRecipe event={event} colors={colors} expanded={expanded} onToggle={onToggle} />;
  if (event.subtype === "servicio")       return <EventService event={event} colors={colors} expanded={expanded} onToggle={onToggle} />;
  return null;
}

