// === Tracker de proceso (compartido por Lab y Recipe) ===
function ProcessTracker({ currentState, timeline }) {
  const order = ["solicitado", "atendido", "procesando", "entregado"];
  // Labels cortas para que quepan
  const SHORT = { solicitado: "Solicit.", atendido: "Atend.", procesando: "Proces.", entregado: "Entreg." };
  const currentStep = PROCESS_STATES[currentState]?.step || 0;

  return (
    <div className="bg-stone-50 rounded-lg p-2.5 border border-stone-200">
      {/* Stepper compacto */}
      <div className="flex items-start justify-between gap-0.5 mb-2">
        {order.map((stateId, i) => {
          const state = PROCESS_STATES[stateId];
          const reached = state.step <= currentStep;
          const isLast = i === order.length - 1;
          const colorClass = PROCESS_BADGE_CLASSES[state.color];
          return (
            <Fragment key={stateId}>
              <div className="flex flex-col items-center gap-1 min-w-0 flex-shrink-0">
                <div className={`w-6 h-6 rounded-full grid place-items-center text-xs font-bold border-2 transition ${
                  reached ? colorClass : "bg-white border-stone-300 text-stone-400"
                }`}>
                  {reached ? <Check size={11} strokeWidth={3} /> : state.step}
                </div>
                <span className={`text-xs font-semibold leading-tight whitespace-nowrap ${
                  reached ? "text-stone-700" : "text-stone-400"
                }`}>{SHORT[stateId]}</span>
              </div>
              {!isLast && (
                <div className={`flex-1 h-0.5 mt-3 min-w-2 ${
                  state.step < currentStep ? "bg-emerald-400" : "bg-stone-300"
                }`}></div>
              )}
            </Fragment>
          );
        })}
      </div>
      {/* Timeline detallado */}
      <div className="border-t border-stone-200 pt-2 mt-1 space-y-1">
        {timeline.map((t, i) => {
          const s = PROCESS_STATES[t.state];
          return (
            <div key={i} className="flex items-center justify-between gap-2 text-xs">
              <span className="text-stone-600 truncate min-w-0 flex-1">
                <span className="font-semibold">{s.label}</span>
                <span className="text-stone-400"> · {t.by}</span>
              </span>
              <span className="text-stone-400 whitespace-nowrap flex-shrink-0">{t.date}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

