// === Lista de conversaciones recientes (uso en Drawer del cliente) ===
function ChatHistoryPreview({ conversation, onOpenChat, max = 5 }) {
  const recent = useMemo(
    () => (conversation || []).slice(-max).reverse(),
    [conversation, max]
  );

  if (!conversation || conversation.length === 0) {
    return (
      <div className="bg-white border border-stone-200 border-dashed rounded-xl p-6 text-center">
        <MessageCircle size={24} className="text-stone-300 mx-auto mb-2" />
        <div className="text-sm font-semibold text-stone-600">Sin mensajes aún</div>
        <div className="text-xs text-stone-500 mt-1 mb-3">
          Inicia una conversación con este cliente.
        </div>
        <button
          onClick={onOpenChat}
          className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold transition"
        >
          <MessageCircle size={11} /> Iniciar chat
        </button>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-2">
        <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
          Últimos mensajes ({conversation.length} total)
        </div>
        <button
          onClick={onOpenChat}
          className="text-xs text-emerald-700 font-semibold hover:underline inline-flex items-center gap-1"
        >
          Abrir chat <ChevronRight size={11} />
        </button>
      </div>
      <div className="bg-white border border-stone-200 rounded-xl divide-y divide-stone-100 overflow-hidden">
        {recent.map(msg => {
          const channelInfo = CHAT_CHANNELS[msg.channel];
          const colors = CHAT_CHANNEL_CLASSES[channelInfo.color];
          const ChannelIcon = channelInfo.icon;
          return (
            <div key={msg.id} className="p-3 flex gap-2.5">
              <div className={`w-7 h-7 rounded-lg ${colors.bg} ${colors.text} grid place-items-center flex-shrink-0`}>
                <ChannelIcon size={11} strokeWidth={1.8} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-baseline gap-2 flex-wrap">
                  <span className={`text-xs font-bold ${colors.text}`}>{channelInfo.label}</span>
                  <span className="text-xs text-stone-400">·</span>
                  <span className="text-xs text-stone-500">
                    {msg.direction === "out" ? "→ Enviado" : "← Recibido"}
                  </span>
                  <span className="ml-auto text-xs text-stone-400 whitespace-nowrap">
                    {formatChatTime(msg.timestamp)}
                  </span>
                </div>
                <div className="text-sm text-stone-700 leading-snug mt-0.5 line-clamp-2">
                  {msg.body}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ========== VISTA: NUEVA VENTA / CATÁLOGO DE SERVICIOS ==========

