function ProfileSection({ title, desc, children }) {
  return (
    <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-5 space-y-3">
      <div>
        <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">{title}</div>
        {desc && <div className="text-xs text-stone-500 mt-0.5">{desc}</div>}
      </div>
      {children}
    </div>
  );
}

function ProfileField({ label, hint, children }) {
  return (
    <div>
      <label className="text-xs font-semibold text-stone-700 block mb-1.5">{label}</label>
      {children}
      {hint && <div className="text-xs text-stone-500 mt-1">{hint}</div>}
    </div>
  );
}

function ToggleRow({ icon: Icon, label, desc, checked, onChange }) {
  return (
    <button
      onClick={onChange}
      className={`w-full flex items-center gap-3 p-3 rounded-xl border transition text-left ${
        checked
          ? "bg-orange-50 border-orange-200"
          : "bg-white border-stone-200 hover:border-stone-300"
      }`}
    >
      <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
        checked ? "bg-orange-100 text-orange-700" : "bg-stone-100 text-stone-500"
      }`}>
        <Icon size={15} strokeWidth={1.8} />
      </div>
      <div className="flex-1 min-w-0">
        <div className="font-semibold text-sm">{label}</div>
        <div className="text-xs text-stone-500 mt-0.5">{desc}</div>
      </div>
      <span className={`w-10 h-5 rounded-full relative transition flex-shrink-0 ${checked ? "bg-orange-600" : "bg-stone-300"}`}>
        <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition ${checked ? "left-5" : "left-0.5"}`}></span>
      </span>
    </button>
  );
}

// ========== PLACEHOLDER: VISTAS EN DESARROLLO ==========

// ========== CRM HUB UNIFICADO (Veterinaria + Grooming + B2B por rol) ==========
// Reemplaza al sidebar antiguo donde cada CRM era un ítem independiente.
// Las secciones disponibles dependen de los permisos del rol actual.
// El super admin ve todas y puede cambiar de "vista de rol" para previsualizar
// cómo se ve la app desde otro rol — útil para QA y onboarding.
function CRMHubView({ userRole, perm, modules = [], onSelectSection, vetProps, groomingOpsProps, standardProps, salesProps, onGoToManager }) {
  // Lookup helper: ¿el módulo X está instalado y NO removido?
  const isInstalled = (id) => {
    if (id === "sales") return true; // sales es parte del tronco fijo, siempre presente
    const m = modules.find(mm => mm.id === id);
    // Si no hay registro en modules (por ejemplo, sales) lo permitimos por defecto.
    // Solo bloqueamos si EXISTE el registro y está marcado como removed.
    return !m || !m.removed;
  };
  // Resolver nombre dinámico desde el registro de módulos (renombrable desde Manager)
  const moduleName = (id, fallback) => {
    const m = modules.find(mm => mm.id === id);
    return m?.name || fallback;
  };

  // Mapa kind → metadatos visuales (icon, accent, descripción base).
  // Los módulos clonados desde una plantilla (ej. "Veterinaria 2") heredan estos
  // valores según su `kind`. Esto permite que CUALQUIER módulo creado se vea
  // y se comporte como una pestaña más, sin tener que tocar este código.
  const KIND_VISUALS = {
    vet:      { Icon: Stethoscope, accent: "from-orange-500 to-orange-700",  desc: "Consultas, fichas clínicas, sugerencias de medicina por diagnóstico." },
    grooming: { Icon: Bath,        accent: "from-emerald-500 to-emerald-700", desc: "Agenda diaria, recepción de mascotas, fotos antes/después." },
    standard: { Icon: Tag,         accent: "from-blue-500 to-blue-700",      desc: "Pipeline configurable con embudo de ventas y campos personalizados." },
    custom:   { Icon: LayoutGrid,  accent: "from-stone-500 to-stone-700",    desc: "CRM personalizado con campos y reglas propias." },
  };

  // Secciones que el rol actual tiene permiso de ver Y cuyo módulo está instalado.
  // Sales siempre presente (parte del tronco). El resto se construye iterando sobre
  // `modules` (registro global): cada módulo no-removido aporta su propia pestaña.
  // Permisos: el rol debe tener acceso al `kind` (ej. "vet") para ver TODOS los módulos
  // de ese kind. Si quieres permisos individuales por instancia, eso vendrá después.
  const sections = useMemo(() => {
    const list = [];
    // Ventas va primero — es el flujo de cierre que más se consulta a diario.
    if (canAccess(perm, "sales")) {
      list.push({ id: "sales", label: "Ventas", Icon: ShoppingBag, accent: "from-purple-500 to-purple-700", desc: "Facturación, pagos, planes de crédito y comprobantes." });
    }
    // Iteramos sobre TODOS los módulos instalados — esto incluye los core (vet,
    // grooming-ops, standard) y cualquier nuevo creado desde Manager.
    (modules || []).filter(m => !m.removed).forEach(m => {
      // === Permisos por instancia ===
      // Cada módulo tiene su propio id en la matriz de permisos. Los core (vet,
      // grooming-ops, standard) ya están en ALL_VIEWS. Los clones (vet-lxabc...)
      // se agregan dinámicamente desde RolesView cuando el admin los asigna.
      // Si un rol NO tiene el permiso del clon explícito, NO ve esa instancia —
      // así puedes tener "Veterinario A" con acceso solo a "vet" y "Veterinario B"
      // con acceso solo a "vet-lxabc...". Sin filtraciones.
      if (!canAccess(perm, m.id)) return;

      const visuals = KIND_VISUALS[m.kind] || KIND_VISUALS.custom;
      list.push({
        id: m.id,                                  // id único del módulo (ej. "vet" o "vet-lxabc123")
        kind: m.kind,                              // motor que renderiza ("vet", "grooming", etc.)
        label: m.name || m.shortName || m.id,
        Icon: visuals.Icon,
        accent: m.accent ? `from-${m.accent.split(' ')[0].replace('from-', '')} ${m.accent.split(' ')[1]}` : visuals.accent,
        desc: m.description || visuals.desc,
      });
    });
    return list;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [perm, modules]);

  // Vista por defecto: la primera sección a la que el rol tiene acceso
  const [activeSection, setActiveSection] = useState(sections[0]?.id || null);

  // Si el rol cambia y ya no tiene permiso a la sección activa, saltar a la primera disponible
  useEffect(() => {
    if (activeSection && !sections.find(s => s.id === activeSection)) {
      setActiveSection(sections[0]?.id || null);
    }
  }, [sections, activeSection]);

  if (sections.length === 0) {
    return (
      <div className="max-w-2xl mx-auto pt-8">
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-10 text-center">
          <div className="w-16 h-16 rounded-2xl bg-stone-100 grid place-items-center text-stone-500 mx-auto mb-5">
            <LayoutGrid size={28} strokeWidth={1.6} />
          </div>
          <h2 className="font-serif text-2xl font-semibold mb-2">Sin acceso a CRM</h2>
          <p className="text-sm text-stone-600 max-w-md mx-auto">
            Tu rol no tiene permisos para ver ninguna sección operativa del CRM.
            Contacta al administrador si esto debería cambiar.
          </p>
        </div>
      </div>
    );
  }

  // Sólo una sección disponible: render directo, sin tabs
  if (sections.length === 1) {
    const onlySection = sections[0];
    const targetModule = (modules || []).find(m => m.id === onlySection.id);
    return renderSection(onlySection, vetProps, groomingOpsProps, standardProps, salesProps, targetModule);
  }

  return (
    <div className="space-y-4">
      {/* Hero con tabs por sección */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="px-5 py-4 border-b border-stone-200 flex items-start gap-4 flex-wrap">
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
              CRM Modular
            </div>
            <h2 className="font-serif text-2xl font-semibold leading-tight">
              Operación unificada
            </h2>
            <p className="text-xs text-stone-500 mt-1">
              {sections.length} {sections.length === 1 ? "sección activa" : "secciones activas"} según tus permisos.
              {userRole === "super" && (
                <button onClick={onGoToManager} className="ml-2 text-orange-600 hover:underline font-semibold">
                  Configurar módulos →
                </button>
              )}
            </p>
          </div>
        </div>

        {/* Tabs */}
        <div className="px-3 py-2 flex gap-1 overflow-x-auto bg-stone-50">
          {sections.map(s => {
            const Icon = s.Icon;
            const active = activeSection === s.id;
            return (
              <button
                key={s.id}
                onClick={() => setActiveSection(s.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                  active
                    ? `bg-gradient-to-br ${s.accent} text-white shadow-md`
                    : "text-stone-600 hover:bg-white"
                }`}
              >
                <Icon size={14} strokeWidth={active ? 2.2 : 1.8} />
                {s.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* Contenido de la sección activa */}
      <div>
        {(() => {
          const activeSec = sections.find(s => s.id === activeSection);
          if (!activeSec) return null;
          // Sales y los IDs core conservan su comportamiento. Para módulos clonados
          // (ej. "vet-lxabc123" con kind="vet"), pasamos el módulo concreto al motor
          // para que sus features y columnas se apliquen correctamente.
          const targetModule = (modules || []).find(m => m.id === activeSection);
          return renderSection(activeSec, vetProps, groomingOpsProps, standardProps, salesProps, targetModule);
        })()}
      </div>
    </div>
  );
}

// Renderiza la sección activa según su kind. Para módulos clonados (mismo kind, otro id)
// inyectamos `module={...}` para que el motor lea las features de esa instancia.
function renderSection(section, vetProps, groomingOpsProps, standardProps, salesProps, targetModule) {
  if (section.id === "sales")        return <SalesView {...salesProps} />;
  if (section.kind === "vet")        return <VetCRM {...vetProps} activeModule={targetModule} />;
  if (section.kind === "grooming")   return <GroomingOpsView {...groomingOpsProps} activeModule={targetModule} />;
  if (section.kind === "standard")   return <StandardCRM {...standardProps} activeModule={targetModule} />;
  // Fallbacks por id legacy (cuando no se pasa section como objeto)
  if (section.id === "vet")          return <VetCRM {...vetProps} />;
  if (section.id === "grooming-ops") return <GroomingOpsView {...groomingOpsProps} />;
  if (section.id === "standard")     return <StandardCRM {...standardProps} />;
  return null;
}

// ========== PRODUCTOS HUB (Inventario + Catálogos en Ajustes) ==========
// Agrupa todo lo "configurable" de la oferta del negocio: stock + servicios.
function ProductsHubView({ userRole, can, vetCatalogProps, groomingProps }) {
  const sections = useMemo(() => {
    const list = [];
    if (can("inventory") || userRole === "super")    list.push({ id: "inventory",   label: "Inventario",          Icon: Package,    desc: "Stock de productos, lotes y vencimientos." });
    if (can("vet-catalog") || userRole === "super")  list.push({ id: "vet-catalog", label: "Catálogo Veterinaria", Icon: Pill,       desc: "Servicios y medicinas de la clínica." });
    if (can("grooming") || userRole === "super")     list.push({ id: "grooming",    label: "Catálogo Grooming",    Icon: Scissors,   desc: "Servicios e insumos de peluquería." });
    return list;
  }, [userRole, can]);

  const [activeSection, setActiveSection] = useState(sections[0]?.id || null);
  useEffect(() => {
    if (activeSection && !sections.find(s => s.id === activeSection)) {
      setActiveSection(sections[0]?.id || null);
    }
  }, [sections, activeSection]);

  if (sections.length === 0) {
    return <ComingSoon view="inventory" />;
  }

  return (
    <div className="space-y-4">
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="px-5 py-4 border-b border-stone-200">
          <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
            Ajustes · Productos
          </div>
          <h2 className="font-serif text-2xl font-semibold leading-tight">
            Inventario y catálogos
          </h2>
          <p className="text-xs text-stone-500 mt-1">
            Configura todo lo que tu tienda ofrece: stock, servicios y medicinas.
          </p>
        </div>

        <div className="px-3 py-2 flex gap-1 overflow-x-auto bg-stone-50">
          {sections.map(s => {
            const Icon = s.Icon;
            const active = activeSection === s.id;
            return (
              <button
                key={s.id}
                onClick={() => setActiveSection(s.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                  active
                    ? "bg-stone-900 text-white shadow-md"
                    : "text-stone-600 hover:bg-white"
                }`}
              >
                <Icon size={14} strokeWidth={active ? 2.2 : 1.8} />
                {s.label}
              </button>
            );
          })}
        </div>
      </div>

      <div>
        {activeSection === "inventory" && <ComingSoon view="inventory" />}
        {activeSection === "vet-catalog" && <VetCatalogView {...vetCatalogProps} />}
        {activeSection === "grooming" && <GroomingCRM {...groomingProps} />}
      </div>
    </div>
  );
}

// ============================================================================
// DASHBOARD GENERAL — Panorama operativo del negocio
// ============================================================================
// Muestra KPIs financieros, citas próximas, alertas operativas y actividad
// reciente. Adapta el contenido según el rol: super ve todo el negocio,
// veterinarios solo su clínica, groomers solo grooming, ventas solo facturación.
//
// Cada sección agrega "valor en 5 segundos" — el usuario debería poder entender
// el estado del negocio sin scroll. Las alertas son accionables: un click navega
// a la vista correspondiente.
function DashboardView({
  user, userRole, userName,
  invoices = [], clients = [], passports = [],
  agendaEvents = [], groomingBookings = [],
  modules = [], customRoles = [], users = [],
  conversations = {}, supplies = [], vetSupplies = [],
  onNavigate, permissions = {},
}) {
  // Helper: ISO fecha de hoy
  const todayISO = useMemo(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
  }, []);
  const now = useMemo(() => new Date(), []);

  // === Permisos por rol ===
  // Super y sales ven KPIs financieros completos. Vet/grooming ven datos operativos
  // de su área pero sin totales de facturación (privacidad).
  const isSuper = userRole === "super";
  const isSales = userRole === "sales" || isSuper;
  const isVet = userRole === "vet" || isSuper;
  const isGrooming = userRole === "grooming" || isSuper;
  // Roles custom: heredan permisos de su base (vet/grooming/sales). Por simplicidad
  // mostramos lo más amplio según los views permitidos.
  const myCustomRole = (customRoles || []).find(r => r.id === userRole);
  const customSeesSales = myCustomRole?.inheritFrom === "sales" || isSales;
  const customSeesVet = myCustomRole?.inheritFrom === "vet" || isVet;
  const customSeesGrooming = myCustomRole?.inheritFrom === "grooming" || isGrooming;

  // === KPIs financieros del día ===
  const todayInvoices = useMemo(
    () => invoices.filter(inv => inv.issueDate === todayISO),
    [invoices, todayISO]
  );

  // Ingresos de hoy (sumando todos los pagos hechos hoy, no solo facturas emitidas hoy).
  // Esto refleja flujo de caja real, incluyendo pagos parciales de facturas viejas.
  const todayRevenue = useMemo(() => {
    let total = 0;
    invoices.forEach(inv => {
      (inv.payments || []).forEach(p => {
        if (p.date === todayISO) total += (p.amount ?? 0);
      });
    });
    return total;
  }, [invoices, todayISO]);

  const totalDebt = useMemo(
    () => invoices.reduce((s, i) => s + (i.balance ?? 0), 0),
    [invoices]
  );
  const overdueCount = useMemo(
    () => invoices.filter(i => i.state === "vencido").length,
    [invoices]
  );
  const draftCount = useMemo(
    () => invoices.filter(i => i.state === "borrador").length,
    [invoices]
  );

  // === Citas próximas (próximas 24 horas) ===
  // Filtra eventos vet/grooming con date >= hoy. Ordena por fecha y hora.
  const upcomingEvents = useMemo(() => {
    const tomorrow = new Date(now);
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tomorrowISO = `${tomorrow.getFullYear()}-${String(tomorrow.getMonth() + 1).padStart(2, "0")}-${String(tomorrow.getDate()).padStart(2, "0")}`;
    return (agendaEvents || [])
      .filter(e => {
        if (!e.date) return false;
        // Hoy o mañana
        if (e.date !== todayISO && e.date !== tomorrowISO) return false;
        // Filtrar por rol
        if (e.type === "vet" && !customSeesVet) return false;
        if (e.type === "grooming" && !customSeesGrooming) return false;
        if (e.type === "b2b" && !customSeesSales) return false;
        return true;
      })
      .sort((a, b) => {
        if (a.date !== b.date) return a.date.localeCompare(b.date);
        return (a.time || "").localeCompare(b.time || "");
      })
      .slice(0, 6);
  }, [agendaEvents, todayISO, now, customSeesVet, customSeesGrooming, customSeesSales]);

  // === Citas de hoy (counter para Hero) ===
  const todayEventsCount = useMemo(
    () => (agendaEvents || []).filter(e => e.date === todayISO).length,
    [agendaEvents, todayISO]
  );

  // === Alertas operativas ===
  // Cada alerta es accionable (navega a una vista). Ordenadas por severidad.
  const alerts = useMemo(() => {
    const list = [];

    // 1. Facturas vencidas
    if (overdueCount > 0 && customSeesSales) {
      list.push({
        id: "overdue",
        severity: "high",
        Icon: AlertTriangle,
        title: `${overdueCount} factura${overdueCount > 1 ? "s" : ""} vencida${overdueCount > 1 ? "s" : ""}`,
        desc: "Requieren cobro urgente",
        action: () => onNavigate?.("sales"),
        actionLabel: "Ver Ventas",
      });
    }

    // 2. Borradores sin emitir
    if (draftCount > 0 && customSeesSales) {
      list.push({
        id: "drafts",
        severity: "medium",
        Icon: FileText,
        title: `${draftCount} factura${draftCount > 1 ? "s" : ""} en borrador`,
        desc: "Sin emitir",
        action: () => onNavigate?.("sales"),
        actionLabel: "Revisar",
      });
    }

    // 3. Insumos bajos en grooming
    const lowSupplies = (supplies || []).filter(s => (s.stock ?? 100) <= (s.minStock ?? 10));
    if (lowSupplies.length > 0 && customSeesGrooming) {
      list.push({
        id: "low-supplies",
        severity: "medium",
        Icon: Droplets,
        title: `${lowSupplies.length} insumo${lowSupplies.length > 1 ? "s" : ""} bajo${lowSupplies.length > 1 ? "s" : ""}`,
        desc: "Stock por debajo del mínimo",
        action: () => onNavigate?.("grooming"),
        actionLabel: "Ver insumos",
      });
    }

    // 4. Insumos veterinarios bajos
    const lowVetSupplies = (vetSupplies || []).filter(s => (s.stock ?? 100) <= (s.minStock ?? 5));
    if (lowVetSupplies.length > 0 && customSeesVet) {
      list.push({
        id: "low-vet-supplies",
        severity: "medium",
        Icon: Pill,
        title: `${lowVetSupplies.length} medicamento${lowVetSupplies.length > 1 ? "s" : ""} bajo${lowVetSupplies.length > 1 ? "s" : ""}`,
        desc: "Stock crítico en consultorio",
        action: () => onNavigate?.("vet-catalog"),
        actionLabel: "Ver catálogo",
      });
    }

    // 5. Mensajes sin leer
    const unreadCount = Object.values(conversations || {}).reduce((sum, conv) => {
      return sum + (conv?.messages || []).filter(m => m.from === "client" && !m.read).length;
    }, 0);
    if (unreadCount > 0) {
      list.push({
        id: "unread-messages",
        severity: "low",
        Icon: MessageCircle,
        title: `${unreadCount} mensaje${unreadCount > 1 ? "s" : ""} sin leer`,
        desc: "Tutores esperando respuesta",
        action: () => onNavigate?.("messages"),
        actionLabel: "Ir a Mensajes",
      });
    }

    return list;
  }, [overdueCount, draftCount, supplies, vetSupplies, conversations, customSeesSales, customSeesVet, customSeesGrooming, onNavigate]);

  // === Saludo dinámico según hora ===
  const greeting = useMemo(() => {
    const h = now.getHours();
    if (h < 12) return "Buenos días";
    if (h < 19) return "Buenas tardes";
    return "Buenas noches";
  }, [now]);

  // === Conteo de módulos activos ===
  const activeModulesCount = (modules || []).filter(m => !m.removed).length;

  // === Top clientes del mes (por volumen facturado) ===
  const topClients = useMemo(() => {
    if (!customSeesSales) return [];
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
    const tally = {};
    invoices.forEach(inv => {
      if (!inv.issueDate) return;
      const d = new Date(inv.issueDate);
      if (d < monthStart) return;
      tally[inv.clientId] = (tally[inv.clientId] || 0) + (inv.total ?? 0);
    });
    return Object.entries(tally)
      .map(([cid, total]) => {
        const c = clients.find(cc => cc.id === cid);
        return c ? { client: c, total } : null;
      })
      .filter(Boolean)
      .sort((a, b) => b.total - a.total)
      .slice(0, 4);
  }, [invoices, clients, customSeesSales, now]);

  return (
    <div className="space-y-5 pb-8">
      {/* === Hero con saludo y resumen === */}
      <div className="relative overflow-hidden bg-gradient-to-br from-stone-900 via-orange-900 to-stone-900 text-white rounded-2xl p-6 shadow-xl">
        <div className="absolute -top-20 -right-20 w-60 h-60 bg-orange-500/20 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-20 -left-20 w-60 h-60 bg-amber-500/10 rounded-full blur-3xl"></div>
        <div className="relative flex items-start justify-between gap-4 flex-wrap">
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-300 font-semibold mb-1">
              Panorama operativo · {now.toLocaleDateString("es-ES", { weekday: "long", day: "numeric", month: "long" })}
            </div>
            <h2 className="font-serif text-3xl sm:text-4xl font-semibold leading-tight">
              {greeting}, <span className="text-orange-300">{(userName || "").split(" ")[0]}</span>
            </h2>
            <p className="text-sm text-stone-300 mt-2 max-w-md">
              {todayEventsCount > 0
                ? `Tienes ${todayEventsCount} cita${todayEventsCount > 1 ? "s" : ""} agendada${todayEventsCount > 1 ? "s" : ""} hoy.`
                : "No hay citas agendadas para hoy."}
              {alerts.length > 0 && ` ${alerts.length} alerta${alerts.length > 1 ? "s" : ""} pendiente${alerts.length > 1 ? "s" : ""}.`}
            </p>
          </div>
          {/* Stats compactas en el hero */}
          <div className="flex gap-3 flex-wrap">
            <DashboardHeroStat label="Citas hoy" value={todayEventsCount} Icon={Calendar} />
            {customSeesSales && (
              <DashboardHeroStat label="Hoy" value={`$${todayRevenue.toFixed(0)}`} Icon={DollarSign} />
            )}
            <DashboardHeroStat label="Clientes" value={clients.length} Icon={Users} />
          </div>
        </div>
      </div>

      {/* === KPIs principales === */}
      {customSeesSales && (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          <KpiCard
            label="Ingresos del día"
            value={`$${todayRevenue.toFixed(0)}`}
            sublabel={`${todayInvoices.length} factura${todayInvoices.length !== 1 ? "s" : ""} emitida${todayInvoices.length !== 1 ? "s" : ""}`}
            Icon={TrendingUp}
            accent="emerald"
            onClick={() => onNavigate?.("sales")}
            info="Suma de TODOS los pagos registrados con fecha de hoy, sin importar cuándo se emitió la factura. Incluye pagos parciales de facturas viejas. Los descuentos no se restan aquí — se reflejan en el total ya cobrado. Fuente: Ventas → registros de pago."
          />
          <KpiCard
            label="Por cobrar"
            value={`$${(totalDebt / 1000).toFixed(1)}k`}
            sublabel={`${invoices.filter(i => (i.balance ?? 0) > 0).length} con saldo pendiente`}
            Icon={Wallet}
            accent={totalDebt > 0 ? "amber" : "stone"}
            onClick={() => onNavigate?.("sales")}
            info="Suma de los saldos pendientes de TODAS las facturas activas (no incluye borradores). Cada factura aporta el monto que aún falta cobrar = total - pagos recibidos. Se muestra en miles ($k). Fuente: Ventas → campo 'balance' por factura."
          />
          <KpiCard
            label="Vencidas"
            value={overdueCount}
            sublabel="Requieren acción"
            Icon={AlertTriangle}
            accent={overdueCount > 0 ? "red" : "stone"}
            onClick={() => onNavigate?.("sales")}
            info="Cantidad de facturas en estado 'vencido' — aquellas cuya fecha de vencimiento ya pasó y aún tienen saldo pendiente. Hace falta gestionar el cobro o renegociar plazo. Fuente: Ventas → state='vencido'."
          />
          <KpiCard
            label="Citas hoy"
            value={todayEventsCount}
            sublabel={`${activeModulesCount} módulos activos`}
            Icon={Calendar}
            accent="blue"
            onClick={() => onNavigate?.("agenda")}
            info="Total de eventos en la agenda con fecha de hoy, de cualquier tipo (veterinaria, grooming, B2B, otros). El sublabel cuenta cuántos CRM/módulos hay activos en el sistema. Fuente: Agenda → eventos del día."
          />
        </div>
      )}

      {/* Para roles que NO ven facturación, mostramos KPIs operativos alternativos */}
      {!customSeesSales && (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          <KpiCard
            label="Citas hoy"
            value={todayEventsCount}
            sublabel="Agendadas para hoy"
            Icon={Calendar}
            accent="blue"
            onClick={() => onNavigate?.("agenda")}
            info="Total de eventos en la agenda con fecha de hoy. Filtra por tu rol: si eres veterinario solo cuentan citas tipo 'vet', si eres groomer solo 'grooming'. Fuente: Agenda → eventos del día."
          />
          <KpiCard
            label="Pasaportes"
            value={passports.length}
            sublabel="Pacientes registrados"
            Icon={Stamp}
            accent="orange"
            info="Cantidad total de pasaportes clínicos creados en el sistema. Cada pasaporte representa un paciente único con su historial médico, vacunas y tutores. Fuente: módulo Pasaportes."
          />
          <KpiCard
            label="Clientes"
            value={clients.length}
            sublabel="Tutores activos"
            Icon={Users}
            accent="emerald"
            onClick={() => onNavigate?.("clients")}
            info="Cantidad total de tutores (humanos dueños de mascotas) registrados. Un mismo tutor puede tener varias mascotas. Fuente: módulo Clientes."
          />
          <KpiCard
            label="Equipo"
            value={users.filter(u => u.active).length}
            sublabel="Usuarios activos"
            Icon={UserPlus}
            accent="purple"
            info="Cantidad de cuentas de empleados con estado activo (excluye los desactivados con el toggle gris). Solo super puede gestionar el equipo. Fuente: Ajustes → Usuarios."
          />
        </div>
      )}

      {/* === Layout de 2 columnas: Citas + Alertas === */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Citas próximas */}
        <div className="lg:col-span-2 bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-stone-200 flex items-center justify-between">
            <div>
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Agenda</div>
              <div className="font-serif text-lg font-semibold mt-0.5">Citas próximas</div>
            </div>
            <button
              onClick={() => onNavigate?.("agenda")}
              className="text-xs font-semibold text-orange-700 hover:text-orange-900 flex items-center gap-1"
            >
              Ver todas <ChevronRight size={12} />
            </button>
          </div>
          {upcomingEvents.length === 0 ? (
            <div className="p-8 text-center">
              <Calendar size={28} className="text-stone-300 mx-auto mb-2" />
              <p className="text-sm text-stone-500">No hay citas próximas en las siguientes 24h</p>
            </div>
          ) : (
            <div className="divide-y divide-stone-100">
              {upcomingEvents.map(ev => {
                const eventDateLabel = ev.date === todayISO ? "Hoy" : "Mañana";
                const typeColor = {
                  vet: "bg-orange-100 text-orange-700",
                  grooming: "bg-emerald-100 text-emerald-700",
                  b2b: "bg-blue-100 text-blue-700",
                  pet: "bg-amber-100 text-amber-700",
                }[ev.type] || "bg-stone-100 text-stone-600";
                const TypeIcon = ev.type === "vet" ? Stethoscope
                              : ev.type === "grooming" ? Bath
                              : ev.type === "b2b" ? Briefcase
                              : Calendar;
                return (
                  <div key={ev.id} className="px-5 py-3 hover:bg-stone-50 transition flex items-center gap-3">
                    <div className={`w-9 h-9 rounded-xl ${typeColor} grid place-items-center flex-shrink-0`}>
                      <TypeIcon size={15} strokeWidth={1.8} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-xs font-bold text-stone-700">{eventDateLabel}</span>
                        <span className="text-xs text-stone-500">·</span>
                        <span className="text-xs font-semibold text-stone-700">{ev.time || "—"}</span>
                        <span className="text-xs text-stone-400">·</span>
                        <span className="text-xs text-stone-500 truncate">{ev.duration}min</span>
                      </div>
                      <div className="text-sm font-semibold truncate">
                        {ev.pet ? `${ev.pet} · ` : ""}{ev.title || "Cita"}
                      </div>
                      <div className="text-xs text-stone-500 truncate">
                        {ev.owner || "Sin tutor"}{ev.professional ? ` · ${ev.professional}` : ""}
                      </div>
                    </div>
                    <div className={`hidden sm:block text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded ${typeColor}`}>
                      {ev.type}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Alertas operativas */}
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-stone-200">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Sistema</div>
            <div className="font-serif text-lg font-semibold mt-0.5">
              Alertas {alerts.length > 0 && <span className="text-orange-700">({alerts.length})</span>}
            </div>
          </div>
          {alerts.length === 0 ? (
            <div className="p-8 text-center">
              <CheckCircle2 size={28} className="text-emerald-400 mx-auto mb-2" />
              <p className="text-sm font-semibold text-emerald-700">Todo en orden</p>
              <p className="text-xs text-stone-500 mt-1">No hay alertas pendientes</p>
            </div>
          ) : (
            <div className="divide-y divide-stone-100">
              {alerts.map(alert => {
                const Ic = alert.Icon;
                const sevColor = {
                  high: "bg-red-100 text-red-700",
                  medium: "bg-amber-100 text-amber-700",
                  low: "bg-blue-100 text-blue-700",
                }[alert.severity];
                return (
                  <button
                    key={alert.id}
                    onClick={alert.action}
                    className="w-full px-5 py-3 hover:bg-stone-50 transition flex items-start gap-3 text-left"
                  >
                    <div className={`w-9 h-9 rounded-xl ${sevColor} grid place-items-center flex-shrink-0 mt-0.5`}>
                      <Ic size={15} strokeWidth={1.8} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-semibold truncate">{alert.title}</div>
                      <div className="text-xs text-stone-500 truncate">{alert.desc}</div>
                      <div className="text-xs font-semibold text-orange-700 mt-1 flex items-center gap-1">
                        {alert.actionLabel} <ChevronRight size={10} />
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* === Top clientes del mes (solo si ve ventas) === */}
      {customSeesSales && topClients.length > 0 && (
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-stone-200 flex items-center justify-between">
            <div>
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Clientes</div>
              <div className="font-serif text-lg font-semibold mt-0.5">Top del mes</div>
            </div>
            <button
              onClick={() => onNavigate?.("clients")}
              className="text-xs font-semibold text-orange-700 hover:text-orange-900 flex items-center gap-1"
            >
              Ver todos <ChevronRight size={12} />
            </button>
          </div>
          <div className="divide-y divide-stone-100">
            {topClients.map((tc, idx) => (
              <div key={tc.client.id} className="px-5 py-3 flex items-center gap-3 hover:bg-stone-50 transition">
                <div className={`w-8 h-8 rounded-lg grid place-items-center font-bold text-sm flex-shrink-0 ${
                  idx === 0 ? "bg-amber-100 text-amber-700" :
                  idx === 1 ? "bg-stone-200 text-stone-700" :
                  idx === 2 ? "bg-orange-100 text-orange-700" :
                  "bg-stone-100 text-stone-600"
                }`}>
                  {idx + 1}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-sm font-semibold truncate">{tc.client.name}</div>
                  <div className="text-xs text-stone-500 truncate">{tc.client.cedula || tc.client.email || "—"}</div>
                </div>
                <div className="text-right flex-shrink-0">
                  <div className="text-sm font-bold text-emerald-700">${tc.total.toFixed(0)}</div>
                  <div className="text-[10px] text-stone-500 uppercase tracking-wider">Este mes</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* === Footer info: módulos activos === */}
      {isSuper && (
        <div className="bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 flex items-center gap-3 flex-wrap">
          <Info size={14} className="text-stone-500 flex-shrink-0" />
          <span className="text-xs text-stone-600">
            Sistema operando con <strong>{activeModulesCount}</strong> módulos activos · <strong>{users.filter(u => u.active).length}</strong> usuarios · <strong>{customRoles.filter(r => !r.isCoreOverride).length}</strong> roles personalizados
          </span>
        </div>
      )}
    </div>
  );
}

// Stat compacta en el Hero del Dashboard
function DashboardHeroStat({ label, value, Icon }) {
  return (
    <div className="bg-white/10 backdrop-blur border border-white/20 rounded-xl px-3 py-2 flex items-center gap-2">
      <Icon size={14} className="text-orange-300 flex-shrink-0" strokeWidth={2} />
      <div>
        <div className="text-[9px] tracking-widest uppercase text-stone-300 font-semibold">{label}</div>
        <div className="text-sm font-bold leading-tight">{value}</div>
      </div>
    </div>
  );
}

// Card de KPI clickable
function KpiCard({ label, value, sublabel, Icon, accent = "stone", onClick, info = null }) {
  const [showInfo, setShowInfo] = useState(false);
  const bgMap = {
    emerald: "from-emerald-50 to-emerald-100 border-emerald-200",
    amber: "from-amber-50 to-amber-100 border-amber-200",
    red: "from-red-50 to-red-100 border-red-200",
    blue: "from-blue-50 to-blue-100 border-blue-200",
    orange: "from-orange-50 to-orange-100 border-orange-200",
    purple: "from-purple-50 to-purple-100 border-purple-200",
    stone: "from-stone-50 to-stone-100 border-stone-200",
  };
  const iconMap = {
    emerald: "bg-emerald-600 text-white",
    amber: "bg-amber-600 text-white",
    red: "bg-red-600 text-white",
    blue: "bg-blue-600 text-white",
    orange: "bg-orange-600 text-white",
    purple: "bg-purple-600 text-white",
    stone: "bg-stone-500 text-white",
  };
  const Tag = onClick ? "button" : "div";
  return (
    <Tag
      onClick={onClick}
      className={`relative text-left bg-gradient-to-br ${bgMap[accent]} border rounded-2xl p-4 transition ${onClick ? "hover:shadow-md hover:scale-[1.01] cursor-pointer" : ""}`}
    >
      <div className="flex items-start justify-between gap-2 mb-2">
        <div className={`w-9 h-9 rounded-xl ${iconMap[accent]} grid place-items-center shadow flex-shrink-0`}>
          <Icon size={16} strokeWidth={2} />
        </div>
        <div className="flex items-center gap-1">
          {/* Ícono "i" con tooltip explicativo del KPI. Se renderiza solo si hay info.
              Usamos onMouseEnter/Leave en lugar de :hover CSS porque queremos posicionarlo
              de forma absoluta sin que el padre clicable interfiera. stopPropagation evita
              que un click en el ícono dispare el onClick del KPI (no se navega sin querer). */}
          {info && (
            <span
              role="button"
              tabIndex={0}
              onMouseEnter={() => setShowInfo(true)}
              onMouseLeave={() => setShowInfo(false)}
              onFocus={() => setShowInfo(true)}
              onBlur={() => setShowInfo(false)}
              onClick={(e) => { e.stopPropagation(); setShowInfo(s => !s); }}
              className="w-5 h-5 rounded-full bg-white/70 hover:bg-white border border-stone-300 grid place-items-center text-stone-500 hover:text-stone-800 transition cursor-help relative"
              title=""
            >
              <Info size={11} strokeWidth={2} />
              {/* Tooltip flotante. Se posiciona arriba a la derecha del ícono. z-20 para
                  quedar sobre las cards adyacentes. La flecha apunta al ícono. */}
              {showInfo && (
                <span className="absolute top-full right-0 mt-1.5 w-64 sm:w-72 p-3 rounded-xl bg-stone-900 text-white shadow-2xl z-20 cursor-default" onClick={(e) => e.stopPropagation()}>
                  <span className="block text-[10px] tracking-widest uppercase text-orange-300 font-semibold mb-1">
                    ¿Cómo se calcula?
                  </span>
                  <span className="block text-xs leading-relaxed text-stone-200 normal-case font-normal">
                    {info}
                  </span>
                  {/* Flecha del tooltip apuntando hacia arriba */}
                  <span className="absolute -top-1 right-2 w-2 h-2 bg-stone-900 rotate-45"></span>
                </span>
              )}
            </span>
          )}
          {onClick && <ChevronRight size={14} className="text-stone-400 mt-1 flex-shrink-0" />}
        </div>
      </div>
      <div className="text-[10px] tracking-widest uppercase text-stone-600 font-semibold mb-0.5">{label}</div>
      <div className="font-serif text-2xl font-bold text-stone-900 leading-tight">{value}</div>
      {sublabel && <div className="text-xs text-stone-500 mt-0.5 truncate">{sublabel}</div>}
    </Tag>
  );
}

// ========== VISTA: AJUSTES DE AGENDA ==========
// Configuración del flujo de agenda y citas. Por ahora solo contiene el toggle
// de auto-aprobación de citas web; se irá enriqueciendo con horarios de atención,
// días bloqueados, salas, recordatorios, etc.
function AgendaSettingsView({ appointmentSettings = { autoApprove: true }, setAppointmentSettings, userRole = "super", agendaEvents = [] }) {
  const isSuper = userRole === "super";

  // Conteo de citas web pendientes para mostrar visibilidad de impacto
  const pendingCount = useMemo(
    () => (agendaEvents || []).filter(e => e.fromWeb === true && e.pendingApproval).length,
    [agendaEvents]
  );

  const toggleAutoApprove = () => {
    if (!setAppointmentSettings || !isSuper) return;
    setAppointmentSettings(prev => ({ ...prev, autoApprove: !prev.autoApprove }));
  };

  return (
    <div className="max-w-3xl mx-auto space-y-5">
      {/* Hero */}
      <div className="relative p-6 rounded-2xl bg-gradient-to-br from-white via-orange-50 to-rose-50 border border-stone-200 overflow-hidden">
        <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
          Configuración · Agenda
        </div>
        <h2 className="font-serif text-3xl font-semibold leading-tight">
          Ajustes de <span className="italic text-orange-700">agenda</span>
        </h2>
        <p className="text-sm text-stone-600 mt-2">
          Configura cómo se gestionan las citas que llegan desde el sitio web y cómo se distribuyen los horarios disponibles.
        </p>
      </div>

      {/* Sección: flujo de citas web */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="p-5 border-b border-stone-200">
          <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
            Citas agendadas por web
          </div>
          <h3 className="font-serif text-lg font-semibold mt-0.5">Flujo de aprobación</h3>
          <p className="text-xs text-stone-500 mt-1">
            Decide qué pasa cuando un cliente reserva desde el sitio público.
          </p>
        </div>

        {/* Toggle: auto-aprobación */}
        <div className="p-5 flex items-start gap-4">
          <div className={`w-11 h-11 rounded-xl grid place-items-center flex-shrink-0 ${
            appointmentSettings.autoApprove
              ? "bg-emerald-100 text-emerald-700"
              : "bg-amber-100 text-amber-700"
          }`}>
            {appointmentSettings.autoApprove ? <CheckCircle size={20} strokeWidth={2} /> : <Clock size={20} strokeWidth={2} />}
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-3 flex-wrap">
              <span className="font-semibold text-sm text-stone-800">Aprobación automática</span>
              {appointmentSettings.autoApprove ? (
                <span className="text-xs font-bold uppercase tracking-wider text-emerald-700 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-200">
                  Activado
                </span>
              ) : (
                <span className="text-xs font-bold uppercase tracking-wider text-amber-700 bg-amber-50 px-2 py-0.5 rounded-full border border-amber-200">
                  Manual
                </span>
              )}
            </div>
            <div className="text-xs text-stone-600 mt-1.5 leading-relaxed">
              {appointmentSettings.autoApprove ? (
                <>Las citas reservadas desde la web se confirman <strong>al instante</strong>. Útil cuando tu agenda está abierta y confías en el filtrado de horarios.</>
              ) : (
                <>Las citas reservadas desde la web entran como <strong>pendientes</strong>. Tienes que aprobarlas manualmente desde la agenda antes de confirmárselas al cliente.</>
              )}
            </div>
            {pendingCount > 0 && !appointmentSettings.autoApprove && (
              <div className="mt-2 text-xs text-amber-700 bg-amber-50 border border-amber-200 rounded-lg px-2.5 py-1.5 inline-flex items-center gap-1.5">
                <AlertCircle size={12} />
                <span>Tenés {pendingCount} {pendingCount === 1 ? "cita pendiente" : "citas pendientes"} en este momento.</span>
              </div>
            )}
          </div>
          {/* Switch */}
          <button
            onClick={toggleAutoApprove}
            disabled={!isSuper || !setAppointmentSettings}
            title={isSuper ? "" : "Solo el super usuario puede modificar este ajuste"}
            className={`relative flex-shrink-0 w-12 h-7 rounded-full transition ${
              appointmentSettings.autoApprove ? "bg-emerald-500" : "bg-stone-300"
            } ${!isSuper ? "opacity-50 cursor-not-allowed" : ""}`}
          >
            <span className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow transition-all ${
              appointmentSettings.autoApprove ? "left-6" : "left-1"
            }`} />
          </button>
        </div>

        {!isSuper && (
          <div className="px-5 pb-5">
            <div className="bg-stone-50 border border-stone-200 rounded-lg px-3 py-2 text-xs text-stone-600 flex items-center gap-2">
              <Lock size={12} />
              Solo el super usuario puede cambiar esta configuración.
            </div>
          </div>
        )}
      </div>

      {/* Placeholder para futuras secciones */}
      <div className="bg-stone-50 border border-stone-200 border-dashed rounded-2xl p-6 text-center">
        <Calendar size={20} className="text-stone-300 mx-auto mb-2" />
        <div className="text-sm text-stone-500">
          Próximamente: horarios de atención, salas y recordatorios.
        </div>
      </div>
    </div>
  );
}

