function ServiceCard({ service, onBookAppointment }) {
  const { Icon, color, title, desc, features } = service;
  const colorClasses = {
    orange:  { bg: "bg-orange-50",  border: "border-orange-200",  text: "text-orange-700",  hover: "group-hover:bg-orange-600 group-hover:text-white" },
    emerald: { bg: "bg-emerald-50", border: "border-emerald-200", text: "text-emerald-700", hover: "group-hover:bg-emerald-600 group-hover:text-white" },
    rose:    { bg: "bg-rose-50",    border: "border-rose-200",    text: "text-rose-700",    hover: "group-hover:bg-rose-600 group-hover:text-white" },
    purple:  { bg: "bg-purple-50",  border: "border-purple-200",  text: "text-purple-700",  hover: "group-hover:bg-purple-600 group-hover:text-white" },
  }[color];

  return (
    <div className="group bg-white border border-stone-200 rounded-3xl p-6 hover:-translate-y-1 hover:shadow-xl transition cursor-pointer flex flex-col">
      <div className={`w-14 h-14 rounded-2xl ${colorClasses.bg} ${colorClasses.text} ${colorClasses.hover} grid place-items-center mb-4 transition`}>
        <Icon size={26} strokeWidth={1.6} />
      </div>

      <h3 className="font-serif text-xl font-semibold mb-2">{title}</h3>
      <p className="text-sm text-stone-600 leading-relaxed mb-4 flex-1">{desc}</p>

      <ul className="space-y-1.5 mb-5">
        {features.map((f, i) => (
          <li key={i} className="text-xs text-stone-700 flex items-center gap-2">
            <Check size={13} className={colorClasses.text} strokeWidth={2.5} />
            {f}
          </li>
        ))}
      </ul>

      <button
        onClick={onBookAppointment}
        className={`flex items-center justify-center gap-1.5 px-3 py-2.5 rounded-xl border ${colorClasses.border} ${colorClasses.text} text-sm font-semibold hover:${colorClasses.bg} transition`}
      >
        Agendar <ArrowRight size={13} />
      </button>
    </div>
  );
}

